          left: showLabel ? 0 : 3,
          right: dense ? 4 : 6,
          bottom: dense ? 1.1 : 3.2,
          child: Container(
            height: dense ? 1.0 : 1.6,
            decoration: BoxDecoration(
              gradient: LinearGradient(
                colors: [
                  Colors.transparent,
                  spec.secondaryAccentColor.withValues(alpha: 0.22),
                  spec.secondaryAccentColor.withValues(alpha: 0.6),
                ],
              ),
            ),
          ),
        ),
        Positioned(
          right: dense ? 4 : 12,
          bottom: dense ? 0.4 : 3.0,
          child: Container(
            width: dense ? 5.0 : 11.0,
            height: dense ? 5.0 : 11.0,
            decoration: BoxDecoration(
              shape: BoxShape.circle,
              gradient: RadialGradient(
