enum _MaatFlowTemplateKind {
  sequence,
  trackSky,
  dawnHouseRite,
  eveningThresholdRite,
  theWeighing,
  offeringTable,
  theTending,
  keptWord,
  theCourse,
  moonReturn,
  theWag,
  decanWatch,
  daysOutsideTheYear,
  theOpenHand,
  theDjed,
  maatDecan,
}

class _MaatFlowTemplate {
  final String key; // stable identifier (e.g., "wealth-economy")
  final String title; // flow title
  final String overview; // overview / description
  final String subtitle; // category and short list description
  final String glyph;
  final String glyphMeaning;
  final String glyphSourceWord;
  final String glyphType;
  final List<_MaatFlowDay> days;
  final Color color; // a nice default color
  final _MaatFlowTemplateKind kind;
  _MaatFlowTemplate({
    required this.key,
    required this.title,
    required this.overview,
    required this.subtitle,
    required this.glyph,
    required this.glyphMeaning,
    required this.glyphSourceWord,
    required this.glyphType,
    required this.color,
    this.kind = _MaatFlowTemplateKind.sequence,
  }) : assert(glyph.trim().isNotEmpty, 'Ma’at Flow glyph cannot be empty'),
       assert(
         subtitle.trim().isNotEmpty,
         'Ma’at Flow subtitle cannot be empty',
       ),
       assert(
         glyphMeaning.trim().isNotEmpty,
         'Ma’at Flow glyph meaning cannot be empty',
       ),
       assert(
         glyphSourceWord.trim().isNotEmpty,
         'Ma’at Flow glyph source word cannot be empty',
       ),
       assert(
         glyphType.trim().isNotEmpty,
         'Ma’at Flow glyph type cannot be empty',
       ),
       days = const <_MaatFlowDay>[];
}

