      _CalendarAction(
        glyph: MeduNeterGlyphs.planner,
        gradient: goldGloss,
        label: 'Planner',
        dispatchBeforeClose: true,
        onSelected: () =>
            navigate('/rhythm/today', durableSection: AppSection.planner),
