      _CalendarAction(
        glyph: MeduNeterGlyphs.flowStudio,
        glyphSize: 20,
        gradient: goldGloss,
        label: 'Flow Studio',
        onSelected:
            onOpenFlowStudio ?? () => openFlowStudioFromAnyContext(context),
      ),
      _CalendarAction(
        glyph: MeduNeterGlyphs.library,
        glyphSize: 20,
        gradient: goldGloss,
        label: 'Library',
        dispatchBeforeClose: true,
        onSelected: () =>
            navigate('/nodes', durableSection: AppSection.library),
      ),
      _CalendarAction(
        glyph: MeduNeterGlyphs.journal,
        gradient: goldGloss,
        label: 'Journal',
        dispatchBeforeClose: true,
        onSelected: () =>
            navigate('/journal', durableSection: AppSection.journal),
      ),
      _CalendarAction(
        glyph: MeduNeterGlyphs.inbox,
        gradient: goldGloss,
        label: 'Inbox',
        showNotificationDot: hasUnreadInbox,
        dispatchBeforeClose: true,
        onSelected: () => navigate('/inbox', durableSection: AppSection.inbox),
      ),
      _CalendarAction(
        glyph: MeduNeterGlyphs.calendars,
        gradient: goldGloss,
        label: 'Calendars',
