        onSelected: () async {
          await dismissMountedReflectionPromptIfAny();
          navigate('/reflections');
        },
      ),
      _CalendarAction(
        glyph: MeduNeterGlyphs.home,
        gradient: goldGloss,
        label: 'Home',
        dispatchBeforeClose: true,
        onSelected: () => navigate('/', durableSection: AppSection.calendar),
