      if (includeNewNote)
        _CalendarAction(
          icon: Icons.add,
          gradient: goldGloss,
          label: 'New note',
          onSelected:
              onOpenNewNote ?? () => _openDetachedQuickAddSheet(context),
        ),
    ];
