  // Build a reminder id that is unique per event occurrence and alert time.
  String _reminderIdForNote(_Note n, DateTime alertUtc) {
    final base = n.id ?? n.title;
    return '$base-${alertUtc.toIso8601String()}';
  }

  int? _effectiveAlertMinutes(int? raw) {
    if (raw == _alertNoneMinutes) return null; // explicit "None"
    // Legacy/unspecified -> default to at-time
    return raw ?? 0;
  }

  DateTime? _alertDateTimeLocal({
    required _Note note,
    required int kYear,
    required int kMonth,
    required int kDay,
  }) {
    final alertMinutes = _effectiveAlertMinutes(note.alertOffsetMinutes);
    if (alertMinutes == null) return null;

    final gDay = KemeticMath.toGregorian(kYear, kMonth, kDay);
    final startHour = note.start?.hour ?? 9;
    final startMinute = note.start?.minute ?? 0;
    final startLocal = DateTime(
      gDay.year,
      gDay.month,
      gDay.day,
      note.allDay ? 9 : startHour,
      note.allDay ? 0 : startMinute,
    );

    return startLocal.subtract(Duration(minutes: alertMinutes));
  }

  Future<void> _saveFlowById(int flowId) async {
    final idx = _flows.indexWhere((f) => f.id == flowId);
    if (idx < 0) {
      if (kDebugMode) {
        _calendarDebugPrint('[saveFlowById] Flow $flowId not found in cache');
      }
      return;
    }
    final flow = _flows[idx];
    if (flow.isSaved) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Already in Saved Flows'),
          duration: Duration(seconds: 2),
        ),
      );
      return;
    }

    try {
      await UserEventsRepo(
        Supabase.instance.client,
      ).setFlowSaved(flowId: flowId, isSaved: true);
      if (!mounted) return;
      setState(() {
        _flows[idx].isSaved = true;
        _flows[idx].savedAt = DateTime.now().toUtc();
      });
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Saved to Saved Flows'),
          duration: Duration(seconds: 2),
        ),
      );
    } catch (e) {
      if (!mounted) return;
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('Unable to save flow: $e')));
    }
  }

