                                        }),
                                      ),
                                    ),
                                    const SizedBox(width: 6),
                                    Expanded(
                                      flex: 3,
                                      child: CupertinoPicker(
                                        scrollController: gregDayCtrl,
                                        itemExtent: 32,
                                        looping: true,
                                        backgroundColor: const Color(
                                          0x00121214,
                                        ),
                                        onSelectedItemChanged: (i) {
