                  }

                  Future<void> saveNote() async {
                    final title = controllerTitle.text.trim();
                    final location = controllerLocation.text.trim();
                    final detail = controllerDetail.text.trim();
                    if (title.isEmpty) {
                      setDialogState(() {
                        errorText = 'Title is required.';
                      });
                      return;
                    }
                    if (!allDay && startTime != null && endTime != null) {
                      if (_toMinutes(endTime!) <= _toMinutes(startTime!)) {
                        endTime = _addMinutes(startTime!, 60);
                      }
                    }

                    setDialogState(() {
                      isSaving = true;
                      errorText = null;
                    });
                    try {
                      await _saveSingleNoteOnly(
                        selYear: selYear,
                        selMonth: selMonth,
                        selDay: selDay,
                        title: title,
                        detail: detail.isEmpty ? null : detail,
                        location: location.isEmpty ? null : location,
                        calendarId: calendarId,
                        calendarName: lockedCalendar.name,
                        allDay: allDay,
                        startTime: startTime,
                        endTime: endTime,
                        color: _flowPalette[selectedColorIndex],
                        category: selectedCategory,
                        alertMinutesBefore: alertMinutesBefore,
                      );
                      if (!dialogCtx.mounted) return;
                      Navigator.of(dialogCtx).pop(true);
                      if (!mounted) return;
                      ScaffoldMessenger.of(context).showSnackBar(
                        SnackBar(
                          content: Text('Added to ${lockedCalendar.name}'),
                        ),
                      );
                    } catch (e, stackTrace) {
                      if (kDebugMode) {
                        _calendarDebugPrint(
                          '[CalendarScopedNote] save failed: $e',
                        );
                        _calendarDebugPrint('$stackTrace');
                      }
                      if (!dialogCtx.mounted) return;
                      setDialogState(() {
                        isSaving = false;
                        errorText = 'Failed to save note: $e';
                      });
                    }
                  }

                  final keyboardInset = keyboardInsetOf(dialogCtx);
                  final dialogMaxHeight = math.max(
                    280.0,
                    math.min(
                      media.size.height * 0.66,
                      media.size.height -
                          keyboardInset -
                          media.padding.top -
                          48,
                    ),
                  );
                  const fieldScrollPadding =
                      keyboardManagedTextFieldScrollPadding;

                  return AnimatedPadding(
                    duration: const Duration(milliseconds: 160),
                    curve: Curves.easeOut,
                    padding: EdgeInsets.only(bottom: keyboardInset),
