  void _showCalendarActionMessage(String message) {
    if (!mounted) return;
    ScaffoldMessenger.of(
      context,
    ).showSnackBar(SnackBar(content: Text(message)));
  }

  ReminderRule? _findReminderRuleForDetail(String reminderId) {
    final trimmed = reminderId.trim();
    if (trimmed.isEmpty) return null;
    for (final rule in _reminderRules) {
      if (rule.id == trimmed) return rule;
    }
    final dbUuid = _dbReminderUuidFromRuleId(trimmed);
    if (dbUuid == null) return null;
    for (final flow in _flows) {
      if (!flow.isReminder || flow.reminderUuid != dbUuid) continue;
      return _reminderRuleFromFlow(flow);
    }
    return null;
  }

  Future<DayViewSheetEventTarget?> _refreshDetailTargetAfterCalendarChange(
    DayViewSheetEventTarget target, {
    required String source,
  }) async {
    await _loadFromDisk(source: source);
    if (!mounted) return null;
    return _resolveCalendarCurrentEventTarget(target);
  }

  Future<DayViewSheetEventTarget?> _moveStandaloneEventToCalendar(
    DayViewSheetEventTarget target,
    String calendarId,
  ) async {
    final repo = UserEventsRepo(Supabase.instance.client);
    var eventId = target.event.id?.trim();
    final clientEventId = target.event.clientEventId?.trim();
    if ((eventId == null || eventId.isEmpty) &&
        clientEventId != null &&
        clientEventId.isNotEmpty) {
      final persisted = await repo.getEventByClientEventId(clientEventId);
      eventId = persisted?.id.trim();
    }
    if (eventId == null || eventId.isEmpty) {
      _showCalendarActionMessage(
        'Save this event first, then change its calendar.',
      );
      return null;
    }

    await repo.update(id: eventId, calendarId: calendarId);
    final optimisticTarget = _detailSheetTargetWithCalendar(target, calendarId);
    _applyDetailSheetCalendarToCache(target, calendarId);
    await _notifySharedCalendarItemAdded(
      calendarId: calendarId,
      itemType: 'event',
      itemId: eventId,
      itemTitle: target.event.title,
      clientEventId: clientEventId,
      eventId: eventId,
      startDate: KemeticMath.toGregorian(target.ky, target.km, target.kd),
      kYear: target.ky,
      kMonth: target.km,
      kDay: target.kd,
    );
    final refreshed = await _refreshDetailTargetAfterCalendarChange(
      optimisticTarget,
      source: 'detail_calendar_move_note',
    );
    return _detailSheetTargetUsesCalendar(refreshed, calendarId)
        ? refreshed
        : optimisticTarget;
  }

  Future<DayViewSheetEventTarget?> _moveFlowEventToCalendar(
    DayViewSheetEventTarget target,
    int flowId,
    String calendarId,
  ) async {
    await _flowsRepo.updateCalendar(id: flowId, calendarId: calendarId);
    await UserEventsRepo(
      Supabase.instance.client,
    ).updateCalendarForFlowEvents(flowId: flowId, calendarId: calendarId);

    String flowName = target.event.title;
    for (final flow in _flows) {
      if (flow.id != flowId) continue;
      flow.calendarId = calendarId;
      flowName = flow.name;
      break;
    }
    final optimisticTarget = _detailSheetTargetWithCalendar(target, calendarId);
    _applyDetailSheetCalendarToCache(target, calendarId);

    await _notifySharedCalendarItemAdded(
      calendarId: calendarId,
      itemType: 'flow',
      itemId: flowId.toString(),
      itemTitle: flowName,
      clientEventId: target.event.clientEventId,
      flowId: flowId,
      startDate: KemeticMath.toGregorian(target.ky, target.km, target.kd),
      kYear: target.ky,
      kMonth: target.km,
      kDay: target.kd,
    );
    final refreshed = await _refreshDetailTargetAfterCalendarChange(
      optimisticTarget,
      source: 'detail_calendar_move_flow',
    );
    return _detailSheetTargetUsesCalendar(refreshed, calendarId)
        ? refreshed
        : optimisticTarget;
  }

  Future<DayViewSheetEventTarget?> _moveReminderEventToCalendar(
    DayViewSheetEventTarget target,
    String calendarId,
  ) async {
    final reminderId = target.event.reminderId?.trim();
    if (reminderId == null || reminderId.isEmpty) {
      _showCalendarActionMessage('Unable to locate that reminder.');
      return null;
    }
    final rule = _findReminderRuleForDetail(reminderId);
    if (rule == null) {
      _showCalendarActionMessage('Unable to load that reminder.');
      return null;
    }

    await _upsertReminderRule(rule.copyWith(calendarId: calendarId));
    final dbUuid = _dbReminderUuidFromRuleId(rule.id);
    final targetFlowId = target.event.flowId;
    final flowId = targetFlowId != null && targetFlowId > 0
        ? targetFlowId
        : dbUuid == null
        ? null
        : await _findFlowIdByReminderUuid(dbUuid);
    await _notifySharedCalendarItemAdded(
      calendarId: calendarId,
      itemType: 'reminder',
      itemId: (flowId ?? reminderId).toString(),
      itemTitle: rule.title,
      clientEventId: target.event.clientEventId,
      flowId: flowId,
      reminderId: dbUuid ?? reminderId,
      startDate: rule.startLocal,
      endDate: rule.endLocal == null
          ? null
          : DateUtils.dateOnly(rule.endLocal!),
      kYear: target.ky,
      kMonth: target.km,
      kDay: target.kd,
    );
    final optimisticTarget = _detailSheetTargetWithCalendar(target, calendarId);
    _applyDetailSheetCalendarToCache(target, calendarId);
    if (!mounted) return null;
    final refreshed = _resolveCalendarCurrentEventTarget(optimisticTarget);
    return _detailSheetTargetUsesCalendar(refreshed, calendarId)
        ? refreshed
        : optimisticTarget;
  }

  Future<DayViewSheetEventTarget?> _reassignDetailTargetCalendar(
    DayViewSheetEventTarget target,
    String calendarId,
  ) async {
    final nextCalendarId =
        _normalizeCalendarId(calendarId) ??
        _normalizeCalendarId(_personalCalendarId);
    if (nextCalendarId == null) return null;

    final currentCalendarId =
        _normalizeCalendarId(target.event.calendarId) ??
        _normalizeCalendarId(_personalCalendarId);
    if (currentCalendarId == nextCalendarId) {
      return _resolveCalendarCurrentEventTarget(target);
    }
    if (!_calendarCanEdit(currentCalendarId)) {
      _showCalendarActionMessage(
        'You can view this calendar, but you cannot edit it.',
      );
      return null;
    }
    if (!_calendarCanEdit(nextCalendarId)) {
      _showCalendarActionMessage(
        'You can view that calendar, but you cannot save events to it.',
      );
      return null;
    }

    try {
      if (target.event.isReminder) {
        return await _moveReminderEventToCalendar(target, nextCalendarId);
      }
      final flowId = target.event.flowId;
      if (flowId != null && flowId > 0) {
        return await _moveFlowEventToCalendar(target, flowId, nextCalendarId);
      }
      return await _moveStandaloneEventToCalendar(target, nextCalendarId);
    } catch (e) {
      _showCalendarActionMessage('Unable to change calendar: $e');
      return null;
    }
  }

  Future<void> _notifySharedCalendarMembers({
    required String? calendarId,
    required String title,
    String? body,
    String? clientEventId,
    Map<String, dynamic>? data,
  }) async {
    final trimmedCalendarId = _normalizeCalendarId(calendarId);
    if (trimmedCalendarId == null) return;

    final summary = _calendarSummary(trimmedCalendarId);
    if (summary == null || summary.isPersonal) return;

    final memberIds = await _sharedCalendarsRepo.getAcceptedMemberIds(
      trimmedCalendarId,
    );
    if (memberIds.isEmpty) return;

    final payload = <String, dynamic>{
      'kind': 'calendar_event',
      'calendar_id': trimmedCalendarId,
      'calendar_name': summary.name,
      'calendar_color': summary.colorValue,
      if (clientEventId != null && clientEventId.trim().isNotEmpty)
        'client_event_id': clientEventId.trim(),
      if (data != null) ...data,
    };

    await _sharedCalendarsRepo.createCalendarNotifications(
      calendarId: trimmedCalendarId,
      userIds: memberIds,
      kind: 'calendar_event',
      title: title,
      body: body,
      data: payload,
    );

    await _sharedCalendarsRepo.sendCalendarPush(
      userIds: memberIds,
      title: title,
      body: body,
      data: payload,
    );
  }

  Future<void> _notifySharedCalendarItemAdded({
    required String? calendarId,
    required String itemType,
    required String itemId,
    String? itemTitle,
    String? clientEventId,
    int? flowId,
    String? eventId,
    String? noteId,
    String? reminderId,
    String? taskId,
    DateTime? startDate,
    DateTime? endDate,
    int? kYear,
    int? kMonth,
    int? kDay,
  }) async {
    final trimmedCalendarId = _normalizeCalendarId(calendarId);
    if (trimmedCalendarId == null) return;

    await _sharedCalendarsRepo.notifySharedCalendarItemAdded(
      calendarId: trimmedCalendarId,
      itemType: itemType,
      itemId: itemId,
      itemTitle: itemTitle,
      clientEventId: clientEventId,
      flowId: flowId,
      eventId: eventId,
      noteId: noteId,
      reminderId: reminderId,
      taskId: taskId,
      startDate: startDate,
      endDate: endDate,
      kYear: kYear,
      kMonth: kMonth,
      kDay: kDay,
    );
  }

  /// Extract the flow id from a unified clientEventId string. Returns -1 if
  /// parsing fails or no flow id segment is present. This can be used when
  /// reconstructing notes from persisted events.
  int _flowIdFromCid(String cid) {
    return extractFlowIdFromClientEventId(cid) ?? -1;
  }

  String? _reminderRuleIdFromCid(String cid) {
    if (!cid.startsWith('reminder:')) return null;
    final parts = cid.split(':');
    // Format: reminder:RULE_ID:YYYY-MM-DD (rule id may contain colons)
    if (parts.length < 3) return null;
    final ruleId = parts.sublist(1, parts.length - 1).join(':').trim();
    return ruleId.isEmpty ? null : ruleId;
  }

  /// Remove legacy clientEventId formats and replace them with unified ones. This
  /// migration runs once on startup (scheduled via microtask) and rewrites
  /// any lingering events that still use old identifiers. It is idempotent and
  /// safe to run multiple times. If Ma’at notes use a separate namespace,
  /// they can be migrated by adding the appropriate legacy patterns here.
  Future<void> _migrateOldClientEventIds() async {
    await _ensureManualDeleteTombstonesLoaded();
    try {
      final prefs = await SharedPreferences.getInstance();
      final alreadyDone = prefs.getBool(_kCidMigrationPrefKey) ?? false;
      if (alreadyDone) {
        if (kDebugMode) {
          _calendarDebugPrint('[migrate-cid] Skipping; persisted flag is set.');
        }
        return;
      }
      final repo = UserEventsRepo(Supabase.instance.client);
      // Iterate over all notes in memory and rebuild unified ids
      // Iterate over a snapshot of entries to avoid concurrent modifications while iterating.
      final entries = _notes.entries.toList();
      bool migrated = false;
      for (final entry in entries) {
        final key = entry.key;
        // Parse kYear, kMonth, kDay from the map key. Keys are strings generated by _kKey, e.g. "2025-10-8".  We parse by splitting on '-'.
        int ky;
        int km;
        int kd;
        {
          // Fallback: parse from string form. Even if key is int (unlikely), toString() will yield a numeric string. We expect parts length == 3.
          final parts = key.toString().split('-');
          if (parts.length != 3) {
            // If the key is purely numeric, derive ky, km, kd by integer arithmetic as a fallback.
            final maybeInt = int.tryParse(key.toString());
            if (maybeInt != null) {
              ky = maybeInt ~/ 10000;
              km = (maybeInt % 10000) ~/ 100;
              kd = maybeInt % 100;
            } else {
              // Unknown key format; skip this entry.
              continue;
            }
          } else {
            ky = int.tryParse(parts[0]) ?? 0;
            km = int.tryParse(parts[1]) ?? 0;
            kd = int.tryParse(parts[2]) ?? 0;
          }
        }
        for (final note in entry.value) {
          // Build unified cid for this note
          final int fid = note.flowId ?? -1;
          final String unifiedCid = _buildCid(
            ky: ky,
            km: km,
            kd: kd,
            title: note.title,
            startHour: note.start?.hour,
            startMinute: note.start?.minute,
            allDay: note.allDay,
            flowId: fid,
            calendarScopeToken: _calendarScopeToken(note.calendarId),
          );
          if (_isTombstoned(unifiedCid)) {
            if (kDebugMode) {
              _calendarDebugPrint(
                '[migrate-cid] skip tombstoned cid=$unifiedCid',
              );
            }
            continue;
          }
          final startTime = note.allDay
              ? null
              : TimeOfDay(
                  hour: note.start?.hour ?? 9,
                  minute: note.start?.minute ?? 0,
                );
          if (_isPendingDelete(
            id: note.id,
            clientEventId: note.clientEventId,
            kYear: ky,
            kMonth: km,
            kDay: kd,
            title: note.title,
            allDay: note.allDay,
            start: startTime,
            end: note.end,
            flowId: fid,
          )) {
            continue;
          }
          // Determine legacy patterns used previously and remove them
          final String rawTitle = note.title;
          final String hhmm = note.start != null
              ? '${note.start!.hour.toString().padLeft(2, '0')}${note.start!.minute.toString().padLeft(2, '0')}'
              : '';
          final legacyIds = <String>{
            'note:$ky-$km-$kd:${rawTitle.hashCode}',
            'ky=$ky-km=$km-kd=$kd|t=$rawTitle',
            if (hhmm.isNotEmpty) 'note:$ky-$km-$kd:$rawTitle:$hhmm',
          };
          for (final oldId in legacyIds) {
            try {
              await repo.deleteByClientId(oldId);
            } catch (_) {}
          }
          // Upsert unified row (idempotent)
          try {
            final g = KemeticMath.toGregorian(ky, km, kd);
            final DateTime startsAt = DateTime(
              g.year,
              g.month,
              g.day,
              note.start?.hour ?? 9,
              note.start?.minute ?? 0,
            );
            final DateTime? endsAt = note.end == null
                ? null
                : DateTime(
                    g.year,
                    g.month,
                    g.day,
                    note.end!.hour,
                    note.end!.minute,
                  );
            await repo.upsertByClientId(
              clientEventId: unifiedCid,
              title: note.title,
              startsAtUtc: startsAt.toUtc(),
              detail: note.detail?.trim().isEmpty ?? true
                  ? null
                  : note.detail!.trim(),
              location: note.location?.trim().isEmpty ?? true
                  ? null
                  : note.location!.trim(),
              allDay: note.allDay,
              endsAtUtc: endsAt?.toUtc(),
              caller: 'migrate_cid',
            );
            migrated = true;
          } catch (e) {
            _calendarDebugPrint(
              '[migrate-cid] Failed to upsert unified cid: $e',
            );
          }
        }
      }
      await prefs.setBool(_kCidMigrationPrefKey, true);
      _calendarDebugPrint(
        '[migrate-cid] Completed pass. migrated=$migrated flag persisted',
      );
    } catch (e) {
      _calendarDebugPrint('[migrate-cid] Migration failed: $e');
    }
  }

  // Keep calendar position only for the active short-lived session.
  static const bool _rememberLastView = true;
  // Day View is part of continuity state. A saved open Day View should be
  // restored after the calendar has rebuilt its initial viewport.
  static const bool _restoreDayViewRouteOnStartup = true;

  int? _lastViewKy; // last centered Kemetic year
  int? _lastViewKm; // last centered Kemetic month (1..13)
  int? _lastViewKd; // last viewed Kemetic day (1..30, or 1..5/6 for month 13)

  Orientation? _lastOrientation; // Tracks functional rotation handoff.

  static const String _kSessionScopeCalendarView = 'calendar_view';
  static const String _kSessionResumeKindDaySheet = 'calendar_day_sheet';
  static const String _kSessionResumeKindPushEvent = 'calendar_push_event';
  static const int _kCalendarViewStateSchemaVersion = 2;
  static const int _kCalendarRestorationLayoutRevision = 1;
  static const String _kCalendarAnchorTargetDayChip = 'dayChip';
  static const String _kCalendarAnchorTargetMonthHeader = 'monthHeader';
  static const String _kCalendarAnchorTargetMonthBody = 'monthBody';

  bool _initialJumpScheduled = false;
  bool _initialViewportSettled = false;
  bool _orientationJumpScheduled = false;
  bool _portraitRecenterPending = false;

  // ✅ ADD: Feedback loop prevention flag
  bool _isUpdatingFromLandscape = false;
  bool _isUpdatingFromPortrait = false;

  // ✅ ADD: First-build gating flag to prevent race condition
  bool _restored = false;
  bool _daySheetResumeAttempted = false;
  bool _pushEventResumeAttempted = false;
  int? _lastHandledCalendarPushIntentNonce;
  bool _isTablet(BuildContext context) =>
      MediaQuery.of(context).size.shortestSide >= 600;

  // Find the month card whose vertical center is closest to the viewport center.
  void _updateCenteredMonth() {
    final candidates = <(int ky, int km, double dist)>[];

    // ✅ OPTIMIZED: Try saved/today month first (most likely mounted)
    final baseKy = _lastViewKy ?? _today.kYear;
    final baseKm = _lastViewKm ?? _today.kMonth;

    ScrollableState? scrollableState;
    RenderBox? viewportBox;

    // Try saved/today month first
    var ctx = keyForMonth(baseKy, baseKm).currentContext;
    if (ctx != null) {
      scrollableState = Scrollable.maybeOf(ctx); // ✅ Use CHILD context!
      if (scrollableState != null) {
        final vpBox = scrollableState.context.findRenderObject() as RenderBox?;
        if (vpBox != null && vpBox.hasSize) {
          viewportBox = vpBox;
        }
      }
    }

    // Fallback: search nearby months if first attempt failed
    if (viewportBox == null) {
      for (var dY = -3; dY <= 3 && viewportBox == null; dY++) {
        final ky = baseKy + dY;
        for (var km = 1; km <= 13; km++) {
          ctx = keyForMonth(ky, km).currentContext;
          if (ctx == null) continue;
          scrollableState = Scrollable.maybeOf(ctx);
          if (scrollableState != null) {
            final vpBox =
                scrollableState.context.findRenderObject() as RenderBox?;
            if (vpBox != null && vpBox.hasSize) {
              viewportBox = vpBox;
              break;
            }
          }
        }
      }
    }

    if (scrollableState == null || viewportBox == null) return;

    // ✅ Viewport must be valid and laid out
    final position = scrollableState.position;
    if (!position.hasPixels || position.viewportDimension <= 0) return;

    // ✅ Calculate viewport center in global coordinates
    final viewportTopGlobal = viewportBox.localToGlobal(Offset.zero).dy;
    final viewportCenterY = viewportTopGlobal + (viewportBox.size.height / 2);

    bool addIfMounted(int ky, int km) {
      final ctx = keyForMonth(ky, km).currentContext;
      if (ctx == null) return false;

      final rb = ctx.findRenderObject() as RenderBox?;
      if (rb == null || !rb.hasSize) return false;

      // ✅ CORRECT: size.center() exists and matches _centerMonth() pattern
      final monthCenterGlobal = rb
          .localToGlobal(rb.size.center(Offset.zero))
          .dy;

      final dist = (monthCenterGlobal - viewportCenterY).abs();
      candidates.add((ky, km, dist));
      return true;
    }

    // Search from saved state (already correct from v3)
    for (var dY = -3; dY <= 3; dY++) {
      final ky = baseKy + dY;
      for (var km = 1; km <= 13; km++) {
        addIfMounted(ky, km);
      }
    }

    if (candidates.isEmpty) return;
    candidates.sort((a, b) => a.$3.compareTo(b.$3));

    final newKy = candidates.first.$1;
    final newKm = candidates.first.$2;

    // ✅ ONLY UPDATE IF CHANGED AND NOT UPDATING FROM LANDSCAPE OR PORTRAIT
    if ((_lastViewKy != newKy || _lastViewKm != newKm) &&
        !_isUpdatingFromLandscape &&
        !_isUpdatingFromPortrait) {
      // ✅ HARDENING 1: Clamp day when month changes
      final maxDay = _maxDayForMonth(newKy, newKm);
      final clampedKd = (_lastViewKd ?? 1).clamp(1, maxDay);

      _setView(newKy, newKm, kd: clampedKd);
    }
  }

  void _updateCenteredMonthWide() {
    // ✅ ONLY update if we don't already have a valid state
    // ✅ FIX 2: Removed _lastViewKy! >= 1 check - accept historical years
    if (_lastViewKy != null &&
        _lastViewKm != null &&
        _lastViewKm! >= 1 &&
        _lastViewKm! <= 13) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '✓ [CALENDAR] Skipping _updateCenteredMonthWide - using existing state: $_lastViewKy-$_lastViewKm',
        );
      }
      return;
    }

    final candidates = <(int ky, int km, double dist)>[];

    // ✅ OPTIMIZED: Try saved/today month first (most likely mounted)
    final base = _lastViewKy ?? _today.kYear;
    final baseMonth = _lastViewKm ?? _today.kMonth;

    ScrollableState? scrollableState;
    RenderBox? viewportBox;

    // Try saved/today month first
    var ctx = keyForMonth(base, baseMonth).currentContext;
    if (ctx != null) {
      scrollableState = Scrollable.maybeOf(ctx); // ✅ Use CHILD context!
      if (scrollableState != null) {
        final vpBox = scrollableState.context.findRenderObject() as RenderBox?;
        if (vpBox != null && vpBox.hasSize) {
          viewportBox = vpBox;
        }
      }
    }

    // Fallback: search nearby months if first attempt failed
    if (viewportBox == null) {
      for (var dy = -220; dy <= 220; dy++) {
        final ky = base + dy;
        for (var km = 1; km <= 13; km++) {
          ctx = keyForMonth(ky, km).currentContext;
          if (ctx != null) {
            scrollableState = Scrollable.maybeOf(ctx);
            if (scrollableState != null) {
              final vpBox =
                  scrollableState.context.findRenderObject() as RenderBox?;
              if (vpBox != null && vpBox.hasSize) {
                viewportBox = vpBox;
                break;
              }
            }
          }
        }
        if (viewportBox != null) break;
      }
    }

    if (scrollableState == null || viewportBox == null) return;

    // ✅ Calculate viewport center in global coordinates (SAME as _updateCenteredMonth)
    final viewportTopGlobal = viewportBox.localToGlobal(Offset.zero).dy;
    final viewportCenterY = viewportTopGlobal + (viewportBox.size.height / 2);

    bool addIfMounted(int ky, int km) {
      final ctx = keyForMonth(ky, km).currentContext;
      if (ctx == null) return false;
      final rb = ctx.findRenderObject() as RenderBox?;
      if (rb == null || !rb.hasSize) return false;

      // ✅ CORRECT: Use same calculation as _centerMonth() and _updateCenteredMonth()
      final monthCenterGlobal = rb
          .localToGlobal(rb.size.center(Offset.zero))
          .dy;
      final dist = (monthCenterGlobal - viewportCenterY).abs();
      candidates.add((ky, km, dist));
      return true;
    }

    // Wider search for landscape (±220 years)
    for (var dy = -220; dy <= 220; dy++) {
      final ky = base + dy;
      var foundAny = false;
      for (var km = 1; km <= 13; km++) {
        foundAny = addIfMounted(ky, km) || foundAny;
      }
      if (foundAny && candidates.length >= 6) break;
    }

    if (candidates.isEmpty) return;
    candidates.sort((a, b) => a.$3.compareTo(b.$3));

    // ✅ Only update if not already set
    if (_lastViewKy == null || _lastViewKm == null) {
      final newKy = candidates.first.$1;
      final newKm = candidates.first.$2;
      final maxDay = _maxDayForMonth(newKy, newKm);
      final clampedKd = (_lastViewKd ?? 1).clamp(1, maxDay);

      _lastViewKy = newKy;
      _lastViewKm = newKm;
      _lastViewKd = clampedKd;
    }
  }

  // Call on scroll to keep tracking the centered month.
  void _onVerticalScroll() {
    if (!_initialViewportSettled) return;
    if (_scrollCtrl.hasClients) {
      _lastKnownCalendarScrollOffset = _scrollCtrl.position.pixels;
    }
    _restorationInteractedSinceBoot = true;
    _maybePersistCalendarRestorationDuringScroll();
    // ✅ Debounce to next frame to avoid stale RenderObjects
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (mounted && _initialViewportSettled) {
        _updateCenteredMonth();
      }
    });
  }

  /// ✅ FIX 4: Compute centered month precisely using getOffsetToReveal
  (int, int) _computeCenteredMonthPrecisely() {
    final fallback = (
      _lastViewKy ?? _today.kYear,
      _lastViewKm ?? _today.kMonth,
    );
    if (!_scrollCtrl.hasClients) {
      return fallback;
    }

    final box = context.findRenderObject();
    if (box is! RenderBox || !box.attached) {
      return fallback;
    }

    final notificationContext =
        _scrollCtrl.position.context.notificationContext;
    final viewportObject = notificationContext?.findRenderObject();
    final viewportBox = viewportObject is RenderBox && viewportObject.attached
        ? viewportObject
        : box;
    final vp = RenderAbstractViewport.maybeOf(viewportBox);
    if (vp == null) {
      return fallback;
    }

    final viewportCenter = _scrollCtrl.offset + (viewportBox.size.height / 2);

    // Search ±2 years around last known position
    var bestKy = _lastViewKy ?? _today.kYear;
    var bestKm = _lastViewKm ?? _today.kMonth;
    double bestDist = double.infinity;

    for (int dy = -2; dy <= 2; dy++) {
      final baseKy = (_lastViewKy ?? _today.kYear) + dy;
      for (int km = 1; km <= 13; km++) {
        final ctx = keyForMonth(baseKy, km).currentContext;
        if (ctx == null) continue;

        final ro = ctx.findRenderObject();
        if (ro == null || ro is! RenderBox || !ro.attached) continue;

        // ✅ Use getOffsetToReveal for precision
        final revealResult = vp.getOffsetToReveal(ro, 0.5);
        final revealOffset = revealResult.offset;
        final dist = (revealOffset - viewportCenter).abs();

        if (dist < bestDist) {
          bestDist = dist;
          bestKy = baseKy;
          bestKm = km;
        }
      }
    }

    return (bestKy, bestKm);
  }

  /// ✅ FIX 4: Handle month change from portrait scroll (with feedback loop guard)
  void _handlePortraitMonthChanged(int ky, int km) {
    if (_isUpdatingFromLandscape || _isUpdatingFromPortrait) return;

    _isUpdatingFromPortrait = true;
    try {
      _restorationInteractedSinceBoot = true;
      final maxDay = _maxDayForMonth(ky, km);
      final clampedKd = (_lastViewKd ?? 1).clamp(1, maxDay);

      _setView(ky, km, kd: clampedKd);
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint('⚠️ [CALENDAR] Error in portrait month change: $e');
      }
    } finally {
      WidgetsBinding.instance.addPostFrameCallback((_) {
        _isUpdatingFromPortrait = false;
      });
    }
  }

