    if (!mounted || _showingFirstFlowEventCoachmark) return;
    _showingFirstFlowEventCoachmark = true;
    WidgetsBinding.instance.addPostFrameCallback((_) {
      Future<void>.delayed(const Duration(milliseconds: 420), () {
