  ReminderRule? _findReminder(String id) {
    for (final r in _reminderRules) {
      if (r.id == id) return r;
    }
    return null;
  }

  Future<void> _editReminderById(String id) async {
    await _loadReminderRules();
    final rule = _findReminder(id);
    if (rule == null) return;
    await _openReminderEditor(existing: rule);
  }

  Future<void> _endReminderRule(String id) async {
    // End = remove the reminder entirely (rule + scheduled instances + cached notes).
    await _loadReminderRules();
    await _deleteReminderRule(id);
  }

  // ✅ Rotation reconcile: re-center on last view after rotation settles
  @override
  void didChangeMetrics() {
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) return;

      final orientation = MediaQuery.orientationOf(context);
      final ky = _lastViewKy ?? _today.kYear;
      final km = _lastViewKm ?? _today.kMonth;

      if (orientation == Orientation.portrait) {
        _centerMonth(ky, km); // your existing helper
      }
      // Landscape rebuild pulls initialKy/Km from _lastView* in build()
    });
  }

  /* ───── helpers ───── */

  String _kKey(int ky, int km, int kd) => '$ky-$km-$kd';

  /// Get event marker colors for a given day (for month grid dots).
  /// Derives colors from filed notes in _notes, not from recomputed flow rules.
  List<Color> getFlowColorsForDay(int kYear, int kMonth, int kDay) {
    final notes = _getNotes(kYear, kMonth, kDay);
    return calendarEventMarkerColors<_Note>(
      notes,
      colorOf: _noteColor,
      groupBy: _calendarMarkerGroupKey,
    );
  }

  Object? _calendarMarkerGroupKey(_Note note) {
    final flowId = note.flowId;
    if (flowId == null || flowId <= 0) return null;
    return 'flow:$flowId';
  }

  List<_Note> _getNotes(int kYear, int kMonth, int kDay) {
    final key = _kKey(kYear, kMonth, kDay);
    final result = _notes[key] ?? const [];
    final visible = !_calendarStateLoaded
        ? result
        : result
              .where((note) => _isCalendarVisible(note.calendarId))
              .toList(growable: false);
    return _dedupeVisibleDayNotes(visible);
  }

  ReminderRule? _reminderRuleFromFlow(_Flow f) {
    if (f.notes == null || f.notes!.trim().isEmpty) return null;
    try {
      final decoded = jsonDecode(f.notes!.trim());
      final map = Map<String, dynamic>.from(decoded as Map);
      final rule = ReminderRule.fromJson(map);
      return rule.copyWith(
        calendarId: rule.calendarId ?? f.calendarId,
        endLocal: rule.endLocal ?? f.end,
      );
    } catch (_) {
      return null;
    }
  }

  /// Flow occurrences that apply to a given Kemetic date (computed on demand).
  List<_FlowOccurrence> _getFlowOccurrences(int kYear, int kMonth, int kDay) {
    final g = KemeticMath.toGregorian(kYear, kMonth, kDay);
    final gDate = DateUtils.dateOnly(g);
    final out = <_FlowOccurrence>[];
    for (final f in _flows) {
      if (!f.active) continue;
      if (f.isHidden) continue; // repeating notes should NOT appear as flows
      final start = f.start != null ? DateUtils.dateOnly(f.start!) : null;
      final end = f.end != null ? DateUtils.dateOnly(f.end!) : null;
      if (start != null && gDate.isBefore(start)) continue;
      if (end != null && gDate.isAfter(end)) continue;
      if (f.isReminder) {
        final rr = _reminderRuleFromFlow(f);
        if (rr == null) continue;
        final occs = _generateReminderOccurrences(rr, gDate, gDate);
        if (occs.isNotEmpty) {
          final startTod = rr.allDay
              ? null
              : TimeOfDay(
                  hour: rr.startLocal.hour,
                  minute: rr.startLocal.minute,
                );
          final endTod = rr.allDay
              ? null
              : TimeOfDay.fromDateTime(
                  DateTime(
                    gDate.year,
                    gDate.month,
                    gDate.day,
                    rr.startLocal.hour,
                    rr.startLocal.minute,
                  ).add(const Duration(minutes: 30)),
                );
          out.add(
            _FlowOccurrence(
              flow: f,
              allDay: rr.allDay,
              start: startTod,
              end: endTod,
            ),
          );
        }
      } else {
        for (final r in f.rules) {
          if (r.matches(ky: kYear, km: kMonth, kd: kDay, g: g)) {
            out.add(
              _FlowOccurrence(
                flow: f,
                allDay: r.allDay,
                start: r.start,
                end: r.end,
              ),
            );
          }
        }
      }
    }
    return out;
  }

  FlowRecordSnapshot _flowRecordSnapshotFromFlow(_Flow flow) {
    return FlowRecordSnapshot(
      id: flow.id,
      active: flow.active,
      isHidden: flow.isHidden,
      isReminder: flow.isReminder,
      isSaved: flow.isSaved,
      notes: flow.notes,
    );
  }

  FlowData _flowDataFromFlow(_Flow flow) {
    return FlowData(
      id: flow.id,
      name: flow.name,
      color: _displayFlowColor(flow.name, flow.color),
      active: flow.active,
      notes: flow.notes,
    );
  }

  Map<int, _Flow> _allFlowsById() {
    return {for (final flow in _flows) flow.id: flow};
  }

  Set<int> _calendarReferencedFlowIds() {
    final ids = <int>{};
    for (final bucket in _notes.values) {
      for (final note in bucket) {
        final flowId = note.flowId;
        if (flowId != null && flowId > 0) {
          ids.add(flowId);
        }
      }
    }
    if (kDebugMode) {
      _calendarDebugPrint(
        '[calendarFlowChrome] referencedFlowIds=${ids.length} flows=${_flows.length}',
      );
    }
    return ids;
  }

  Map<int, FlowData> _buildActiveLedgerFlowIndex() {
    final flowIndex = <int, FlowData>{};
    final ledger = _buildFlowLedger(_flows);
    for (final f in ledger.activeItems) {
      flowIndex[f.id] = _flowDataFromFlow(f);
    }
    return flowIndex;
  }

  Set<int> _buildActiveLedgerFlowIds() {
    return _buildActiveLedgerFlowIndex().keys.toSet();
  }

  void _refreshNoteCacheUi() {
    if (!mounted) return;
    setState(() {});
    _notifyDayViewDataChanged();
  }

  bool _addNote(
    int kYear,
    int kMonth,
    int kDay,
    String title,
    String? detail, {
    String? id,
    String? clientEventId,
    String? calendarId,
    String? calendarName,
    String? location,
    bool allDay = false,
    TimeOfDay? start,
    TimeOfDay? end,
    int? flowId,
    Color? manualColor,
    String? category,
    bool isReminder = false,
    String? reminderId,
    int? alertOffsetMinutes,
    String? actionId,
    Map<String, dynamic>? behaviorPayload,
    bool notify = true,
  }) {
    final shouldSkip =
        _isPendingDelete(
          kYear: kYear,
          kMonth: kMonth,
          kDay: kDay,
          title: title,
          allDay: allDay,
          start: start,
          end: end,
          clientEventId: clientEventId,
          flowId: flowId,
        ) ||
        _isTombstoned(clientEventId);
    if (shouldSkip) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[_addNote] skip add for title="$title" cid=${clientEventId ?? '<none>'} pending/tombstoned',
        );
      }
      return false;
    }

    final k = _kKey(kYear, kMonth, kDay);
    final list = _notes.putIfAbsent(k, () => <_Note>[]);
    list.add(
      _Note(
        id: id,
        clientEventId: clientEventId,
        calendarId: calendarId,
        calendarName: calendarName,
        title: title.trim(),
        detail: detail?.trim(),
        location: (location == null || location.trim().isEmpty)
            ? null
            : location.trim(),
        allDay: allDay,
        start: allDay ? null : start,
        end: allDay ? null : end,
        flowId: flowId,
        manualColor: manualColor,
        category: category,
        isReminder: isReminder,
        reminderId: reminderId,
        alertOffsetMinutes: alertOffsetMinutes,
        actionId: actionId,
        behaviorPayload: behaviorPayload == null
            ? null
            : Map<String, dynamic>.from(behaviorPayload),
      ),
    );
    // Do not schedule notifications here; scheduling is handled by the caller.
    if (notify) {
      _refreshNoteCacheUi();
    }
    return true;
  }

  int _removeLocalNotesForFlowReplacement(int flowId) {
    if (flowId <= 0) return 0;
    var removed = 0;
    _notes.removeWhere((_, bucket) {
      final before = bucket.length;
      bucket.removeWhere((note) => note.flowId == flowId);
      removed += before - bucket.length;
      return bucket.isEmpty;
    });
    return removed;
  }

  _Note? _removeLocalNoteOnly(int kYear, int kMonth, int kDay, int index) {
    final k = _kKey(kYear, kMonth, kDay);
    final list = _notes[k];
    if (list == null || index < 0 || index >= list.length) return null;

    final removed = list.removeAt(index);
    if (list.isEmpty) _notes.remove(k);
    setState(() {});
    _notifyDayViewDataChanged();
    return removed;
  }

  String _standaloneDedupeKey(_Note note) {
    final normalizedTitle = note.title.trim().toLowerCase();
    final startMin = note.start == null
        ? -1
        : (note.start!.hour * 60 + note.start!.minute);
    final endMin = note.end == null
        ? -1
        : (note.end!.hour * 60 + note.end!.minute);
    return '${note.calendarId ?? ''}|$normalizedTitle|${note.allDay}|$startMin|$endMin';
  }

  int _standalonePriority(String? cid) {
    if (cid == null || cid.isEmpty) return 2;
    if (cid.contains('|f=-1') || cid.startsWith('ky=')) return 4; // manual
    if (cid.startsWith('native:')) return 3;
    if (cid.startsWith('holiday:')) return 1;
    return 2;
  }

  String? _editableStandaloneCategory({
    required bool detachImportedDeviceEvent,
    String? category,
  }) {
    final trimmed = category?.trim();
    if (trimmed == null || trimmed.isEmpty) return null;
    if (detachImportedDeviceEvent && trimmed.toLowerCase() == 'native_sync') {
      return null;
    }
    return trimmed;
  }

  Future<void> _suppressImportedDeviceEventSource(String? clientEventId) async {
    final trimmed = clientEventId?.trim();
    if (trimmed == null || trimmed.isEmpty) return;
    if (!isImportedDeviceCalendarEvent(clientEventId: trimmed)) return;
    await sharedCalendarSyncService(
      Supabase.instance.client,
    ).recordDeletedInApp(trimmed);
  }

  bool _isManualCid(String? cid, {int? flowId}) {
    final trimmed = cid?.trim() ?? '';
    if (trimmed.startsWith('reminder:') ||
        trimmed.startsWith('nutrition:') ||
        trimmed.startsWith('native:') ||
        trimmed.startsWith('holiday:')) {
      return false;
    }
    if (trimmed.isEmpty) {
      return flowId == null || flowId == -1;
    }
    if (trimmed.startsWith('ky=')) return true;
    if (trimmed.contains('|f=-1')) return true;
    return flowId == null || flowId == -1;
  }

  String? _manualCidForNote(_Note note, int kYear, int kMonth, int kDay) {
    final cid = note.clientEventId?.trim();
    if (_isManualCid(cid, flowId: note.flowId)) {
      return cid;
    }
    final fid = note.flowId ?? -1;
    if (fid == -1) {
      return _buildCid(
        ky: kYear,
        km: kMonth,
        kd: kDay,
        title: note.title,
        startHour: note.start?.hour,
        startMinute: note.start?.minute,
        allDay: note.allDay,
        flowId: -1,
        calendarScopeToken: _calendarScopeToken(note.calendarId),
      );
    }
    return null;
  }

  String? _inviteImportTombstoneCid(String? cid) {
    final trimmed = cid?.trim();
    if (trimmed == null || trimmed.isEmpty) return null;
    if (trimmed.startsWith('event_share:')) {
      return trimmed;
    }
    return null;
  }

  Future<void> _ensureManualDeleteTombstonesLoaded() async {
    if (_manualTombstonesLoaded) return;
    _manualTombstonesLoad ??= () async {
      try {
        final prefs = await SharedPreferences.getInstance();
        final stored =
            prefs.getStringList(_kManualDeleteTombstonesKey) ?? <String>[];
        _manualDeleteTombstones
          ..clear()
          ..addAll(stored);
      } catch (_) {
        // ignore load errors; tombstones are a best-effort safeguard
      } finally {
        _manualTombstonesLoaded = true;
      }
    }();
    await _manualTombstonesLoad;
  }

  Future<void> _persistManualDeleteTombstones() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setStringList(
        _kManualDeleteTombstonesKey,
        _manualDeleteTombstones.toList(),
      );
    } catch (_) {
      // ignore persistence errors; safeguard is best-effort
    }
  }

  Future<void> _recordManualTombstone(String cid) async {
    final trimmed = cid.trim();
    if (trimmed.isEmpty) return;
    await _ensureManualDeleteTombstonesLoaded();
    final added = _manualDeleteTombstones.add(trimmed);
    if (added) {
      await _persistManualDeleteTombstones();
    }
  }

  Future<void> _clearManualTombstone(String cid) async {
    final trimmed = cid.trim();
    if (trimmed.isEmpty) return;
    await _ensureManualDeleteTombstonesLoaded();
    final removed = _manualDeleteTombstones.remove(trimmed);
    if (removed) {
      await _persistManualDeleteTombstones();
    }
  }

  bool _isTombstoned(String? cid) {
    final trimmed = cid?.trim();
    if (trimmed == null || trimmed.isEmpty) return false;
    return _manualDeleteTombstones.contains(trimmed);
  }

  String? _buildDeletionKey({
    String? id,
    String? clientEventId,
    int? kYear,
    int? kMonth,
    int? kDay,
    String? title,
    bool? allDay,
    TimeOfDay? start,
    TimeOfDay? end,
    int? flowId,
  }) {
    final trimmedId = id?.trim();
    if (trimmedId != null && trimmedId.isNotEmpty) {
      return 'id:$trimmedId';
    }

    final trimmedCid = clientEventId?.trim();
    if (trimmedCid != null && trimmedCid.isNotEmpty) {
      return 'cid:$trimmedCid';
    }

    if (kYear != null &&
        kMonth != null &&
        kDay != null &&
        title != null &&
        title.trim().isNotEmpty) {
      final normalizedTitle = title.trim().toLowerCase();
      final startMin = start == null ? -1 : (start.hour * 60 + start.minute);
      final endMin = end == null ? -1 : (end.hour * 60 + end.minute);
      final fid = flowId ?? -9999;
      final allDayFlag = allDay == true ? '1' : '0';
      return 'fallback:$kYear-$kMonth-$kDay|$normalizedTitle|$allDayFlag|$startMin|$endMin|$fid';
    }

    return null;
  }

  bool _isPendingDelete({
    String? id,
    String? clientEventId,
    int? kYear,
    int? kMonth,
    int? kDay,
    String? title,
    bool? allDay,
    TimeOfDay? start,
    TimeOfDay? end,
    int? flowId,
  }) {
    final key = _buildDeletionKey(
      id: id,
      clientEventId: clientEventId,
      kYear: kYear,
      kMonth: kMonth,
      kDay: kDay,
      title: title,
      allDay: allDay,
      start: start,
      end: end,
      flowId: flowId,
    );
    final hit = key != null && _pendingDeleteKeys.contains(key);
    if (hit && kDebugMode) {
      _calendarDebugPrint('[_loadFromDisk] skip pending delete key=$key');
    }
    return hit;
  }

  Future<bool> _deleteNote(int kYear, int kMonth, int kDay, int index) async {
    final k = _kKey(kYear, kMonth, kDay);
    final list = _notes[k];
    if (list == null || index < 0 || index >= list.length) return false;

    // Capture note before removal so we know what to delete remotely.
    final note = list[index];
    final String deletedTitle = note.title;
    final manualCid = _manualCidForNote(note, kYear, kMonth, kDay);
    final int? flowIdForNote = note.flowId;

    // If this is a repeating-note micro-flow, delete the entire series (flow + all occurrences).
    if (flowIdForNote != null && flowIdForNote > 0) {
      _Flow? owningFlow;
      try {
        owningFlow = _flows.firstWhere((f) => f.id == flowIdForNote);
      } catch (_) {
        owningFlow = null;
      }
      final isRepeatingNoteFlow =
          owningFlow != null && owningFlow.isHidden && !owningFlow.isReminder;
      if (isRepeatingNoteFlow) {
        final repo = UserEventsRepo(Supabase.instance.client);

        // Remove all local occurrences tied to this flow and cancel their notifications.
        final List<String> cidsToCancel = [];
        _notes.removeWhere((_, bucket) {
          bucket.removeWhere((n) {
            final match = (n.flowId ?? -1) == flowIdForNote;
            if (match && n.clientEventId != null) {
              cidsToCancel.add(n.clientEventId!);
            }
            return match;
          });
          return bucket.isEmpty;
        });
        for (final cid in cidsToCancel) {
          try {
            await Notify.cancelNotificationForEvent(cid);
          } catch (_) {
            // ignore cancellation errors
          }
        }

        // Remove the flow locally so it disappears from cache-driven views.
        _flows.removeWhere((f) => f.id == flowIdForNote);
        setState(() {});
        _notifyDayViewDataChanged();

        // Delete from Supabase: all events for the flow, then the flow row.
        try {
          await repo.deleteByFlowId(flowIdForNote);
          await repo.deleteFlow(flowIdForNote);
        } catch (e) {
          if (kDebugMode) {
            _calendarDebugPrint(
              '[delete-note] Failed to delete repeating flow $flowIdForNote: $e',
            );
          }
        }

        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            SnackBar(
              content: Text('✓ Deleted repeating note series: $deletedTitle'),
              backgroundColor: Colors.green,
              duration: const Duration(seconds: 2),
            ),
          );
        }

        await _loadFromDisk(source: 'delete_repeat_series');
        return true;
      }
    }
    final pendingKey = _buildDeletionKey(
      id: note.id,
      clientEventId: note.clientEventId,
      kYear: kYear,
      kMonth: kMonth,
      kDay: kDay,
      title: note.title,
      allDay: note.allDay,
      start: note.start,
      end: note.end,
      flowId: note.flowId,
    );
    if (pendingKey != null) {
      _pendingDeleteKeys.add(pendingKey);
      if (kDebugMode) {
        _calendarDebugPrint('[delete-note] pending delete key=$pendingKey');
      }
    }

    // Remove locally for responsive UI.
    list.removeAt(index);
    if (list.isEmpty) _notes.remove(k);
    setState(() {});
    _notifyDayViewDataChanged();

    final repo = UserEventsRepo(Supabase.instance.client);
    final Set<int> candidateFlowIds = <int>{};
    bool removed = false;
    String? successfulCid;

    Future<void> cancelNotification(String cid) async {
      try {
        await Notify.cancelNotificationForEvent(cid);
      } catch (_) {
        // ignore cancellation errors
      }
    }

    try {
      // Priority 1: Use the note's own flowId.
      if (note.flowId != null) {
        candidateFlowIds.add(note.flowId!);
        if (kDebugMode) {
          _calendarDebugPrint(
            '[delete-note] Primary candidate: flowId=${note.flowId}',
          );
        }
      }

      // Priority 2: Standalone fallback (-1).
      candidateFlowIds.add(-1);

      // Attempt direct delete by persistent id or clientEventId first.
      try {
        if (note.id != null && note.id!.trim().isNotEmpty) {
          await repo.delete(note.id!);
          if (note.clientEventId != null) {
            await cancelNotification(note.clientEventId!);
          }
          removed = true;
          successfulCid = note.clientEventId ?? note.id;
          if (note.clientEventId != null &&
              note.clientEventId!.startsWith('native:')) {
            await sharedCalendarSyncService(
              Supabase.instance.client,
            ).recordDeletedInApp(note.clientEventId!);
          }
          if (kDebugMode) {
            _calendarDebugPrint(
              '[delete-note] ✅ SUCCESS: Deleted by id=${note.id} cid=${note.clientEventId}',
            );
          }
        } else if (note.clientEventId != null &&
            note.clientEventId!.trim().isNotEmpty) {
          await repo.deleteByClientId(note.clientEventId!);
          await cancelNotification(note.clientEventId!);
          removed = true;
          successfulCid = note.clientEventId;
          if (note.clientEventId!.startsWith('native:')) {
            await sharedCalendarSyncService(
              Supabase.instance.client,
            ).recordDeletedInApp(note.clientEventId!);
          }
          if (kDebugMode) {
            _calendarDebugPrint(
              '[delete-note] ✅ SUCCESS: Deleted by clientEventId=${note.clientEventId}',
            );
          }
        }
      } catch (e) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[delete-note] ⚠️ delete by id/clientEventId failed: $e',
          );
        }
      }

      if (removed) {
        final tombstoneCid =
            manualCid ?? _inviteImportTombstoneCid(successfulCid);
        if (tombstoneCid != null) {
          await _recordManualTombstone(tombstoneCid);
          try {
            // Store the deletion marker outside client-readable event rows so
            // deleted notes cannot resurface as calendar ghosts.
            await repo.recordDeletionTombstone(
              clientEventId: tombstoneCid,
              calendarId: note.calendarId,
              reason: 'delete_note',
            );
          } catch (e) {
            if (kDebugMode) {
              _calendarDebugPrint('[delete-note] tombstone record failed: $e');
            }
          }
        }
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            SnackBar(
              content: Text('✓ Deleted: $deletedTitle'),
              backgroundColor: Colors.green,
              duration: const Duration(seconds: 1),
            ),
          );
        }
        // ✅ Reload from server truth so other-device state is reflected immediately.
        await _loadFromDisk(source: 'delete');
        return true;
      }

      // Priority 3: Pre-fetch events from Supabase to gather other possible flowIds.
      try {
        // Limit to a reasonable number of events for performance.
        final events = await repo.getAllEvents(limit: 1000);
        for (final evt in events) {
          if (evt.title == deletedTitle) {
            // Extract flowId from unified CID if present.
            final cid = evt.clientEventId;
            if (cid != null && cid.isNotEmpty) {
              final parsed = _flowIdFromCid(cid);
              candidateFlowIds.add(parsed);
              if (kDebugMode) {
                _calendarDebugPrint(
                  '[delete-note] Candidate from CID: flowId=$parsed, CID=$cid',
                );
              }
            }
            // Also consider flowLocalId provided by the server.
            final fid = evt.flowLocalId;
            if (fid != null) {
              candidateFlowIds.add(fid);
              if (kDebugMode) {
                _calendarDebugPrint(
                  '[delete-note] Candidate from flowLocalId: $fid',
                );
              }
            }
          }
        }
      } catch (e) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[delete-note] ⚠️ Could not pre-fetch events for deletion: $e',
          );
        }
      }

      // Convert to list for ordered iteration.
      final List<int> candidates = candidateFlowIds.toList();
      if (kDebugMode) {
        _calendarDebugPrint(
          '[delete-note] Will try ${candidates.length} candidate flowIds: $candidates',
        );
      }

      final List<String> attemptedCids = [];

      // Try each candidate flowId.
      for (final fid in candidates) {
        final String cid = _buildCid(
          ky: kYear,
          km: kMonth,
          kd: kDay,
          title: deletedTitle,
          startHour: note.start?.hour,
          startMinute: note.start?.minute,
          allDay: note.allDay,
          flowId: fid,
        );
        attemptedCids.add(cid);
        if (kDebugMode) {
          _calendarDebugPrint('[delete-note] Trying CID: $cid');
        }
        try {
          await repo.deleteByClientId(cid);
          await cancelNotification(cid);
          removed = true;
          successfulCid = cid;
          if (kDebugMode) {
            _calendarDebugPrint(
              '[delete-note] ✅ SUCCESS: Deleted with CID: $cid',
            );
          }
          if (mounted) {
            ScaffoldMessenger.of(context).showSnackBar(
              SnackBar(
                content: Text('✓ Deleted: $deletedTitle'),
                backgroundColor: Colors.green,
                duration: const Duration(seconds: 1),
              ),
            );
          }
          break;
        } catch (e) {
          if (kDebugMode) {
            _calendarDebugPrint(
              '[delete-note] ⚠️ Failed to delete with flowId=$fid: $e',
            );
          }
          // Continue to next candidate.
        }
      }

      // 🚨 LAST RESORT: Direct deletion by matching title/date.
      if (!removed) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[delete-note] All candidate CIDs failed. Trying direct title-based deletion...',
          );
        }
        try {
          final events = await repo.getAllEvents(limit: 1000);
          for (final evt in events) {
            final evtTime = evt.startsAtUtc.toLocal();
            final kEvt = KemeticMath.fromGregorian(evtTime);
            if (evt.title == deletedTitle &&
                kEvt.kYear == kYear &&
                kEvt.kMonth == kMonth &&
                kEvt.kDay == kDay) {
              final cid = evt.clientEventId;
              if (cid != null && cid.isNotEmpty) {
                await repo.deleteByClientId(cid);
                await cancelNotification(cid);
                removed = true;
                successfulCid = cid;
                if (kDebugMode) {
                  _calendarDebugPrint(
                    '[delete-note] ✅ SUCCESS (direct): Deleted using actual CID: $cid',
                  );
                }
                if (mounted) {
                  ScaffoldMessenger.of(context).showSnackBar(
                    SnackBar(
                      content: Text('✓ Deleted: $deletedTitle'),
                      backgroundColor: Colors.green,
                      duration: const Duration(seconds: 1),
                    ),
                  );
                }
                break;
              }
            }
          }
        } catch (e) {
          if (kDebugMode) {
            _calendarDebugPrint('[delete-note] ❌ Direct deletion failed: $e');
          }
        }
      }

      // Final status: if still not removed, show error.
      if (!removed) {
        _calendarDebugPrint(
          '[delete-note] ❌❌❌ CRITICAL: Could not delete note!',
        );
        _calendarDebugPrint(
          '[delete-note] Note: "$deletedTitle", flowId=${note.flowId}',
        );
        _calendarDebugPrint(
          '[delete-note] Attempted ${attemptedCids.length} CIDs: ${attemptedCids.join(", ")}',
        );
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            SnackBar(
              content: Text(
                '⚠️ Could not delete "$deletedTitle". Please delete manually in Supabase.',
              ),
              backgroundColor: Colors.red,
              duration: const Duration(seconds: 5),
              action: SnackBarAction(
                label: 'OK',
                textColor: Colors.white,
                onPressed: () {},
              ),
            ),
          );
        }
      } else {
        if (manualCid != null) {
          await _recordManualTombstone(manualCid);
        }
        if (kDebugMode) {
          _calendarDebugPrint(
            '[delete-note] ✓ Deletion confirmed: $successfulCid',
          );
        }
      }
    } finally {
      if (pendingKey != null) {
        _pendingDeleteKeys.remove(pendingKey);
      }
    }

    return removed;
  }

  /// Returns the index of the note in _notes[dayKey] matching id or clientEventId, or -1.
  int _findNoteIndexByIdOrClientId(
    String dayKey, {
    String? eventId,
    String? clientEventId,
  }) {
    final list = _notes[dayKey];
    if (list == null || list.isEmpty) return -1;
    final trimmedEventId = eventId?.trim();
    final trimmedClientId = clientEventId?.trim();
    return list.indexWhere((n) {
      final noteId = n.id?.trim() ?? '';
      final noteCid = n.clientEventId?.trim() ?? '';
      if (trimmedEventId != null &&
          trimmedEventId.isNotEmpty &&
          noteId == trimmedEventId) {
        return true;
      }
      if (trimmedClientId != null &&
          trimmedClientId.isNotEmpty &&
          noteCid == trimmedClientId) {
        return true;
      }
      return false;
    });
  }

  _Note? _findLatestNoteByIdOrClientId({
    String? eventId,
    String? clientEventId,
  }) {
    final trimmedEventId = eventId?.trim();
    final trimmedClientId = clientEventId?.trim();
    if ((trimmedEventId == null || trimmedEventId.isEmpty) &&
        (trimmedClientId == null || trimmedClientId.isEmpty)) {
      return null;
    }

    _Note? bestClientIdMatch;

    for (final bucket in _notes.values) {
      for (final note in bucket) {
        final noteId = note.id?.trim() ?? '';
        final noteCid = note.clientEventId?.trim() ?? '';
        if (trimmedEventId != null &&
            trimmedEventId.isNotEmpty &&
            noteId == trimmedEventId) {
          return note;
        }
        if (trimmedClientId != null &&
            trimmedClientId.isNotEmpty &&
            noteCid == trimmedClientId) {
          if (bestClientIdMatch == null) {
            bestClientIdMatch = note;
            continue;
          }
          final bestHasId = bestClientIdMatch.id?.trim().isNotEmpty ?? false;
          final noteHasId = noteId.isNotEmpty;
          if (!bestHasId && noteHasId) {
            bestClientIdMatch = note;
          }
        }
      }
    }

    return bestClientIdMatch;
  }

  _Note? _findBestReminderNoteForInvite(EventItem evt) {
    final reminderId = evt.reminderId?.trim();
    if (!evt.isReminder || reminderId == null || reminderId.isEmpty) {
      return null;
    }

    final evtTitle = evt.title.trim().toLowerCase();
    final evtLocation = (evt.location ?? '').trim().toLowerCase();
    final evtDetail = (evt.detail ?? '').trim().toLowerCase();
    final evtStartHour = evt.startMin ~/ 60;
    final evtStartMinute = evt.startMin % 60;
    final evtEndHour = evt.endMin ~/ 60;
    final evtEndMinute = evt.endMin % 60;

    int score(_Note note) {
      var value = 0;
      if (note.id?.trim().isNotEmpty ?? false) value += 4;
      if (note.clientEventId?.trim().isNotEmpty ?? false) value += 2;
      if ((note.location ?? '').trim().toLowerCase() == evtLocation) value += 1;
      if ((note.detail ?? '').trim().toLowerCase() == evtDetail) value += 1;
      return value;
    }

    _Note? best;
    for (final bucket in _notes.values) {
      for (final note in bucket) {
        if (!note.isReminder) continue;
        if ((note.reminderId?.trim() ?? '') != reminderId) continue;
        if (note.title.trim().toLowerCase() != evtTitle) continue;
        if (note.allDay != evt.allDay) continue;
        if (!evt.allDay) {
          if (note.start == null ||
              note.start!.hour != evtStartHour ||
              note.start!.minute != evtStartMinute) {
            continue;
          }
          if (note.end != null &&
              (note.end!.hour != evtEndHour ||
                  note.end!.minute != evtEndMinute)) {
            continue;
          }
        }

        if (best == null || score(note) > score(best)) {
          best = note;
        }
      }
    }

    return best;
  }

  void _attachPersistedEventIdentity({
    required String eventId,
    required String clientEventId,
  }) {
    if (!mounted) return;

    var changed = false;
    for (final bucket in _notes.values) {
      for (var i = 0; i < bucket.length; i++) {
        final note = bucket[i];
        if ((note.clientEventId?.trim() ?? '') != clientEventId) continue;
        if (note.id?.trim().isNotEmpty ?? false) continue;
        bucket[i] = note.copyWith(id: eventId, clientEventId: clientEventId);
        changed = true;
      }
    }

    if (changed) {
      setState(() {});
      _notifyDayViewDataChanged();
    }
  }

  int? _findNoteIndexByEvent(int ky, int km, int kd, EventItem evt) {
    final key = _kKey(ky, km, kd);
    final list = _notes[key];
    if (list == null) return null;

    // Fast path: match by id or clientEventId if present.
    final idxByIds = _findNoteIndexByIdOrClientId(
      key,
      eventId: evt.id,
      clientEventId: evt.clientEventId,
    );
    if (idxByIds >= 0) return idxByIds;

    int startHour = evt.startMin ~/ 60;
    int startMinute = evt.startMin % 60;
    int endHour = evt.endMin ~/ 60;
    int endMinute = evt.endMin % 60;
    int? metadataOnlyMatch;

    for (int i = 0; i < list.length; i++) {
      final n = list[i];
      // For flow-driven events, require flowId match when provided.
      if (evt.flowId != null && (n.flowId ?? -1) != evt.flowId) continue;
      if (n.allDay != evt.allDay) continue;
      if (!evt.allDay) {
        if (n.start == null ||
            n.start!.hour != startHour ||
            n.start!.minute != startMinute) {
          continue;
        }
        if (n.end != null &&
            (n.end!.hour != endHour || n.end!.minute != endMinute)) {
          continue;
        }
      }
      final titlesMatch =
          n.title.trim().toLowerCase() == evt.title.trim().toLowerCase();
      final locMatch =
          (n.location ?? '').trim().toLowerCase() ==
          (evt.location ?? '').trim().toLowerCase();
      final detMatch =
          (n.detail ?? '').trim().toLowerCase() ==
          (evt.detail ?? '').trim().toLowerCase();
      if (titlesMatch && locMatch && detMatch) {
        if ((n.start == null && !evt.allDay) ||
            (n.end == null && !evt.allDay)) {
          if (metadataOnlyMatch != null) return null;
          metadataOnlyMatch = i;
          continue;
        }
        return i;
      }
    }

    for (int i = 0; i < list.length; i++) {
      final n = list[i];
      if (evt.flowId != null && (n.flowId ?? -1) != evt.flowId) continue;
      if (n.allDay != evt.allDay) continue;
      final titlesMatch =
          n.title.trim().toLowerCase() == evt.title.trim().toLowerCase();
      final locMatch =
          (n.location ?? '').trim().toLowerCase() ==
          (evt.location ?? '').trim().toLowerCase();
      final detMatch =
          (n.detail ?? '').trim().toLowerCase() ==
          (evt.detail ?? '').trim().toLowerCase();
      if (!titlesMatch || !locMatch || !detMatch) continue;
      if (metadataOnlyMatch != null) return null;
      metadataOnlyMatch = i;
    }

    return metadataOnlyMatch;
  }

  Future<void> _deleteNoteByEvent(int ky, int km, int kd, EventItem evt) async {
    final idx = _findNoteIndexByEvent(ky, km, kd, evt);
    if (idx != null) {
      await _deleteNote(ky, km, kd, idx);
    }
  }

  Future<void> _editNoteByEvent(int ky, int km, int kd, EventItem evt) async {
    final idx = _findNoteIndexByEvent(ky, km, kd, evt);
    if (idx == null) return;
    final key = _kKey(ky, km, kd);
    final note = _notes[key]![idx];

    await Future<void>.delayed(Duration.zero, () {
      _openDaySheet(
        ky,
        km,
        kd,
        allowDateChange: true,
        initialTitle: note.title,
        initialLocation: note.location,
        initialDetail: note.detail,
        initialAllDay: note.allDay,
        initialStartTime: note.start,
        initialEndTime: note.end,
        initialColor: note.manualColor,
        initialCategory: note.category,
        initialAlertMinutes: note.alertOffsetMinutes,
        editingIndex: idx,
      );
    });
  }

  Future<void> _openFlowShareSheetFromEvent({
    required int flowId,
    required String fallbackTitle,
  }) async {
    var flowTitle = fallbackTitle.trim();
    var flowExists = false;
    for (final flow in _flows) {
      if (flow.id != flowId) continue;
      flowExists = true;
      final candidate = flow.name.trim();
      if (candidate.isNotEmpty) {
        flowTitle = candidate;
      }
      break;
    }

    if (!flowExists) {
      try {
        final persistedFlow = await _flowsRepo.getFlowById(flowId);
        if (persistedFlow != null) {
          flowExists = true;
          final candidate = persistedFlow.name.trim();
          if (candidate.isNotEmpty) {
            flowTitle = candidate;
          }
        }
      } catch (_) {
        // Ignore lookup failures here and surface the generic share error below.
      }
    }

    if (!flowExists) {
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(
            content: Text('This flow is no longer available to share.'),
          ),
        );
      }
      return;
    }

    if (flowTitle.isEmpty) {
      flowTitle = 'Flow';
    }

    if (!mounted) return;
    await showModalBottomSheet<bool>(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.transparent,
      builder: (ctx) => ShareFlowSheet(flowId: flowId, flowTitle: flowTitle),
    );
  }

  Future<void> _shareFlowFromEventItem(EventItem evt) async {
    final flowId = evt.flowId;
    if (flowId == null || evt.isReminder) return;
    await _openFlowShareSheetFromEvent(
      flowId: flowId,
      fallbackTitle: evt.title,
    );
  }

  Future<void> _shareNoteSimple(EventItem evt) async {
    _Note? latest =
        _findLatestNoteByIdOrClientId(
          eventId: evt.id,
          clientEventId: evt.clientEventId,
        ) ??
        _findBestReminderNoteForInvite(evt);

    var eventId = (latest?.id ?? evt.id)?.trim();
    var lookupClientId = (latest?.clientEventId ?? evt.clientEventId)?.trim();

    if ((eventId == null || eventId.isEmpty) &&
        (lookupClientId == null || lookupClientId.isEmpty) &&
        evt.isReminder) {
      await _loadFromDisk();
      if (!mounted) return;

      latest =
          _findLatestNoteByIdOrClientId(
            eventId: evt.id,
            clientEventId: evt.clientEventId,
          ) ??
          _findBestReminderNoteForInvite(evt);
      eventId = (latest?.id ?? evt.id)?.trim();
      lookupClientId = (latest?.clientEventId ?? evt.clientEventId)?.trim();
    }

    if ((eventId == null || eventId.isEmpty) &&
        lookupClientId != null &&
        lookupClientId.isNotEmpty) {
      final persisted = await UserEventsRepo(
        Supabase.instance.client,
      ).getEventByClientEventId(lookupClientId);
      if (persisted != null) {
        eventId = persisted.id.trim();
        _attachPersistedEventIdentity(
          eventId: persisted.id,
          clientEventId: persisted.clientEventId ?? lookupClientId,
        );
      }
    }

    if (eventId == null || eventId.isEmpty) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Save this event first, then invite people.'),
        ),
      );
      return;
    }
    if (!mounted) return;
    await _openEventInviteSheet(
      eventId: eventId,
      title: latest?.title ?? evt.title,
    );
  }

  Future<void> _openEventInviteSheet({
    required String eventId,
    required String title,
  }) async {
    await showModalBottomSheet<bool>(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.transparent,
      builder: (ctx) =>
          ShareFlowSheet(flowId: null, flowTitle: title, eventId: eventId),
    );
  }

  EventItem _noteToEventItem(_Note note) {
    final startMin = note.allDay
        ? 9 * 60
        : (note.start?.hour ?? 9) * 60 + (note.start?.minute ?? 0);
    final endMin = note.allDay
        ? 17 * 60
        : (note.end?.hour ?? 17) * 60 + (note.end?.minute ?? 0);

    // Prefer manual color; otherwise use resolver (handles flow color).
    final resolvedColor = note.manualColor ?? _noteColor(note);

    return EventItem(
      id: note.id,
      clientEventId: note.clientEventId,
      calendarId: note.calendarId,
      calendarName: note.calendarName,
      title: note.title,
      detail: note.detail,
      location: note.location,
      startMin: startMin,
      endMin: endMin,
      flowId: note.flowId,
      color: resolvedColor,
      manualColor: note.manualColor,
      allDay: note.allDay,
      category: note.category,
      isReminder: note.isReminder,
      reminderId: note.reminderId,
      behaviorPayload: note.behaviorPayload,
    );
  }

  Future<void> _moveEventInDayView(
    int ky,
    int km,
    int kd,
    EventItem evt,
    int proposedStartMin,
  ) async {
    final rawId = evt.id?.trim();
    final rawClientId = evt.clientEventId?.trim();
    final moveKeyForLog = (rawId != null && rawId.isNotEmpty)
        ? rawId
        : (rawClientId != null && rawClientId.isNotEmpty)
        ? rawClientId
        : '<none>';
    if (kDebugMode) {
      _calendarDebugPrint(
        '[DayView] move start id=${evt.id} cid=${evt.clientEventId} rawId=$rawId rawCid=$rawClientId moveKey=$moveKeyForLog title="${evt.title}" flowId=${evt.flowId} startMin=${evt.startMin} endMin=${evt.endMin} proposedStart=$proposedStartMin',
      );
    }
    if (evt.allDay) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[DayView] move bail: all-day event "${evt.title}"',
        );
      }
      return;
    }
    if (evt.isReminder) {
      if (kDebugMode) {
        _calendarDebugPrint('[DayView] move bail: reminder "${evt.title}"');
      }
      return;
    }

    if ((rawId == null || rawId.isEmpty) &&
        (rawClientId == null || rawClientId.isEmpty)) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[DayView] move bail: no id/clientEventId for "${evt.title}"',
        );
      }
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('Save event before moving.')),
        );
      }
      return;
    }

    final moveKey = (rawId != null && rawId.isNotEmpty) ? rawId : rawClientId!;
    if (_eventMoveInProgress.contains(moveKey)) {
      if (kDebugMode) {
        _calendarDebugPrint('[DayView] move already in progress for $moveKey');
      }
      return;
    }
    _eventMoveInProgress.add(moveKey);

    final key = _kKey(ky, km, kd);
    int localIdx = -1;
    _Note? previousNote;
    bool updatedLocalNote = false;
    final bool isReminderOccurrence =
        rawClientId != null && rawClientId.startsWith('reminder:');
    String? detailWithOverrideMarker;
    if (isReminderOccurrence) {
      final currentDetail = evt.detail ?? '';
      if (currentDetail.contains(_kReminderManualOverrideMarker)) {
        detailWithOverrideMarker = currentDetail;
      } else {
        final needsNewline =
            currentDetail.isNotEmpty && !currentDetail.endsWith('\n');
        detailWithOverrideMarker =
            '$currentDetail${needsNewline ? '\n' : ''}$_kReminderManualOverrideMarker';
      }
    }

    String fmtTod(TimeOfDay? tod) {
      if (tod == null) return 'all-day';
      final hh = tod.hour.toString().padLeft(2, '0');
      final mm = tod.minute.toString().padLeft(2, '0');
      return '$hh:$mm';
    }

    void logBucket(String label) {
      if (!kDebugMode) return;
      final bucket = _notes[key] ?? const [];
      final summary = bucket
          .map(
            (n) =>
                'id=${n.id ?? '-'} cid=${n.clientEventId ?? '-'} start=${fmtTod(n.start)}',
          )
          .join(' | ');
      _calendarDebugPrint(
        '[DayView] $label key=$key count=${bucket.length} notes=[$summary]',
      );
    }

    try {
      int durationMin = evt.endMin - evt.startMin;
      if (durationMin < 15) durationMin = 15;
      final int maxStart = (1440 - durationMin).clamp(0, 1440).toInt();
      int clampedStart = proposedStartMin.clamp(0, maxStart).toInt();
      int clampedEnd = clampedStart + durationMin;
      if (clampedEnd > 1439) {
        clampedEnd = 1439;
        clampedStart = (clampedEnd - durationMin).clamp(0, 1439).toInt();
      }

      if (clampedStart == evt.startMin && clampedEnd == evt.endMin) {
        if (kDebugMode) {
          _calendarDebugPrint('[DayView] move no-op for $moveKey');
        }
        return;
      }

      final gregorian = KemeticMath.toGregorian(ky, km, kd);
      final startLocal = DateTime(
        gregorian.year,
        gregorian.month,
        gregorian.day,
        clampedStart ~/ 60,
        clampedStart % 60,
      );
      final endLocal = DateTime(
        gregorian.year,
        gregorian.month,
        gregorian.day,
        clampedEnd ~/ 60,
        clampedEnd % 60,
      );

      final repo = UserEventsRepo(Supabase.instance.client);
      final importedDeviceEvent = isImportedDeviceCalendarEvent(
        clientEventId: rawClientId,
        category: evt.category,
      );
      final effectiveCategory = _editableStandaloneCategory(
        detachImportedDeviceEvent: importedDeviceEvent,
        category: evt.category,
      );
      final detailToPersist = isReminderOccurrence
          ? detailWithOverrideMarker
          : evt.detail;
      UserEvent updated;
      if (importedDeviceEvent) {
        final detachedCid = _buildCid(
          ky: ky,
          km: km,
          kd: kd,
          title: evt.title,
          startHour: clampedStart ~/ 60,
          startMinute: clampedStart % 60,
          allDay: evt.allDay,
          flowId: -1,
        );
        if (kDebugMode) {
          _calendarDebugPrint(
            '[DayView] move persist: detaching imported device event oldCid=$rawClientId newCid=$detachedCid start=${startLocal.toUtc()} end=${endLocal.toUtc()}',
          );
        }
        if (rawId != null && rawId.isNotEmpty) {
          updated = await repo.replace(
            id: rawId,
            clientEventId: detachedCid,
            title: evt.title,
            detail: detailToPersist,
            location: evt.location,
            allDay: evt.allDay,
            startsAt: startLocal,
            endsAt: endLocal,
            category: effectiveCategory,
          );
        } else {
          final persisted = rawClientId == null
              ? null
              : await repo.getEventByClientEventId(rawClientId);
          if (persisted != null) {
            updated = await repo.replace(
              id: persisted.id,
              clientEventId: detachedCid,
              title: evt.title,
              detail: detailToPersist,
              location: evt.location,
              allDay: evt.allDay,
              startsAt: startLocal,
              endsAt: endLocal,
              category: effectiveCategory,
            );
          } else {
            updated = await repo.upsertByClientId(
              clientEventId: detachedCid,
              title: evt.title,
              startsAtUtc: startLocal.toUtc(),
              detail: detailToPersist,
              location: evt.location,
              allDay: evt.allDay,
              endsAtUtc: endLocal.toUtc(),
              flowLocalId: null,
              category: effectiveCategory,
              caller: 'move_event_detach',
            );
          }
          if (rawClientId != null && rawClientId != detachedCid) {
            try {
              await repo.deleteByClientId(rawClientId);
            } catch (_) {
              // Best-effort cleanup for a stale imported row.
            }
          }
        }
        await _suppressImportedDeviceEventSource(rawClientId);
      } else if (rawId != null && rawId.isNotEmpty) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[DayView] move persist: update by id=$rawId start=${startLocal.toUtc()} end=${endLocal.toUtc()}',
          );
        }
        updated = await repo.update(
          id: rawId,
          startsAt: startLocal.toUtc(),
          endsAt: endLocal.toUtc(),
          detail: isReminderOccurrence ? detailWithOverrideMarker : null,
        );
      } else {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[DayView] move persist: upsert by cid=$rawClientId start=${startLocal.toUtc()} end=${endLocal.toUtc()}',
          );
        }
        updated = await repo.upsertByClientId(
          clientEventId: rawClientId!,
          title: evt.title,
          startsAtUtc: startLocal.toUtc(),
          detail: detailToPersist,
          location: evt.location,
          allDay: evt.allDay,
          endsAtUtc: endLocal.toUtc(),
          flowLocalId: evt.flowId,
          category: effectiveCategory,
          caller: 'move_event',
        );
      }
      if (kDebugMode) {
        _calendarDebugPrint(
          '[DayView] move persist: result id=${updated.id} cid=${updated.clientEventId} start=${updated.startsAt} end=${updated.endsAt}',
        );
      }

      final TimeOfDay updatedStart = TimeOfDay(
        hour: clampedStart ~/ 60,
        minute: clampedStart % 60,
      );
      final TimeOfDay updatedEnd = TimeOfDay(
        hour: clampedEnd ~/ 60,
        minute: clampedEnd % 60,
      );

      final updatedMeta = _decodeDetailMetadata(updated.detail);
      final cleanedDetail = _cleanDetail(updatedMeta.detail);

      _Note reminderNote;
      localIdx = _findNoteIndexByIdOrClientId(
        key,
        eventId: updated.id,
        clientEventId: updated.clientEventId,
      );
      if (localIdx != -1) {
        final existing = _notes[key]![localIdx];
        previousNote = existing;
        if (kDebugMode) {
          _calendarDebugPrint(
            '[DayView] move: local note found at index $localIdx id=${existing.id} cid=${existing.clientEventId}',
          );
        }
        final replacement = existing.copyWith(
          id: updated.id,
          clientEventId: updated.clientEventId,
          detail: cleanedDetail,
          start: updatedStart,
          end: updatedEnd,
          category: updated.category,
          alertOffsetMinutes:
              existing.alertOffsetMinutes ??
              updatedMeta.alertMinutes ??
              _alertNoneMinutes,
        );
        _notes[key]![localIdx] = replacement;
        updatedLocalNote = true;
        reminderNote = replacement;
        logBucket('move: updated _notes (in-place)');
      } else {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[DayView] move: note not found locally for id=${updated.id} cid=${updated.clientEventId}; reconciling fallback into _notes',
          );
        }
        reminderNote = _Note(
          id: updated.id.trim(),
          clientEventId: updated.clientEventId?.trim(),
          calendarId: updated.calendarId?.trim(),
          calendarName: updated.calendarName?.trim(),
          title: updated.title.trim().isNotEmpty ? updated.title : evt.title,
          detail: cleanedDetail,
          location: updated.location,
          allDay: updated.allDay,
          start: updatedStart,
          end: updatedEnd,
          flowId: updated.flowLocalId,
          manualColor:
              evt.manualColor ??
              (updated.calendarIsPersonal
                  ? null
                  : (updated.calendarColor != null
                        ? Color(updated.calendarColor!)
                        : null)),
          category: updated.category,
          isReminder: evt.isReminder,
          reminderId: evt.reminderId,
          alertOffsetMinutes: updatedMeta.alertMinutes ?? _alertNoneMinutes,
        );
        final bucket = _notes.putIfAbsent(key, () => <_Note>[]);
        bucket.add(reminderNote);
        bucket.removeWhere((n) {
          if (identical(n, reminderNote)) return false;
          final noteId = n.id?.trim() ?? '';
          final noteCid = n.clientEventId?.trim() ?? '';
          final updatedIdMatch =
              reminderNote.id != null &&
              reminderNote.id!.isNotEmpty &&
              noteId == reminderNote.id;
          final updatedCidMatch =
              reminderNote.clientEventId != null &&
              reminderNote.clientEventId!.isNotEmpty &&
              noteCid == reminderNote.clientEventId;
          final incomingIdMatch =
              rawId != null && rawId.isNotEmpty && noteId == rawId;
          final incomingCidMatch =
              rawClientId != null &&
              rawClientId.isNotEmpty &&
              noteCid == rawClientId;
          final titleStartMatch =
              n.title.trim().toLowerCase() ==
                  reminderNote.title.trim().toLowerCase() &&
              n.start != null &&
              reminderNote.start != null &&
              n.start!.hour == reminderNote.start!.hour &&
              n.start!.minute == reminderNote.start!.minute;
          return updatedIdMatch ||
              updatedCidMatch ||
              incomingIdMatch ||
              incomingCidMatch ||
              titleStartMatch;
        });
        logBucket('move: reconciled _notes (fallback)');
      }

      final alertMinutes = _effectiveAlertMinutes(
        reminderNote.alertOffsetMinutes,
      );
      DateTime? alertLocal;
      if (alertMinutes != null) {
        alertLocal = startLocal.subtract(Duration(minutes: alertMinutes));
        final reminderId = _reminderIdForNote(reminderNote, alertLocal.toUtc());
        await _reminderService.addOrUpdate(
          Reminder(
            id: reminderId,
            eventId: reminderNote.id?.toString(),
            title: reminderNote.title,
            detail: reminderNote.detail,
            alertAtUtc: alertLocal.toUtc(),
            flowId: reminderNote.flowId?.toString(),
            createdAt: DateTime.now().toUtc(),
            updatedAt: DateTime.now().toUtc(),
          ),
        );
      }

      if (updated.clientEventId != null && updated.clientEventId!.isNotEmpty) {
        await Notify.cancelNotificationForEvent(updated.clientEventId!);
        if (alertLocal != null) {
          final bodyLines = <String>[
            if ((updated.location ?? '').trim().isNotEmpty)
              updated.location!.trim(),
            if (cleanedDetail.isNotEmpty) cleanedDetail,
          ];
          final scheduleResult =
              await Notify.scheduleAlertWithPersistenceResult(
                clientEventId: updated.clientEventId!,
                scheduledAt: alertLocal,
                title: reminderNote.title,
                body: bodyLines.isEmpty ? null : bodyLines.join('\n'),
                payload: CalendarPage._calendarNotificationPayloadJson(
                  itemType:
                      reminderNote.flowId != null && reminderNote.flowId! > 0
                      ? calendarPushItemTypeFlowEvent
                      : calendarPushItemTypeNote,
                  kYear: ky,
                  kMonth: km,
                  kDay: kd,
                  eventId: updated.id,
                  clientEventId: updated.clientEventId,
                  reminderId: reminderNote.reminderId,
                  flowId: reminderNote.flowId,
                ),
              );
          if (scheduleResult.needsUserVisibleWarning) {
            _showNotificationScheduleWarning(scheduleResult.message);
          }
        }
      }

      _notifyDayViewDataChanged();
    } catch (e, st) {
      if (updatedLocalNote && previousNote != null) {
        final list = _notes[key];
        if (list != null && localIdx >= 0 && localIdx < list.length) {
          list[localIdx] = previousNote;
        }
      }
      if (kDebugMode) {
        _calendarDebugPrint('[DayView] move failed for $moveKey: $e');
        _calendarDebugPrint('$st');
      }
      if (mounted) {
        ScaffoldMessenger.of(
          context,
        ).showSnackBar(const SnackBar(content: Text("Couldn't move event.")));
      }
    } finally {
      _eventMoveInProgress.remove(moveKey);
    }
  }

  // Flows — add/remove/toggle
  // >>> FIND-ME: PATCH-2 _saveNewFlow AFTER
  Future<int?> _saveNewFlow(_Flow flow) async {
    try {
      final repo = UserEventsRepo(Supabase.instance.client);
      final rulesJson = jsonEncode(flow.rules.map(ruleToJson).toList());

      final savedId = await repo.upsertFlow(
        id: null, // let server assign id
        name: flow.name,
        color: flow.color.toARGB32(),
        active: flow.active,
        calendarId: flow.calendarId,
        startDate: flow.start,
        endDate: flow.end,
        notes: flow.notes,
        rules: rulesJson,
        isHidden: flow.isHidden,
        isSaved: flow.isSaved,
        shareId: flow.shareId,
        isReminder: flow.isReminder,
        reminderUuid: flow.reminderUuid,
      );

      // Keep nextFlowId monotonic with server ids
      if (savedId >= _nextFlowId) _nextFlowId = savedId + 1;

      final persisted = _Flow(
        id: savedId,
        calendarId: flow.calendarId,
        name: flow.name,
        color: flow.color,
        active: flow.active,
        isSaved: flow.isSaved,
        savedAt: flow.savedAt,
        rules: flow.rules,
        start: flow.start,
        end: flow.end,
        notes: flow.notes,
        shareId: flow.shareId,
        isHidden: flow.isHidden,
        isReminder: flow.isReminder,
        reminderUuid: flow.reminderUuid,
      );

      _flows.add(persisted);
      if (mounted) setState(() {});
      _notifyDayViewDataChanged();

      return savedId;
    } on PostgrestException catch (e, st) {
      _calendarDebugPrint('[saveNewFlow] ✗ ${e.code} ${e.message}');
      final details = e.details?.toString() ?? '';
      if (details.isNotEmpty) {
        _calendarDebugPrint('[saveNewFlow] details: $details');
      }
      final hint = e.hint?.toString() ?? '';
      if (hint.isNotEmpty) _calendarDebugPrint('[saveNewFlow] hint: $hint');
      _calendarDebugPrint(
        '[saveNewFlow] nulls start:${flow.start == null} end:${flow.end == null} notes:${flow.notes == null} shareId:${flow.shareId == null} isReminder:${flow.isReminder} isSaved:${flow.isSaved}',
      );
      _calendarDebugPrint('$st');
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(
            content: Text('Unable to save flow to cloud. Please retry.'),
            duration: Duration(seconds: 2),
          ),
        );
      }
      return null;
    } catch (e, st) {
      _calendarDebugPrint('[saveNewFlow] ✗ $e');
      _calendarDebugPrint('$st');
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(
            content: Text('Unable to save flow to cloud. Please retry.'),
            duration: Duration(seconds: 2),
          ),
        );
      }
      return null;
    }
  }

  void _deleteFlow(int flowId) {
    final flow = _flows.firstWhere(
      (f) => f.id == flowId,
      orElse: () => _Flow(
        id: flowId,
        name: '',
        color: Colors.white,
        active: false,
        rules: const [],
      ),
    );
    final isSaved = flow.isSaved;

    // prune notes tied to this flow from the in-memory map
    final keysToPrune = <String>[];
    _notes.forEach((k, list) {
      list.removeWhere((n) => n.flowId == flowId);
      if (list.isEmpty) keysToPrune.add(k);
    });
    for (final k in keysToPrune) {
      _notes.remove(k);
    }

    if (isSaved) {
      // For saved flows, keep the flow row and events as a template,
      // just mark it inactive so it disappears from the calendar.
      final idx = _flows.indexWhere((f) => f.id == flowId);
      if (idx >= 0) {
        final f = _flows[idx];
        _flows[idx] = _Flow(
          id: f.id,
          calendarId: f.calendarId,
          name: f.name,
          color: f.color,
          active: false,
          rules: f.rules,
          start: f.start,
          end: f.end,
          notes: f.notes,
          shareId: f.shareId,
          isHidden: f.isHidden,
          isSaved: f.isSaved,
          savedAt: f.savedAt,
          isReminder: f.isReminder,
          reminderUuid: f.reminderUuid,
        );
      }
      setState(() {});
    } else {
      _flows.removeWhere((f) => f.id == flowId);
      setState(() {});
    }

    Future.microtask(() async {
      try {
        final repo = UserEventsRepo(Supabase.instance.client);
        if (isSaved) {
          // Keep events and flow row; just persist inactive state.
          await repo.upsertFlow(
            id: flow.id,
            name: flow.name,
            color: flow.color.toARGB32(),
            active: false,
            calendarId: flow.calendarId,
            startDate: flow.start,
            endDate: flow.end,
            notes: flow.notes,
            rules: jsonEncode(flow.rules.map(ruleToJson).toList()),
            isHidden: flow.isHidden,
            isSaved: flow.isSaved,
            shareId: flow.shareId,
            isReminder: flow.isReminder,
            reminderUuid: flow.reminderUuid,
          );
          if (kDebugMode) {
            _calendarDebugPrint(
              '[deleteFlow] Saved flow $flowId marked inactive, events retained',
            );
          }
        } else {
          await repo.deleteByFlowId(flowId);
          await repo.deleteFlow(flowId);
          await _loadFromDisk();
        }
      } catch (e, stackTrace) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[deleteFlow] ✗ Failed to delete flow $flowId: $e',
          );
          _calendarDebugPrint('[deleteFlow] Stack trace: $stackTrace');
        }
        // Resync local state to match server (restores flow if delete failed)
        await _loadFromDisk();
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            SnackBar(
              content: Text('Failed to delete flow. Please try again.'),
              action: SnackBarAction(
                label: 'Retry',
                onPressed: () => _deleteFlow(flowId),
              ),
              duration: const Duration(seconds: 4),
            ),
          );
        }
      }
    });
  }

  String _formatTimeOfDay(TimeOfDay t) {
    final h = t.hourOfPeriod == 0 ? 12 : t.hourOfPeriod;
    final m = t.minute.toString().padLeft(2, '0');
    final ap = t.period == DayPeriod.am ? 'AM' : 'PM';
    return '$h:$m $ap';
  }

  int _toMinutes(TimeOfDay t) => t.hour * 60 + t.minute;

  TimeOfDay _addMinutes(TimeOfDay t, int delta) {
    final m = (_toMinutes(t) + delta) % (24 * 60);
    return TimeOfDay(hour: (m ~/ 60), minute: m % 60);
  }

  String _timeRangeLabel({
    required bool allDay,
    TimeOfDay? start,
    TimeOfDay? end,
  }) {
    if (allDay) return 'All-day';
    String s(TimeOfDay t) => _formatTimeOfDay(t);
    if (start != null && end != null) return '${s(start)} – ${s(end)}';
    if (start != null) return s(start);
    if (end != null) return '… – ${s(end)}';
    return '';
  }

  /// Gregorian label for a Kemetic month/year (handles epagomenal spanning years).
  String _gregYearLabelFor(int kYear, int kMonth) {
    final lastDay = (kMonth == 13)
        ? (KemeticMath.isLeapKemeticYear(kYear) ? 6 : 5)
        : 30;
    final yStart = KemeticMath.toGregorian(kYear, kMonth, 1).year;
    final yEnd = KemeticMath.toGregorian(kYear, kMonth, lastDay).year;
    return (yStart == yEnd) ? '$yStart' : '$yStart/$yEnd';
  }

  String _monthLabel(int kMonth) => getMonthById(kMonth).displayFull;

