  Future<void> _openProfile(
    BuildContext context, {
    bool openedFromCalendarSwipe = false,
  }) async {
    final userId = Supabase.instance.client.auth.currentUser?.id;
    if (userId == null) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Please log in to view your profile')),
      );
      return;
    }
    if (_profileNavigationInFlight || !mounted) return;

    UiGuards.disableJournalSwipe();
    _profileNavigationInFlight = true;
    try {
      await RestorationCoordinator.instance.clearProfileFeedContinuity(userId);
      if (!mounted || !context.mounted) return;
      unawaited(
        AppNavigationRestorationController.instance.recordPrimaryTabSelection(
          AppSection.profile,
        ),
      );
      context.go('/profile/${Uri.encodeComponent(userId)}');
    } finally {
      _profileNavigationInFlight = false;
      UiGuards.enableJournalSwipe();
    }
  }

  Future<void> openProfileFromOutside(BuildContext context) =>
      _openProfile(context);

  Future<void> openQuickAddFromOutside() => _openQuickAddSheet();

  void jumpToTodayFromOutside({bool animate = true}) =>
      _scrollToToday(animate: animate);

  Future<void> _openJournalFromAppBar() async {
    if (!_journalInitialized) {
      try {
        await _journalController.init();
        if (mounted) setState(() => _journalInitialized = true);
      } catch (_) {
        // If init fails, skip opening rather than throwing.
        return;
      }
    }

    if (!mounted) return;

    UiGuards.disableJournalSwipe();
    try {
      unawaited(
        AppNavigationRestorationController.instance.recordPrimaryTabSelection(
          AppSection.journal,
        ),
      );
      context.go('/journal');
    } finally {
      UiGuards.enableJournalSwipe();
    }
  }

