  /* ───── Search ───── */

  void _openSearch() {
    _openSearchForContext(context);
  }

  void _openSearchForContext(BuildContext searchContext) {
    unawaited(
      CalendarPage._showEventSearch(
        context: searchContext,
        notes: _notes,
        flows: _flows,
        openResult: (ky, km, kd, note) {
          Navigator.of(searchContext).pop();
          final detail = CalendarPage._eventDetailRestorationStateForSearchNote(
            kYear: ky,
            kMonth: km,
            kDay: kd,
            note: note,
          );
          WidgetsBinding.instance.addPostFrameCallback((_) {
            if (!mounted) return;
            final searchIsOnRoot =
                searchContext.mounted &&
                CalendarPage._isRootRouteLocation(
                  CalendarPage._currentRouteLocationForContext(searchContext),
                );
            if (searchIsOnRoot) {
              _openDayView(
                context,
                ky,
                km,
                kd,
                initialEventDetailRestorationState: detail,
              );
              return;
            }
            CalendarPage._routeHomeForSearchResult(
              searchContext,
              ky: ky,
              km: km,
              kd: kd,
              eventDetail: detail,
            );
          });
        },
      ),
    );
  }

  /* ───── Flow Studio ───── */

  // Centralize applying Flow Studio results to calendar state
  Future<void> _applyFlowStudioResult(_FlowStudioResult edited) async {
    int? finalFlowId; // <-- NEW: ensure we know the actual flow id to tag notes
    bool notesAlreadyPersisted =
        false; // When true, skip duplicate planned-note persistence
    final flowCalendarId = edited.savedFlow?.calendarId;
    final flowCalendarName = _calendarSummary(flowCalendarId)?.name;
    String? firstClientEventId;
    String? notificationWarning;

    final deleteId = edited.deleteFlowId;
    if (deleteId != null) {
      _deleteFlow(deleteId);
    } else if (edited.savedFlow != null) {
      final f = edited.savedFlow!;
      final editFlowId = f.id >= 0 ? f.id : null;
      if (editFlowId != null) {
        // ✅ FIX: Persist to database when editing existing flow
        await _persistFlowStudioResult(edited);
        finalFlowId = editFlowId;
        notesAlreadyPersisted =
            true; // plannedNotes handled inside _persistFlowStudioResult
      } else {
        finalFlowId = await _saveNewFlow(f); // await save and get server ID
        if (finalFlowId == null) {
          if (kDebugMode) {
            _calendarDebugPrint(
              '[FlowStudio] Aborting apply - flow insert failed',
            );
          }
          return;
        }
      }
    }

    // Only handle plannedNotes here when we didn't already persist them via _persistFlowStudioResult
    if (!notesAlreadyPersisted && edited.plannedNotes.isNotEmpty) {
      final repo2 = UserEventsRepo(Supabase.instance.client);
      for (final p in edited.plannedNotes) {
        final n = p.note;

        // Determine which flow id to tag: prefer the note's current flowId,
        // else fall back to the captured finalFlowId, else -1.
        final int noteFlowId = (n.flowId ?? finalFlowId) ?? -1;
        final _Note persisted = n.copyWith(flowId: noteFlowId);

        _addNote(
          p.ky,
          p.km,
          p.kd,
          persisted.title,
          persisted.detail,
          calendarId: flowCalendarId,
          calendarName: flowCalendarName,
          location: persisted.location,
          allDay: persisted.allDay,
          start: persisted.start,
          end: persisted.end,
          flowId: noteFlowId >= 0 ? noteFlowId : null,
          category: persisted.category,
          alertOffsetMinutes: persisted.alertOffsetMinutes,
        );

        // Build canonical id using placement and persisted note fields
        final String cid = _buildCid(
          ky: p.ky,
          km: p.km,
          kd: p.kd,
          title: persisted.title,
          startHour: persisted.start?.hour ?? 9,
          startMinute: persisted.start?.minute ?? 0,
          allDay: persisted.allDay,
          flowId: noteFlowId,
        );

        final gDay = KemeticMath.toGregorian(p.ky, p.km, p.kd);
        final DateTime startsAt = DateTime(
          gDay.year,
          gDay.month,
          gDay.day,
          persisted.start?.hour ?? 9,
          persisted.start?.minute ?? 0,
        );
        DateTime? endsAt;
        if (!persisted.allDay && persisted.end != null) {
          endsAt = DateTime(
            gDay.year,
            gDay.month,
            gDay.day,
            persisted.end!.hour,
            persisted.end!.minute,
          );
        }

        final trimmedDetail = (persisted.detail ?? '').trim();
        final baseDetail = trimmedDetail.isEmpty ? null : trimmedDetail;
        final detailWithMeta = _encodeDetailWithMeta(
          baseDetail,
          alertMinutes: persisted.alertOffsetMinutes,
        );
        final detailToSave = detailWithMeta ?? baseDetail;

        try {
          final savedEvent = await repo2.upsertByClientId(
            clientEventId: cid,
            title: persisted.title,
            startsAtUtc: startsAt.toUtc(),
            detail: detailToSave,
            location: (persisted.location ?? '').trim().isEmpty
                ? null
                : persisted.location!.trim(),
            allDay: persisted.allDay,
            endsAtUtc: endsAt?.toUtc(),
            calendarId: flowCalendarId,
            flowLocalId: noteFlowId >= 0 ? noteFlowId : null,
            category: persisted.category,
            caller: 'persist_flow_planned',
          );
          firstClientEventId ??= savedEvent.clientEventId ?? cid;

          final scheduleResult = await _scheduleAlertForEvent(
            note: persisted.copyWith(
              calendarId: flowCalendarId,
              calendarName: flowCalendarName,
            ),
            ky: p.ky,
            km: p.km,
            kd: p.kd,
            clientEventId: savedEvent.clientEventId ?? cid,
            eventId: savedEvent.id,
          );
          if (scheduleResult?.needsUserVisibleWarning == true) {
            notificationWarning ??= scheduleResult?.message;
          }
        } catch (e) {
          _calendarDebugPrint('persist planned notes (apply) failed: $e');
        }
      }
    }

    if (!notesAlreadyPersisted &&
        edited.savedFlow != null &&
        finalFlowId != null) {
      await _notifySharedCalendarItemAdded(
        calendarId: flowCalendarId,
        itemType: 'flow',
        itemId: finalFlowId.toString(),
        itemTitle: edited.savedFlow!.name,
        clientEventId: firstClientEventId,
        flowId: finalFlowId,
        startDate: edited.savedFlow!.start,
        endDate: edited.savedFlow!.end,
      );
    }
    _showNotificationScheduleWarning(notificationWarning);
  }

  // Slide-up Flow Studio shell with inner Navigator and draggable behavior
  Future<void> _openFlowStudioSheet({
    required Widget Function(BuildContext innerCtx) rootBuilder,
    Map<String, dynamic> continuityState = const <String, dynamic>{
      'mode': _kFlowStudioModeHub,
    },
    List<Route<dynamic>> Function(NavigatorState navigator)?
    initialRoutesBuilder,
  }) async {
    if (!mounted || _flowStudioSheetOpenOrOpening) return;
    _flowStudioSheetOpenOrOpening = true;
    UiGuards.disableJournalSwipe();
    final isTablet = _isTablet(context);
    try {
      await _saveCalendarOverlayState(
        _kCalendarOverlayKindFlowStudio,
        continuityState,
      );
      if (!mounted) return;

      final result = await showModalBottomSheet<_FlowStudioResult?>(
        context: context,
        isScrollControlled: true,
        backgroundColor: Colors.transparent,
        barrierColor: Colors.black54,
        useSafeArea: true,
        useRootNavigator: true,
        isDismissible: isTablet ? false : true,
        enableDrag: isTablet ? false : true,
        builder: (outerCtx) {
          if (isTablet) {
            return SafeArea(
              child: FractionallySizedBox(
                heightFactor: 0.9,
                child: ClipRRect(
                  borderRadius: const BorderRadius.vertical(
                    top: Radius.circular(16),
                  ),
                  child: Material(
                    color: Colors.black,
                    child: Column(
                      children: [
                        Align(
                          alignment: Alignment.topRight,
                          child: IconButton(
                            icon: const Icon(Icons.close, color: Colors.white),
                            onPressed: () => Navigator.of(outerCtx).pop(),
                          ),
                        ),
                        Expanded(
                          child: Navigator(
                            onGenerateInitialRoutes: (nav, initial) {
                              final routes = initialRoutesBuilder?.call(nav);
                              if (routes != null) return routes;
                              return [
                                MaterialPageRoute(
                                  builder: (ctx) => rootBuilder(ctx),
                                ),
                              ];
                            },
                          ),
                        ),
                      ],
                    ),
                  ),
                ),
              ),
            );
          }

          return DraggableScrollableSheet(
            initialChildSize: 0.8,
            minChildSize: 0.4,
            maxChildSize: 1.0,
            snap: true,
            snapSizes: const [0.8, 1.0],
            expand: false,
            builder: (innerCtx, scrollController) {
              return ClipRRect(
                borderRadius: const BorderRadius.vertical(
                  top: Radius.circular(16),
                ),
                child: Material(
                  color: Colors.black,
                  child: Column(
                    children: [
                      const SizedBox(height: 10),
                      Container(
                        width: 36,
                        height: 4,
                        decoration: BoxDecoration(
                          color: Colors.white24,
                          borderRadius: BorderRadius.circular(2),
                        ),
                      ),
                      const SizedBox(height: 8),
                      Expanded(
                        child: Navigator(
                          onGenerateInitialRoutes: (nav, initial) {
                            final routes = initialRoutesBuilder?.call(nav);
                            if (routes != null) return routes;
                            return [
                              MaterialPageRoute(
                                builder: (ctx) => rootBuilder(ctx),
                              ),
                            ];
                          },
                        ),
                      ),
                    ],
                  ),
                ),
              );
            },
          );
        },
      );

      if (result != null) {
        await _applyFlowStudioResult(result);
      }
    } finally {
      try {
        final preserveForLifecycle =
            !mounted ||
            RestorationCoordinator
                .instance
                .shouldPreserveOverlayForLifecycleClose;
        if (!preserveForLifecycle) {
          await CalendarPage._clearFlowStudioTransientState();
        }
        UiGuards.enableJournalSwipe();
      } finally {
        _flowStudioSheetOpenOrOpening = false;
      }
    }
  }

  // Directly open My Flows list (no Flow Hub chooser).
  void _openMyFlowsList({int? initialFlowId}) {
    if (!mounted || _flowStudioSheetOpenOrOpening) return;
    _flowStudioSheetOpenOrOpening = true;
    UiGuards.disableJournalSwipe();
    final isTab = _isTablet(context);
    unawaited(() async {
      try {
        await _saveCalendarOverlayState(
          _kCalendarOverlayKindFlowStudio,
          <String, dynamic>{
            'mode': _kFlowStudioModeMyFlows,
            if (initialFlowId != null) 'initialFlowId': initialFlowId,
          },
        );
        if (!mounted) return;

        final result = await showModalBottomSheet<_FlowStudioResult?>(
          context: context,
          isScrollControlled: true,
          backgroundColor: Colors.transparent,
          barrierColor: Colors.black54,
          useSafeArea: true,
          useRootNavigator: true,
          isDismissible: !isTab,
          enableDrag: !isTab,
          builder: (modalCtx) {
            return FractionallySizedBox(
              heightFactor: 0.9,
              child: ClipRRect(
                borderRadius: const BorderRadius.vertical(
                  top: Radius.circular(16),
                ),
                child: Navigator(
                  onGenerateInitialRoutes: (nav, _) {
                    return [
                      MaterialPageRoute(
                        builder: (ctx2) {
                          // If a flowId was provided, push editor after first frame.
                          if (initialFlowId != null) {
                            WidgetsBinding.instance.addPostFrameCallback((_) {
                              unawaited(
                                _pushFlowStudioEditor(
                                  nav,
                                  editFlowId: initialFlowId,
                                  returnState: const <String, dynamic>{
                                    'mode': _kFlowStudioModeMyFlows,
                                  },
                                ),
                              );
                            });
                          }

                          return _FlowsViewerPage(
                            loadFilingSnapshot: _loadMyFlowsFilingSnapshot,
                            initialFilingSnapshot:
                                _cachedMyFlowsFilingSnapshot(),
                            fmtGregorian: (d) => d == null
                                ? '--'
                                : '${d.year}-${d.month.toString().padLeft(2, '0')}-${d.day.toString().padLeft(2, '0')}',
                            onCreateNew: () async {
                              final edited = await _pushFlowStudioEditor(
                                nav,
                                returnState: const <String, dynamic>{
                                  'mode': _kFlowStudioModeMyFlows,
                                },
                              );
                              await _saveCalendarOverlayState(
                                _kCalendarOverlayKindFlowStudio,
                                const <String, dynamic>{
                                  'mode': _kFlowStudioModeMyFlows,
                                },
                              );
                              if (edited != null) {
                                await _persistFlowStudioResult(edited);
                              }
                              await _loadFromDisk();
                            },
                            onEditFlow: (id) async {
                              final edited = await _pushFlowStudioEditor(
                                nav,
                                editFlowId: id,
                                returnState: const <String, dynamic>{
                                  'mode': _kFlowStudioModeMyFlows,
                                },
                              );
                              await _saveCalendarOverlayState(
                                _kCalendarOverlayKindFlowStudio,
                                const <String, dynamic>{
                                  'mode': _kFlowStudioModeMyFlows,
                                },
                              );
                              if (edited != null) {
                                await _persistFlowStudioResult(edited);
                              }
                              await _loadFromDisk();
                            },
                            onEndFlow: (id) => _endFlow(id),
                            onImportFlow: (importedFlowId) async {
                              if (importedFlowId != null) {
                                await _loadFromDisk();
                              }
                            },
                            onAppendToJournal: _journalInitialized
                                ? (text) =>
                                      _journalController.appendToToday(text)
                                : null,
                          );
                        },
                      ),
                    ];
                  },
                ),
              ),
            );
          },
        );
        if (result != null) {
          await _applyFlowStudioResult(result);
        }
      } finally {
        try {
          final preserveForLifecycle =
              !mounted ||
              RestorationCoordinator
                  .instance
                  .shouldPreserveOverlayForLifecycleClose;
          if (!preserveForLifecycle) {
            await CalendarPage._clearFlowStudioTransientState();
          }
          UiGuards.enableJournalSwipe();
        } finally {
          _flowStudioSheetOpenOrOpening = false;
        }
      }
    }());
  }

  /// Public entrypoint so other screens (e.g., Profile) can open Flow Studio's
  /// "My Flows" viewer without duplicating UI.
  Future<void> openMyFlowsFromOutside() async {
    await _loadFromDisk(source: 'open_my_flows_from_outside');
    if (!mounted) return;
    _openMyFlowsList();
  }

  Widget _buildMaatFlowsListPage(BuildContext listCtx) {
    final navigator = Navigator.of(listCtx);
    return _MaatFlowsListPage(
      title: _kMaatFlowsDisplayTitle,
      templates: _kMaatFlowTemplates,
      hasActiveForKey: (key) => _hasActiveMaatInstanceFor(key),
      onPickTemplate: (tpl) async {
        final importedFlowId = await _pushMaatFlowTemplateDetail(
          navigator,
          tpl,
          returnState: const <String, dynamic>{
            'mode': _kFlowStudioModeMaatFlows,
          },
        );
        if (importedFlowId != null && importedFlowId > 0 && listCtx.mounted) {
          final listNavigator = Navigator.of(listCtx);
          if (listNavigator.canPop()) {
            listNavigator.pop(importedFlowId);
          } else {
            Navigator.of(listCtx, rootNavigator: true).pop();
          }
        }
      },
      onCreateNew: () async {
        final edited = await _pushFlowStudioEditor(
          navigator,
          returnState: const <String, dynamic>{
            'mode': _kFlowStudioModeMaatFlows,
          },
        );
        if (edited != null) await _persistFlowStudioResult(edited);
      },
    );
  }

  // Manage Flows callback: jump straight to My Flows (or specific flow editor if id provided).
  void Function(int? flowId) _getMyFlowsCallback() {
    return (int? flowId) {
      if (flowId != null) {
        if (kIsWeb) {
          unawaited(
            CalendarPage.openFlowEditorFromAnyContext(
              context,
              flowId: flowId,
              fallbackLocation: '/',
              source: 'calendar_detail',
            ),
          );
          return;
        }
        // Open the existing Flow editor directly when a flowId is provided.
        _openFlowEditorDirectly(flowId);
        return;
      }
      _openMyFlowsList();
    };
  }

  // Flow Studio callback that opens the Flow Hub (same as main calendar)
  void Function(int? flowId) _getFlowStudioCallback() {
    return (int? flowId) {
      // If flowId provided, go directly to that flow
      if (flowId != null) {
        if (kIsWeb) {
          unawaited(
            CalendarPage.openFlowEditorFromAnyContext(
              context,
              flowId: flowId,
              fallbackLocation: '/',
              source: 'flow_studio_callback',
            ),
          );
          return;
        }
        _openFlowEditorDirectly(flowId);
        return;
      }

      // Otherwise open Flow Hub as before
      _openFlowStudioSheet(
        rootBuilder: (innerCtx) {
          return _FlowHubPage(
            openMyFlows: () {
              unawaited(
                _pushFlowStudioRoute<void>(
                  Navigator.of(innerCtx),
                  MaterialPageRoute<void>(
                    builder: (ctx2) => _FlowsViewerPage(
                      loadFilingSnapshot: _loadMyFlowsFilingSnapshot,
                      initialFilingSnapshot: _cachedMyFlowsFilingSnapshot(),
                      fmtGregorian: (d) => d == null
                          ? '--'
                          : '${d.year}-${d.month.toString().padLeft(2, '0')}-${d.day.toString().padLeft(2, '0')}',
                      onCreateNew: () async {
                        final edited = await _pushFlowStudioEditor(
                          Navigator.of(innerCtx),
                          returnState: const <String, dynamic>{
                            'mode': _kFlowStudioModeMyFlows,
                          },
                        );
                        if (edited != null) {
                          await _persistFlowStudioResult(edited);
                        }
                        await _loadFromDisk();
                      },
                      onEditFlow: (id) async {
                        final edited = await _pushFlowStudioEditor(
                          Navigator.of(innerCtx),
                          editFlowId: id,
                          returnState: const <String, dynamic>{
                            'mode': _kFlowStudioModeMyFlows,
                          },
                        );
                        if (edited != null) {
                          await _persistFlowStudioResult(edited);
                        }
                        await _loadFromDisk();
                      },
                      onEndFlow: (id) => _endFlow(id),
                      onImportFlow: (importedFlowId) async {
                        if (importedFlowId != null) {
                          await _loadFromDisk();
                        }
                      },
                      onAppendToJournal: _journalInitialized
                          ? (text) => _journalController.appendToToday(text)
                          : null,
                    ),
                  ),
                  visibleState: const <String, dynamic>{
                    'mode': _kFlowStudioModeMyFlows,
                  },
                  returnState: const <String, dynamic>{
                    'mode': _kFlowStudioModeHub,
                  },
                ),
              );
            },
            openMaatFlows: () {
              unawaited(() async {
                await _loadFromDisk(source: 'open_maat_flows');
                if (!innerCtx.mounted) return;
                final importedFlowId = await _pushFlowStudioRoute<int?>(
                  Navigator.of(innerCtx),
                  MaterialPageRoute<int?>(
                    builder: (ctx3) => _buildMaatFlowsListPage(ctx3),
                  ),
                  visibleState: const <String, dynamic>{
                    'mode': _kFlowStudioModeMaatFlows,
                  },
                  returnState: const <String, dynamic>{
                    'mode': _kFlowStudioModeHub,
                  },
                );
                if (importedFlowId != null && importedFlowId > 0) {
                  await _loadFromDisk(source: 'maat_flow_imported');
                }
              }());
            },
            onCreateNew: () async {
              final edited = await _pushFlowStudioEditor(
                Navigator.of(innerCtx),
                returnState: const <String, dynamic>{
                  'mode': _kFlowStudioModeHub,
                },
              );
              if (edited != null) await _persistFlowStudioResult(edited);
            },
          );
        },
      );
    };
  }

  void _openFlowEditorDirectly(int flowId) {
    _openFlowStudioSheet(
      continuityState: <String, dynamic>{
        'mode': _kFlowStudioModeEditor,
        'editFlowId': flowId,
      },
      rootBuilder: (innerCtx) {
        return _FlowStudioPage(
          // Force DB load for full fidelity (rules/notes) when editing.
          existingFlows: const [],
          editFlowId: flowId,
        );
      },
    );
  }

  void _openFlowsViewer() {
    _openFlowStudioSheet(
      continuityState: const <String, dynamic>{'mode': _kFlowStudioModeMyFlows},
      rootBuilder: (innerCtx) {
        return _FlowsViewerPage(
          loadFilingSnapshot: _loadMyFlowsFilingSnapshot,
          initialFilingSnapshot: _cachedMyFlowsFilingSnapshot(),
          fmtGregorian: (d) => d == null
              ? '--'
              : '${d.year}-${d.month.toString().padLeft(2, '0')}-${d.day.toString().padLeft(2, '0')}',
          onCreateNew: () async {
            final edited = await _pushFlowStudioEditor(
              Navigator.of(innerCtx),
              returnState: const <String, dynamic>{
                'mode': _kFlowStudioModeMyFlows,
              },
            );
            await _saveCalendarOverlayState(
              _kCalendarOverlayKindFlowStudio,
              const <String, dynamic>{'mode': _kFlowStudioModeMyFlows},
            );
            if (edited != null) await _persistFlowStudioResult(edited);
            // ✅ Refresh calendar data after flow operations
            await _loadFromDisk();
          },
          onEditFlow: (id) async {
            final edited = await _pushFlowStudioEditor(
              Navigator.of(innerCtx),
              editFlowId: id,
              returnState: const <String, dynamic>{
                'mode': _kFlowStudioModeMyFlows,
              },
            );
            await _saveCalendarOverlayState(
              _kCalendarOverlayKindFlowStudio,
              const <String, dynamic>{'mode': _kFlowStudioModeMyFlows},
            );
            if (edited != null) await _persistFlowStudioResult(edited);
            // ✅ Refresh calendar data after flow operations
            await _loadFromDisk();
          },
          onEndFlow: (id) => _endFlow(id),
          onImportFlow: (importedFlowId) async {
            if (importedFlowId != null) {
              await _loadFromDisk();
            }
          },
          onAppendToJournal: _journalInitialized
              ? (text) => _journalController.appendToToday(text)
              : null,
        );
      },
    );
  }

  /* ─────────── Ma’at Flows helpers ─────────── */

  /// True if there is at least one *active* instance of template [tplKey]
  /// with any remaining day today or in the future.
  bool _hasActiveMaatInstanceFor(String tplKey) {
    return _flows.any((f) {
      return CalendarPage._flowMatchesActiveMaatTemplate(f, tplKey);
    });
  }

  MoonReturnEnrollmentWindow? _resolveMountedMoonReturnJoinWindow({
    required TrackSkyTimeZone timezone,
    DateTime? startDate,
  }) {
    final now = DateTime.now();
    Object? caughtError;
    StackTrace? caughtStackTrace;
    final window = resolveMoonReturnEnrollmentWindowSafely(
      timezone: timezone,
      startDate: startDate,
      now: now,
      onError: (error, stackTrace) {
        caughtError = error;
        caughtStackTrace = stackTrace;
      },
    );
    if (window == null && kDebugMode) {
      _calendarDebugPrint(
        '[moonReturn] enrollment window unavailable: '
        'flow=The Moon Return '
        'timezone=${timezone.key} '
        'selectedDate=${startDate?.toIso8601String() ?? 'none'} '
        'now=${now.toIso8601String()} '
        'reason=${caughtError ?? 'no matching enrollment window'}',
      );
      final stackTrace = caughtStackTrace;
      if (stackTrace != null) {
        _calendarDebugPrint('$stackTrace');
      }
    }
    return window;
  }

  WagEnrollmentWindow? _resolveMountedWagJoinWindow({
    required TrackSkyTimeZone timezone,
    DateTime? startDate,
  }) {
    final now = DateTime.now();
    Object? caughtError;
    StackTrace? caughtStackTrace;
    final window = resolveWagEnrollmentWindowSafely(
      timezone: timezone,
      startDate: startDate,
      now: now,
      onError: (error, stackTrace) {
        caughtError = error;
        caughtStackTrace = stackTrace;
      },
    );
    if (window == null && kDebugMode) {
      _calendarDebugPrint(
        '[theWag] enrollment window unavailable: '
        'flow=The Wag '
        'timezone=${timezone.key} '
        'selectedDate=${startDate?.toIso8601String() ?? 'none'} '
        'now=${now.toIso8601String()} '
        'reason=${caughtError ?? 'no matching enrollment window'}',
      );
      final stackTrace = caughtStackTrace;
      if (stackTrace != null) {
        _calendarDebugPrint('$stackTrace');
      }
    }
    return window;
  }

