  /// Create a user-owned *instance* from a Ma'at template starting on [startDate].
  /// - Sequence templates use [startDate] and optionally [useKemetic].
  /// - Ongoing templates can use their own join settings, such as timezone.
  /// - Returns the created flow's id.
  Future<int> _addMaatFlowInstance({
    required _MaatFlowTemplate template,
    DateTime? startDate,
    bool useKemetic = false,
    TrackSkyTimeZone? trackSkyTimeZone,
    int alertMinutesBefore = _alertNoneMinutes,
    bool dawnDiscreetMode = false,
    DawnHouseRiteLens dawnLens = DawnHouseRiteLens.neutral,
    bool eveningDiscreetMode = false,
    EveningThresholdRiteLens eveningLens = EveningThresholdRiteLens.neutral,
    int eveningFallbackMinutesAfterMidnight =
        kEveningThresholdDefaultFallbackMinutes,
    TheWeighingLens theWeighingLens = TheWeighingLens.neutral,
    OfferingTableLens offeringTableLens = OfferingTableLens.neutral,
    bool offeringNoCupMode = false,
    TheTendingLens theTendingLens = TheTendingLens.neutral,
    KeptWordLens keptWordLens = KeptWordLens.neutral,
    CourseLens courseLens = CourseLens.neutral,
    MoonReturnLens moonReturnLens = MoonReturnLens.neutral,
    WagLens wagLens = WagLens.neutral,
    DecanWatchLens decanWatchLens = DecanWatchLens.neutral,
    OpenHandLens openHandLens = OpenHandLens.neutral,
    DjedLens djedLens = DjedLens.neutral,
  }) async {
    if (template.kind == _MaatFlowTemplateKind.trackSky) {
      final timezone = trackSkyTimeZone ?? detectTrackSkyTimeZone();
      final flowData = await loadTrackSkyFlowData(timezone);
      final events = upcomingTrackSkyEvents(flowData);
      if (events.isEmpty) {
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(
              content: Text('No upcoming sky events remain for this flow.'),
            ),
          );
        }
        return -1;
      }

      final dates = <DateTime>{
        for (final event in events)
          DateUtils.dateOnly(trackSkyEventStartLocal(event, timezone)),
      };
      final orderedDates = dates.toList()..sort();
      final firstG = orderedDates.first;
      final lastG = orderedDates.last;

      final flow = _Flow(
        id: -1,
        calendarId: _personalCalendarId,
        name: template.title,
        color: template.color,
        active: true,
        rules: [_RuleDates(dates: dates)],
        start: firstG,
        end: lastG,
        notes: [
          'mode=gregorian',
          'split=1',
          if (template.overview.trim().isNotEmpty)
            'ov=${Uri.encodeComponent(template.overview.trim())}',
          'maat=${template.key}',
          'sky_tz=${timezone.key}',
        ].join(';'),
      );

      final serverFlowId = await _saveNewFlow(flow);
      if (serverFlowId == null) {
        if (kDebugMode) {
          _calendarDebugPrint('[trackSky] Aborting - flow insert failed');
        }
        return -1;
      }

      final repo = UserEventsRepo(Supabase.instance.client);
      try {
        for (final event in events) {
          final startLocal = trackSkyEventStartLocal(event, timezone);
          final endLocal = trackSkyEventEndLocal(event, timezone);
          final dayOnly = DateUtils.dateOnly(startLocal);
          final kyKmKd = KemeticMath.fromGregorian(dayOnly);
          final startTod = event.schedule.allDay
              ? null
              : TimeOfDay(hour: startLocal.hour, minute: startLocal.minute);
          final endTod = event.schedule.allDay
              ? null
              : TimeOfDay(hour: endLocal.hour, minute: endLocal.minute);
          final clientEventId = _buildCid(
            ky: kyKmKd.kYear,
            km: kyKmKd.kMonth,
            kd: kyKmKd.kDay,
            title: event.title,
            startHour: startTod?.hour,
            startMinute: startTod?.minute,
            allDay: event.schedule.allDay,
            flowId: serverFlowId,
          );
          final note = _Note(
            clientEventId: clientEventId,
            title: event.title,
            detail: event.detailText,
            allDay: event.schedule.allDay,
            start: startTod,
            end: endTod,
            flowId: serverFlowId,
            category: event.category,
            alertOffsetMinutes: alertMinutesBefore,
          );

          _addNote(
            kyKmKd.kYear,
            kyKmKd.kMonth,
            kyKmKd.kDay,
            event.title,
            event.detailText,
            clientEventId: clientEventId,
            allDay: event.schedule.allDay,
            start: startTod,
            end: endTod,
            flowId: serverFlowId,
            category: event.category,
            alertOffsetMinutes: alertMinutesBefore,
          );

          await repo.upsertByClientId(
            clientEventId: clientEventId,
            title: event.title,
            startsAtUtc: trackSkyEventStartUtc(event, timezone),
            detail: _encodeDetailWithMeta(
              event.detailText,
              alertMinutes: alertMinutesBefore,
            ),
            location: null,
            allDay: event.schedule.allDay,
            endsAtUtc: trackSkyEventEndUtc(event, timezone),
            category: event.category,
            flowLocalId: serverFlowId,
            caller: 'track_sky_join',
          );

          await _scheduleAlertForEvent(
            note: note,
            ky: kyKmKd.kYear,
            km: kyKmKd.kMonth,
            kd: kyKmKd.kDay,
            clientEventId: clientEventId,
          );
        }
      } catch (e, st) {
        if (kDebugMode) {
          _calendarDebugPrint('[trackSky] event creation failed: $e');
          _calendarDebugPrint('$st');
        }
        _flows.removeWhere((flow) => flow.id == serverFlowId);
        final emptyKeys = <String>[];
        _notes.forEach((key, notes) {
          notes.removeWhere((note) => note.flowId == serverFlowId);
          if (notes.isEmpty) emptyKeys.add(key);
        });
        for (final key in emptyKeys) {
          _notes.remove(key);
        }
        if (mounted) {
          setState(() {});
          ScaffoldMessenger.of(context).showSnackBar(
            SnackBar(content: Text('Could not create ${template.title}.')),
          );
        }
        try {
          await repo.deleteFlow(serverFlowId);
        } catch (_) {}
        return -1;
      }

      setState(() {});
      return serverFlowId;
    }

    if (template.kind == _MaatFlowTemplateKind.moonReturn) {
      final timezone = trackSkyTimeZone ?? detectTrackSkyTimeZone();
      final window = _resolveMountedMoonReturnJoinWindow(
        timezone: timezone,
        startDate: startDate,
      );
      if (window == null) {
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(
              content: Text('Choose one of the listed new-moon start dates.'),
            ),
          );
        }
        return const FlowJoinResult.failure(
          FlowJoinFailureCode.noEnrollmentWindow,
        ).flowIdOrNegativeOne;
      }
      final occurrences = moonReturnOccurrencesForWindow(window: window);
      if (occurrences.isEmpty) {
        return const FlowJoinResult.failure(
          FlowJoinFailureCode.noOccurrences,
        ).flowIdOrNegativeOne;
      }
      final dates = <DateTime>{
        for (final occurrence in occurrences)
          DateUtils.dateOnly(occurrence.startLocal),
      };
      final orderedDates = dates.toList()..sort();
      final nowLocal = moonReturnNowInZone(timezone);

      final flow = _Flow(
        id: -1,
        calendarId: _personalCalendarId,
        name: template.title,
        color: template.color,
        active: true,
        rules: [_RuleDates(dates: dates)],
        start: DateUtils.dateOnly(window.opensAtLocal),
        end: orderedDates.last,
        notes: [
          'mode=astronomy',
          'split=1',
          if (template.overview.trim().isNotEmpty)
            'ov=${Uri.encodeComponent(template.overview.trim())}',
          'maat=${template.key}',
          'moon_tz=${timezone.key}',
          'moon_lens=${moonReturnLens.key}',
          'moon_enrolled_at=${nowLocal.toIso8601String()}',
          'moon_window_open=${CalendarPage._formatDetachedGregorian(window.opensAtLocal)}',
          'moon_new_moon=${window.newMoonDateIso}',
        ].join(';'),
      );

      final serverFlowId = await _saveNewFlow(flow);
      if (serverFlowId == null) {
        if (kDebugMode) {
          _calendarDebugPrint('[moonReturn] Aborting - flow insert failed');
        }
        return -1;
      }

      final repo = UserEventsRepo(Supabase.instance.client);
      try {
        for (final occurrence in occurrences) {
          final kyKmKd = KemeticMath.fromGregorian(
            DateUtils.dateOnly(occurrence.startLocal),
          );
          final startTod = TimeOfDay(
            hour: occurrence.startLocal.hour,
            minute: occurrence.startLocal.minute,
          );
          final endTod = TimeOfDay(
            hour: occurrence.endLocal.hour,
            minute: occurrence.endLocal.minute,
          );
          final title = moonReturnEventTitle(occurrence);
          final detail = moonReturnDetailText(occurrence, lens: moonReturnLens);
          final behaviorPayload = moonReturnBehaviorPayload(
            occurrence: occurrence,
            lens: moonReturnLens,
          );
          final clientEventId = moonReturnClientEventId(
            flowId: serverFlowId,
            occurrence: occurrence,
          );
          final note = _Note(
            clientEventId: clientEventId,
            calendarId: _personalCalendarId,
            title: title,
            detail: detail,
            allDay: false,
            start: startTod,
            end: endTod,
            flowId: serverFlowId,
            category: 'Ritual',
            alertOffsetMinutes: 0,
            actionId: moonReturnActionId(occurrence),
            behaviorPayload: behaviorPayload,
          );

          _addNote(
            kyKmKd.kYear,
            kyKmKd.kMonth,
            kyKmKd.kDay,
            title,
            detail,
            clientEventId: clientEventId,
            calendarId: _personalCalendarId,
            allDay: false,
            start: startTod,
            end: endTod,
            flowId: serverFlowId,
            category: 'Ritual',
            alertOffsetMinutes: 0,
            actionId: moonReturnActionId(occurrence),
            behaviorPayload: behaviorPayload,
          );

          await repo.upsertByClientId(
            clientEventId: clientEventId,
            title: title,
            startsAtUtc: occurrence.startUtc,
            detail: detail,
            calendarId: _personalCalendarId,
            allDay: false,
            endsAtUtc: occurrence.endUtc,
            category: 'Ritual',
            flowLocalId: serverFlowId,
            actionId: moonReturnActionId(occurrence),
            behaviorPayload: behaviorPayload,
            caller: 'moon_return_join',
          );

          await _scheduleAlertForEvent(
            note: note,
            ky: kyKmKd.kYear,
            km: kyKmKd.kMonth,
            kd: kyKmKd.kDay,
            clientEventId: clientEventId,
          );
        }
      } catch (e, st) {
        if (kDebugMode) {
          _calendarDebugPrint('[moonReturn] event creation failed: $e');
          _calendarDebugPrint('$st');
        }
        _flows.removeWhere((flow) => flow.id == serverFlowId);
        final emptyKeys = <String>[];
        _notes.forEach((key, notes) {
          notes.removeWhere((note) => note.flowId == serverFlowId);
          if (notes.isEmpty) emptyKeys.add(key);
        });
        for (final key in emptyKeys) {
          _notes.remove(key);
        }
        if (mounted) {
          setState(() {});
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(content: Text('Could not create The Moon Return.')),
          );
        }
        try {
          await repo.deleteFlow(serverFlowId);
        } catch (_) {}
        return -1;
      }

      setState(() {});
      return serverFlowId;
    }

    if (template.kind == _MaatFlowTemplateKind.theWag) {
      final timezone = trackSkyTimeZone ?? detectTrackSkyTimeZone();
      final window = _resolveMountedWagJoinWindow(
        timezone: timezone,
        startDate: startDate,
      );
      if (window == null) {
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(
              content: Text('Choose one of the listed Wep Ronpet start dates.'),
            ),
          );
        }
        return const FlowJoinResult.failure(
          FlowJoinFailureCode.noEnrollmentWindow,
        ).flowIdOrNegativeOne;
      }
      final kYear = window.kYear;
      final alreadyEnrolled = _flows.any((flow) {
        final notes = (flow.notes ?? '').toLowerCase();
        return flow.active &&
            resolveMaatFlowKind(flowNotes: flow.notes) == MaatFlowKind.theWag &&
            notes.contains('wag_kyear=$kYear');
      });
      if (alreadyEnrolled) {
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(
              content: Text('You are already enrolled in this year\'s Wag.'),
            ),
          );
        }
        return -1;
      }

      final schedules = <WagEvent, WagOccurrenceSchedule>{
        for (final event in kWagEvents)
          event: wagScheduleForEvent(
            event: event,
            kYear: kYear,
            timezone: timezone,
          ),
      };
      final dates = <DateTime>{
        for (final schedule in schedules.values)
          DateUtils.dateOnly(schedule.startLocal),
      };
      final nowLocal = wagNowInZone(timezone);
      final flow = _Flow(
        id: -1,
        calendarId: _personalCalendarId,
        name: template.title,
        color: template.color,
        active: true,
        rules: [_RuleDates(dates: dates)],
        start: DateUtils.dateOnly(wagYearStartGregorian(kYear)),
        end: DateUtils.dateOnly(wagYearEndGregorian(kYear)),
        notes: [
          'mode=kemetic',
          'split=1',
          if (template.overview.trim().isNotEmpty)
            'ov=${Uri.encodeComponent(template.overview.trim())}',
          'maat=${template.key}',
          'wag_kyear=$kYear',
          'wag_tz=${timezone.key}',
          'wag_lens=${wagLens.key}',
          'wag_enrolled_at=${nowLocal.toIso8601String()}',
          'wag_window_open=${CalendarPage._formatDetachedGregorian(window.opensAtLocal)}',
        ].join(';'),
      );

      final serverFlowId = await _saveNewFlow(flow);
      if (serverFlowId == null) {
        if (kDebugMode) {
          _calendarDebugPrint('[theWag] Aborting - flow insert failed');
        }
        return -1;
      }

      final repo = UserEventsRepo(Supabase.instance.client);
      try {
        for (final event in kWagEvents) {
          final schedule = schedules[event]!;
          final variant = wagCopyVariantForEvent(event: event, kYear: kYear);
          final kyKmKd = KemeticMath.fromGregorian(
            DateUtils.dateOnly(schedule.startLocal),
          );
          final startTod = TimeOfDay(
            hour: schedule.startLocal.hour,
            minute: schedule.startLocal.minute,
          );
          final endTod = TimeOfDay(
            hour: schedule.endLocal.hour,
            minute: schedule.endLocal.minute,
          );
          final title = wagEventTitle(event);
          final detail = wagDetailText(
            event,
            lens: wagLens,
            variant: variant,
            nextWagDate: event.sharePromptOnComplete
                ? wagNextFeastGregorian(kYear)
                : null,
          );
          final behaviorPayload = wagBehaviorPayload(
            event: event,
            kYear: kYear,
            timezoneKey: timezone.key,
            ianaTimezone: timezone.ianaName,
            scheduleType: schedule.scheduleType,
            referenceLocationName: schedule.referenceLocationName,
            usedFallback: schedule.usedFallback,
            lens: wagLens,
            variant: variant,
          );
          final clientEventId = wagClientEventId(
            flowId: serverFlowId,
            kYear: kYear,
            event: event,
          );
          final note = _Note(
            clientEventId: clientEventId,
            calendarId: _personalCalendarId,
            title: title,
            detail: detail,
            allDay: false,
            start: startTod,
            end: endTod,
            flowId: serverFlowId,
            category: 'Ritual',
            alertOffsetMinutes: 0,
            actionId: wagActionId(event),
            behaviorPayload: behaviorPayload,
          );

          _addNote(
            kyKmKd.kYear,
            kyKmKd.kMonth,
            kyKmKd.kDay,
            title,
            detail,
            clientEventId: clientEventId,
            calendarId: _personalCalendarId,
            allDay: false,
            start: startTod,
            end: endTod,
            flowId: serverFlowId,
            category: 'Ritual',
            alertOffsetMinutes: 0,
            actionId: wagActionId(event),
            behaviorPayload: behaviorPayload,
          );

          await repo.upsertByClientId(
            clientEventId: clientEventId,
            title: title,
            startsAtUtc: schedule.startUtc,
            detail: detail,
            calendarId: _personalCalendarId,
            allDay: false,
            endsAtUtc: schedule.endUtc,
            category: 'Ritual',
            flowLocalId: serverFlowId,
            actionId: wagActionId(event),
            behaviorPayload: behaviorPayload,
            caller: 'wag_join',
          );

          await _scheduleAlertForEvent(
            note: note,
            ky: kyKmKd.kYear,
            km: kyKmKd.kMonth,
            kd: kyKmKd.kDay,
            clientEventId: clientEventId,
          );
        }
      } catch (e, st) {
        if (kDebugMode) {
          _calendarDebugPrint('[theWag] event creation failed: $e');
          _calendarDebugPrint('$st');
        }
        _flows.removeWhere((flow) => flow.id == serverFlowId);
        final emptyKeys = <String>[];
        _notes.forEach((key, notes) {
          notes.removeWhere((note) => note.flowId == serverFlowId);
          if (notes.isEmpty) emptyKeys.add(key);
        });
        for (final key in emptyKeys) {
          _notes.remove(key);
        }
        if (mounted) {
          setState(() {});
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(content: Text('Could not create The Wag.')),
          );
        }
        try {
          await repo.deleteFlow(serverFlowId);
        } catch (_) {}
        return -1;
      }

      setState(() {});
      return serverFlowId;
    }

    if (template.kind == _MaatFlowTemplateKind.daysOutsideTheYear) {
      final timezone = trackSkyTimeZone ?? detectTrackSkyTimeZone();
      final window = _resolveMountedDaysOutsideYearJoinWindow(
        timezone: timezone,
        startDate: startDate,
      );
      if (window == null) {
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(
              content: Text(
                'Choose one of the listed year-closing start dates.',
              ),
            ),
          );
        }
        return const FlowJoinResult.failure(
          FlowJoinFailureCode.noEnrollmentWindow,
        ).flowIdOrNegativeOne;
      }
      final closingKYear = window.closingKYear;
      final alreadyEnrolled = _flows.any((flow) {
        final notes = (flow.notes ?? '').toLowerCase();
        return flow.active &&
            resolveMaatFlowKind(flowNotes: flow.notes) ==
                MaatFlowKind.daysOutsideTheYear &&
            notes.contains('doy_kyear=$closingKYear');
      });
      if (alreadyEnrolled) {
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(
              content: Text(
                'You are already enrolled in this year\'s Days Outside the Year.',
              ),
            ),
          );
        }
        return -1;
      }

      final schedules = <DaysOutsideEvent, DaysOutsideOccurrenceSchedule>{
        for (final event in kDaysOutsideEvents)
          event: daysOutsideScheduleForEvent(
            event: event,
            closingKYear: closingKYear,
            timezone: timezone,
          ),
      };
      final dates = <DateTime>{
        for (final schedule in schedules.values)
          DateUtils.dateOnly(schedule.startLocal),
      };
      final nowLocal = daysOutsideNowInZone(timezone);
      final flow = _Flow(
        id: -1,
        calendarId: _personalCalendarId,
        name: template.title,
        color: template.color,
        active: true,
        rules: [_RuleDates(dates: dates)],
        start: DateUtils.dateOnly(window.opensAtLocal),
        end: DateUtils.dateOnly(daysOutsideFlowEndGregorian(closingKYear)),
        notes: [
          'mode=kemetic',
          'split=1',
          if (template.overview.trim().isNotEmpty)
            'ov=${Uri.encodeComponent(template.overview.trim())}',
          'maat=${template.key}',
          'doy_kyear=$closingKYear',
          'doy_tz=${timezone.key}',
