  }

  Future<void> _recordEventCompletion({
    required String clientEventId,
    required int flowId,
    required DateTime completedOnDate,
    Map<String, dynamic>? metadata,
  }) async {
    final repo = UserEventsRepo(Supabase.instance.client);
    try {
      await repo.recordEventCompletion(
        clientEventId: clientEventId,
        flowId: flowId,
        completedOnDate: completedOnDate,
        metadata: metadata,
      );
      if (resolveMaatFlowKind(behaviorPayload: metadata) ==
          MaatFlowKind.decanWatch) {
        unawaited(_ensureDecanWatchHorizon(flowId));
      }
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint('[DayView] recordEventCompletion failed: $e');
      }
    }
  }

  Future<void> _ensureDecanWatchHorizon(int flowId) async {
    final flowIndex = _flows.indexWhere((flow) => flow.id == flowId);
    if (flowIndex < 0) return;
    final flow = _flows[flowIndex];
    if (!flow.active) return;
    if (resolveMaatFlowKind(flowNotes: flow.notes) != MaatFlowKind.decanWatch) {
      return;
    }

    final timezone =
        _trackSkyTimeZoneFromKey(_flowNoteToken(flow.notes, 'dw_tz=')) ??
        detectTrackSkyTimeZone();
    final lens = decanWatchLensFromNotes(flow.notes);
    final hour =
        int.tryParse(_flowNoteToken(flow.notes, 'dw_hour=') ?? '') ??
        kDecanWatchDefaultHour;
    final minute =
        int.tryParse(_flowNoteToken(flow.notes, 'dw_minute=') ?? '') ??
        kDecanWatchDefaultMinute;
    final occurrences = upcomingDecanWatchOccurrences(
      timezone: timezone,
      count: 3,
      hour: hour,
      minute: minute,
    );
    if (occurrences.isEmpty) return;

    final repo = UserEventsRepo(Supabase.instance.client);
    final ruleDates = <DateTime>{};
    for (final rule in flow.rules) {
      if (rule is _RuleDates) {
        ruleDates.addAll(rule.dates.map(DateUtils.dateOnly));
      }
    }

    for (final occurrence in occurrences) {
      final dayOnly = DateUtils.dateOnly(occurrence.startLocal);
      final kyKmKd = KemeticMath.fromGregorian(dayOnly);
      final context = courseContextForKemeticDate(
        kYear: occurrence.kYear,
        kMonth: occurrence.kMonth,
        kDay: occurrence.decanStartDay,
      );
      final title = decanWatchEventTitle(occurrence);
      final detail = decanWatchDetailText(
        occurrence,
        lens: lens,
        context: context,
      );
      final behaviorPayload = decanWatchBehaviorPayload(
        occurrence: occurrence,
        lens: lens,
      );
      final clientEventId = decanWatchClientEventId(
        flowId: flowId,
        occurrence: occurrence,
      );
      final startTod = TimeOfDay(
        hour: occurrence.startLocal.hour,
        minute: occurrence.startLocal.minute,
      );
      final endTod = TimeOfDay(
        hour: occurrence.endLocal.hour,
        minute: occurrence.endLocal.minute,
      );
      final note = _Note(
        clientEventId: clientEventId,
        calendarId: flow.calendarId ?? _personalCalendarId,
        title: title,
        detail: detail,
        allDay: false,
        start: startTod,
        end: endTod,
        flowId: flowId,
        category: 'Ritual',
        alertOffsetMinutes: 0,
        actionId: decanWatchActionId(occurrence),
        behaviorPayload: behaviorPayload,
      );
      try {
        await repo.upsertByClientId(
          clientEventId: clientEventId,
          title: title,
          startsAtUtc: occurrence.startUtc,
          detail: detail,
          calendarId: flow.calendarId ?? _personalCalendarId,
          allDay: false,
          endsAtUtc: occurrence.endUtc,
          category: 'Ritual',
          flowLocalId: flowId,
          actionId: decanWatchActionId(occurrence),
          behaviorPayload: behaviorPayload,
          caller: 'decan_watch_horizon',
        );
        ruleDates.add(dayOnly);

        _addNote(
          kyKmKd.kYear,
          kyKmKd.kMonth,
          kyKmKd.kDay,
          title,
          detail,
          clientEventId: clientEventId,
          calendarId: flow.calendarId ?? _personalCalendarId,
          allDay: false,
          start: startTod,
          end: endTod,
          flowId: flowId,
          category: 'Ritual',
          alertOffsetMinutes: 0,
          actionId: decanWatchActionId(occurrence),
          behaviorPayload: behaviorPayload,
          notify: false,
        );
        await _scheduleAlertForEvent(
          note: note,
          ky: kyKmKd.kYear,
          km: kyKmKd.kMonth,
          kd: kyKmKd.kDay,
          clientEventId: clientEventId,
        );
      } catch (e, st) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[decanWatchHorizon] event creation failed '
            'flowId=$flowId cid=$clientEventId: $e',
          );
          _calendarDebugPrint('$st');
        }
      }
    }

    final orderedDates = ruleDates.toList()..sort();
    if (orderedDates.isNotEmpty) {
      flow.rules
        ..clear()
        ..add(_RuleDates(dates: ruleDates));
      flow.start = orderedDates.first;
      flow.end = orderedDates.last;
      try {
        await repo.upsertFlow(
          id: flow.id,
          name: flow.name,
          color: flow.color.toARGB32(),
          active: flow.active,
          calendarId: flow.calendarId,
          startDate: flow.start,
          endDate: flow.end,
          notes: flow.notes,
          rules: jsonEncode(
            flow.rules.map(CalendarPageState.ruleToJson).toList(),
          ),
          originType: 'template',
        );
      } catch (e, st) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[decanWatchHorizon] flow rule update failed flowId=$flowId: $e',
          );
          _calendarDebugPrint('$st');
        }
      }
    }
    if (mounted) {
      setState(() {});
      _notifyDayViewDataChanged();
    }
  }

  String? _flowNoteToken(String? notes, String prefix) {
    if (notes == null || notes.isEmpty) return null;
    for (final token in notes.split(';')) {
      final trimmed = token.trim();
      if (trimmed.startsWith(prefix)) {
        return trimmed.substring(prefix.length);
      }
    }
    return null;
  }

  TrackSkyTimeZone? _trackSkyTimeZoneFromKey(String? key) {
    switch (key?.trim().toLowerCase()) {
      case 'pacific':
        return TrackSkyTimeZone.pacific;
      case 'mountain':
        return TrackSkyTimeZone.mountain;
      case 'central':
        return TrackSkyTimeZone.central;
      case 'eastern':
        return TrackSkyTimeZone.eastern;
    }
    return null;
  }

  Future<void> _unrecordEventCompletion(String clientEventId) async {
    final repo = UserEventsRepo(Supabase.instance.client);
    try {
      await repo.unrecordEventCompletion(clientEventId);
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint('[DayView] unrecordEventCompletion failed: $e');
      }
    }
  }

  Future<Set<String>> _loadCompletedClientEventIds({
    int? flowId,
    DateTime? completedOnDate,
  }) async {
    final user = Supabase.instance.client.auth.currentUser;
    if (user == null) return {};
    try {
      final client = Supabase.instance.client;
      var query = client
          .from('user_event_completions')
          .select('client_event_id')
          .eq('user_id', user.id);
      if (flowId != null) {
        query = query.eq('flow_id', flowId);
      }
      if (completedOnDate != null) {
        final dateStr =
            '${completedOnDate.year}-${completedOnDate.month.toString().padLeft(2, '0')}-${completedOnDate.day.toString().padLeft(2, '0')}';
        query = query.eq('completed_on', dateStr);
      }
      final rows = await query;
      final ids = <String>{};
      for (final row in (rows as List)) {
        final cid = (row as Map<String, dynamic>)['client_event_id'] as String?;
        if (cid != null && cid.isNotEmpty) {
          ids.add(cid);
        }
      }
      return ids;
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint('[DayView] loadCompletedClientEventIds failed: $e');
      }
      return {};
    }
  }

  void _openDaySheet(
    int kYear,
    int kMonth,
    int kDay, {
    bool allowDateChange = false,
    bool? initialShowGregorian,
    bool persistAsRestoration = true,
    TimeOfDay? initialStartTime,
    TimeOfDay? initialEndTime,
    bool initialAllDay = false,
    String? initialTitle,
    String? initialLocation,
    String? initialDetail,
    Color? initialColor,
    String? initialCategory,
    int? initialAlertMinutes,
    String? initialCalendarId,
    int? editingIndex,
    int? editingSourceKYear,
    int? editingSourceKMonth,
    int? editingSourceKDay,
  }) {
    // Ensure reminder rules are loaded before building the sheet so the list is populated.
    _loadReminderRules();
    _calendarDebugPrint('');
    _calendarDebugPrint('┌─────────────────────────────────────┐');
    _calendarDebugPrint('│ 📝 OPENING DAY SHEET                │');
    _calendarDebugPrint('├─────────────────────────────────────┤');
    _calendarDebugPrint('│ Date: $kYear/$kMonth/$kDay');
    _calendarDebugPrint('│ allowDateChange: $allowDateChange');
    _calendarDebugPrint('│ Context mounted: ${context.mounted}');
    _calendarDebugPrint('│ Context widget: ${context.widget.runtimeType}');
    _calendarDebugPrint('└─────────────────────────────────────┘');
    _calendarDebugPrint('');

    int selYear = kYear;
    int selMonth = kMonth;
    int selDay = kDay;
    final initialGregorianDate = KemeticMath.toGregorian(kYear, kMonth, kDay);
    bool showGregorianDates = initialShowGregorian ?? _showGregorian;
    int gregYear = initialGregorianDate.year;
    int gregMonth = initialGregorianDate.month;
    int gregDay = initialGregorianDate.day;

    int maxDayFor(int year, int month) =>
        (month == 13) ? (KemeticMath.isLeapKemeticYear(year) ? 6 : 5) : 30;
    int gregDayMax(int year, int month) =>
        DateUtils.getDaysInMonth(year, month);

    final int yearStart = _today.kYear - 200;
    final int yearItem = kYear - yearStart;
    final yearCtrl = FixedExtentScrollController(
      initialItem: yearItem.clamp(0, 400).toInt(),
    );
    final monthCtrl = FixedExtentScrollController(
      initialItem: (kMonth - 1).clamp(0, 12).toInt(),
    );
    final dayCtrl = FixedExtentScrollController(initialItem: (kDay - 1));
    final int gregYearStart = initialGregorianDate.year - 200;
    final gregYearCtrl = FixedExtentScrollController(
      initialItem: (gregYear - gregYearStart).clamp(0, 400).toInt(),
    );
    final gregMonthCtrl = FixedExtentScrollController(
      initialItem: (gregMonth - 1).clamp(0, 11).toInt(),
    );
    final gregDayCtrl = FixedExtentScrollController(
      initialItem: (gregDay - 1).clamp(0, 30).toInt(),
    );
    final sourceEditingKYear = editingSourceKYear ?? kYear;
    final sourceEditingKMonth = editingSourceKMonth ?? kMonth;
    final sourceEditingKDay = editingSourceKDay ?? kDay;
    final initialEditingBucketKey = _kKey(
      sourceEditingKYear,
      sourceEditingKMonth,
      sourceEditingKDay,
    );
    final initialEditingNote =
        editingIndex != null &&
            _notes[initialEditingBucketKey] != null &&
            editingIndex < _notes[initialEditingBucketKey]!.length
        ? _notes[initialEditingBucketKey]![editingIndex]
        : null;
    final availableCalendars =
        _calendarSummariesById.values
            .where(
              (calendar) =>
                  calendar.canEdit ||
                  initialEditingNote?.calendarId == calendar.id,
            )
            .toList()
          ..sort((a, b) {
            if (a.isPersonal && !b.isPersonal) return -1;
            if (!a.isPersonal && b.isPersonal) return 1;
            return a.name.toLowerCase().compareTo(b.name.toLowerCase());
          });
    final normalizedInitialCalendarId = _normalizeCalendarId(initialCalendarId);
    final initialCalendarCanEdit =
        normalizedInitialCalendarId != null &&
        availableCalendars.any(
          (calendar) => calendar.id == normalizedInitialCalendarId,
        );

    final rawInitialDetail = initialDetail ?? '';
    final strippedInitialDetail = _stripCidLines(rawInitialDetail);
    final initialCidMetadata = _extractCidMetadata(rawInitialDetail);

    final controllerTitle = TextEditingController(text: initialTitle ?? '');
    final controllerLocation = TextEditingController(
      text: initialLocation ?? '',
    );
    final controllerDetail = TextEditingController(text: strippedInitialDetail);

    bool allDay = initialAllDay;
    TimeOfDay? startTime =
        initialStartTime ?? const TimeOfDay(hour: 12, minute: 0);
    TimeOfDay? endTime = initialEndTime ?? const TimeOfDay(hour: 13, minute: 0);
    String? selectedCategory = initialCategory;
    int alertMinutesBefore = initialAlertMinutes ?? _alertNoneMinutes;
    String? selectedCalendarId =
        initialEditingNote?.calendarId ??
        (initialCalendarCanEdit ? normalizedInitialCalendarId : null) ??
        _personalCalendarId ??
        (availableCalendars.isNotEmpty ? availableCalendars.first.id : null);
    String? selectedCalendarName =
        initialEditingNote?.calendarName ??
        _calendarSummariesById[selectedCalendarId]?.name;

    // Repeat state
    NoteRepeatOption repeatOption = NoteRepeatOption.never;
    NoteRepeatEndType endType = NoteRepeatEndType.never;
    SimpleRecurrenceFrequency customFrequency = SimpleRecurrenceFrequency.daily;
    int customInterval = 1;
    DateTime? endDate;
    int endCount = 10;

    // Color state – index into _flowPalette
    int selectedColorIndex = initialColor != null
        ? _flowPalette.indexWhere(
            (c) => c.toARGB32() == initialColor.toARGB32(),
          )
        : 0;
    if (selectedColorIndex < 0) selectedColorIndex = 0;
    bool sheetClosing = false;
    bool sheetControllersDisposed = false;

    Map<String, dynamic> daySheetSessionPayload() {
      return <String, dynamic>{
        'kYear': selYear,
        'kMonth': selMonth,
        'kDay': selDay,
        'showGregorianDates': showGregorianDates,
        'allowDateChange': allowDateChange,
        'title': controllerTitle.text,
        'location': controllerLocation.text,
        'detail': controllerDetail.text,
        'allDay': allDay,
        'startHour': startTime?.hour,
        'startMinute': startTime?.minute,
        'endHour': endTime?.hour,
        'endMinute': endTime?.minute,
        'colorValue': _flowPalette[selectedColorIndex].toARGB32(),
        'category': selectedCategory,
        'alertMinutesBefore': alertMinutesBefore,
        'calendarId': selectedCalendarId,
        'editingIndex': editingIndex,
        'editingSourceKYear': editingIndex == null ? null : sourceEditingKYear,
        'editingSourceKMonth': editingIndex == null
            ? null
            : sourceEditingKMonth,
        'editingSourceKDay': editingIndex == null ? null : sourceEditingKDay,
      };
    }

    void persistDaySheetSession() {
      if (sheetClosing || sheetControllersDisposed) return;
      if (persistAsRestoration) {
        unawaited(
          AppRestorationService.instance.saveDaySheetState(
            daySheetSessionPayload(),
          ),
        );
      }
      unawaited(
        SessionResumeService.saveResumeEntry(
          baseRoute: '/',
          kind: _kSessionResumeKindDaySheet,
          payload: daySheetSessionPayload(),
        ),
      );
    }

    controllerTitle.addListener(persistDaySheetSession);
    controllerLocation.addListener(persistDaySheetSession);
    controllerDetail.addListener(persistDaySheetSession);
    persistDaySheetSession();

    void disposeDaySheetControllers() {
      if (sheetControllersDisposed) return;
      sheetControllersDisposed = true;
      controllerTitle.removeListener(persistDaySheetSession);
      controllerLocation.removeListener(persistDaySheetSession);
      controllerDetail.removeListener(persistDaySheetSession);
      controllerTitle.dispose();
      controllerLocation.dispose();
      controllerDetail.dispose();
      yearCtrl.dispose();
      monthCtrl.dispose();
      dayCtrl.dispose();
      gregYearCtrl.dispose();
      gregMonthCtrl.dispose();
      gregDayCtrl.dispose();
    }

    void scheduleDayPickerJump() {
      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (sheetClosing || sheetControllersDisposed || !dayCtrl.hasClients) {
          return;
        }
        dayCtrl.jumpToItem(selDay - 1);
      });
    }

    void scheduleGregorianDayPickerJump() {
      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (sheetClosing ||
            sheetControllersDisposed ||
            !gregDayCtrl.hasClients) {
          return;
        }
        gregDayCtrl.jumpToItem(gregDay - 1);
      });
    }

    void syncGregorianControllers() {
      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (sheetClosing || sheetControllersDisposed) return;
        if (gregYearCtrl.hasClients) {
          gregYearCtrl.jumpToItem(
            (gregYear - gregYearStart).clamp(0, 400).toInt(),
          );
        }
        if (gregMonthCtrl.hasClients) {
          gregMonthCtrl.jumpToItem((gregMonth - 1).clamp(0, 11).toInt());
        }
        if (gregDayCtrl.hasClients) {
          gregDayCtrl.jumpToItem((gregDay - 1).clamp(0, 30).toInt());
        }
      });
    }

    void syncKemeticControllers() {
      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (sheetClosing || sheetControllersDisposed) return;
        if (yearCtrl.hasClients) {
          yearCtrl.jumpToItem((selYear - yearStart).clamp(0, 400).toInt());
        }
        if (monthCtrl.hasClients) {
          monthCtrl.jumpToItem((selMonth - 1).clamp(0, 12).toInt());
        }
        if (dayCtrl.hasClients) {
          dayCtrl.jumpToItem((selDay - 1).clamp(0, 29).toInt());
        }
      });
    }

    void syncGregorianFromKemetic() {
      final gregorian = KemeticMath.toGregorian(selYear, selMonth, selDay);
      gregYear = gregorian.year;
      gregMonth = gregorian.month;
      gregDay = gregorian.day;
    }

    void syncKemeticFromGregorian() {
      final kemetic = KemeticMath.fromGregorian(
        DateUtils.dateOnly(DateTime(gregYear, gregMonth, gregDay)),
      );
      selYear = kemetic.kYear;
      selMonth = kemetic.kMonth;
      selDay = kemetic.kDay;
    }

    try {
      _calendarDebugPrint('🚀 Attempting to show modal bottom sheet...');
      UiGuards.disableJournalSwipe();
      showModalBottomSheet(
        context: context,
        isScrollControlled: true,
        backgroundColor: Colors.transparent, // ✅ More stable like Flow Studio
        useSafeArea: true,
        // iPad/tablet: allow swipe-to-close + backdrop tap to avoid trapped sheets.
        isDismissible: true,
        enableDrag: true,
        shape: const RoundedRectangleBorder(
          borderRadius: BorderRadius.vertical(top: Radius.circular(16)),
        ),
        builder: (sheetCtx) {
          final media = MediaQuery.of(sheetCtx);

          final labelStyleWhite = const TextStyle(
            color: Colors.white,
            fontSize: 18,
            fontWeight: FontWeight.w600,
          );

          final fieldLabel = const TextStyle(
            fontSize: 12,
            color: Color(0xFFBFC3C7),
          );
          bool showReminders = _noteSheetShowReminders;

          final daySheetContent = StatefulBuilder(
            builder: (sheetCtx, setSheetState) {
              // Clamp before any toGregorian
              int dayCount = maxDayFor(selYear, selMonth);
              if (selDay > dayCount) {
                selDay = dayCount;
                if (allowDateChange && dayCtrl.hasClients) {
                  scheduleDayPickerJump();
                }
              }

              final titleG = KemeticMath.toGregorian(
                selYear,
                selMonth,
                selDay,
