              syncGregorianFromKemetic();
              final titleGradient = showGregorianDates ? whiteGloss : goldGloss;
              final wheelGradient = showGregorianDates ? blueGloss : goldGloss;
              final dateTitleStyle = labelStyleWhite.copyWith(
                fontSize: 18,
                fontWeight: FontWeight.w500,
                fontFamily: 'GentiumPlus',
                fontFamilyFallback: const [
                  'NotoSans',
                  'Roboto',
                  'Arial',
                  'sans-serif',
                ],
              );

              final dayNotes = _getNotes(selYear, selMonth, selDay);
              final dayFlows = _getFlowOccurrences(selYear, selMonth, selDay);
              final editingNote = initialEditingNote;
              final selectedCalendar = selectedCalendarId == null
                  ? null
                  : _calendarSummariesById[selectedCalendarId];
              final selectedCalendarLabel =
                  selectedCalendar?.name ??
                  selectedCalendarName ??
                  'My Calendar';

              Future<void> pickStart() async {
                final t = await showTimePicker(
                  context: sheetCtx,
                  initialTime:
                      startTime ?? const TimeOfDay(hour: 12, minute: 0),
                  builder: (c, w) => Theme(
                    data: Theme.of(c).copyWith(
                      colorScheme: const ColorScheme.dark(
                        primary: _gold,
                        surface: _bg,
                        onSurface: Colors.white,
                      ),
                    ),
                    child: w ?? const SizedBox.shrink(),
                  ),
                );
                if (t == null) return;
                setSheetState(() {
                  startTime = t;
                  if (endTime != null &&
                      _toMinutes(endTime!) <= _toMinutes(t)) {
                    endTime = _addMinutes(t, 60);
                  }
                });
                persistDaySheetSession();
              }

              Future<void> pickEnd() async {
                final t = await showTimePicker(
                  context: sheetCtx,
                  initialTime:
                      endTime ??
                      (startTime != null
                          ? _addMinutes(startTime!, 60)
                          : const TimeOfDay(hour: 13, minute: 0)),
                  builder: (c, w) => Theme(
                    data: Theme.of(c).copyWith(
                      colorScheme: const ColorScheme.dark(
                        primary: _gold,
                        surface: _bg,
                        onSurface: Colors.white,
                      ),
                    ),
                    child: w ?? const SizedBox.shrink(),
                  ),
                );
                if (t == null) return;
                setSheetState(() {
                  endTime = t;
                  if (startTime != null &&
                      _toMinutes(t) <= _toMinutes(startTime!)) {
                    startTime = _addMinutes(t, -60);
                  }
                });
                persistDaySheetSession();
              }

              Widget timeButton({
                required String label,
                required TimeOfDay? value,
                required VoidCallback onTap,
                required bool enabled,
              }) {
                final text = value == null ? '--:--' : _formatTimeOfDay(value);
                return Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(label, style: fieldLabel),
                    const SizedBox(height: 6),
                    SizedBox(
                      height: 40,
                      child: OutlinedButton(
                        style: OutlinedButton.styleFrom(
                          foregroundColor: Colors.white,
                          side: const BorderSide(color: _silver, width: 1),
                        ),
                        onPressed: enabled ? onTap : null,
                        child: Text(text),
                      ),
                    ),
                  ],
                );
              }

              Widget datePicker() {
                final titleWidget = Semantics(
                  button: allowDateChange,
                  label: showGregorianDates
                      ? 'Show Kemetic dates'
                      : 'Show Gregorian dates',
