                                  ),
                                ),
                                const SizedBox(width: 6),
                                Expanded(
                                  flex: 4,
                                  child: CupertinoPicker(
                                    scrollController: gregYearCtrl,
                                    itemExtent: 32,
                                    looping: false,
                                    backgroundColor: const Color(0x00121214),
                                    onSelectedItemChanged: (i) {
                                      setSheetState(() {
                                        gregYear = gregYearStart + i;
                                        final max = gregDayMax(
                                          gregYear,
