                                          if (gregDayCtrl.hasClients) {
                                            scheduleGregorianDayPickerJump();
                                          }
                                        }
                                        syncKemeticFromGregorian();
                                      });
                                      persistDaySheetSession();
                                    },
                                    children: List<Widget>.generate(401, (i) {
                                      final year = gregYearStart + i;
