                                              NoteRepeatEndType.never) {
                                            endDate = null;
                                          }
                                        });
                                        persistDaySheetSession();
                                      }
                                    },
                              child: Container(
                                padding: const EdgeInsets.symmetric(
                                  vertical: 12,
                                ),
                                child: Row(
                                  mainAxisAlignment:
                                      MainAxisAlignment.spaceBetween,
                                  children: [
                                    GlossyText(
                                      text: 'End Repeat',
                                      gradient:
                                          repeatOption == NoteRepeatOption.never
