  void _repairDawnHouseRiteLoadedDetail({
    required UserEventsRepo repo,
    required FlowEventRow event,
    required String canonicalDetail,
    required Color? color,
    required int? alertMinutes,
  }) {
    final id = event.id;
    if (id == null || id.isEmpty) return;
    final updatedDetail = _encodeDetailWithMeta(
      canonicalDetail,
      color: color,
      alertMinutes: alertMinutes,
    );
    if (updatedDetail == null || updatedDetail == event.detail) return;

    unawaited(() async {
      try {
        await repo.update(id: id, detail: updatedDetail);
      } catch (e, st) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[dawnHouseRite] detail repair failed id=$id: $e',
          );
          _calendarDebugPrint('$st');
        }
      }
    }());
  }

  Future<void> _loadFromDisk({
    String source = 'manual',
    bool preserveViewport = false,
  }) async {
    if (_isLoadingFromDisk) {
      return;
    }
    _isLoadingFromDisk = true;

    if (kDebugMode) {
      _calendarDebugPrint('=== _loadFromDisk START ($source) ===');
    }

    final currentUser = Supabase.instance.client.auth.currentUser;
    if (currentUser == null) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[loadFromDisk] Skipping load: no authenticated user',
        );
      }
      _isLoadingFromDisk = false;
      return;
    }
    final preservedScrollOffset = preserveViewport
        ? (_scrollCtrl.hasClients ? _scrollCtrl.position.pixels : null) ??
              _lastKnownCalendarScrollOffset
        : null;
    await _ensureManualDeleteTombstonesLoaded();
    try {
      final fastStartupMode = source.startsWith('startup:');
      final warmStartBackfillMode = source.startsWith('startup_backfill:');
      final keepWarmStartSnapshotVisible =
          warmStartBackfillMode && _hasWarmStartSnapshotVisibleForCurrentUser();
      final focusWindow = fastStartupMode
          ? _computeStartupVisibleHydrationWindow()
          : null;
      final repo = UserEventsRepo(Supabase.instance.client);

      // Flow-first: load flows, then events; join only to known active flows
      final List<_Flow> newFlows = [];
      final Map<String, List<_Note>> newNotes = {};
      int nextFlowId = _nextFlowId;

      // Load flows into _flows list
      final serverFlows = await repo.getAllFlows();
      if (kDebugMode) {
        _calendarDebugPrint(
          '[loadFromDisk] getAllFlows count: ${serverFlows.length}',
        );
      }
      for (final f in serverFlows) {
        final repMeta = _decodeRepeatingNoteMetadata(f.notes);
        final derivedHidden =
            f.isHidden ||
            repMeta.detail != null ||
            repMeta.location != null ||
            repMeta.category != null;
        if (kDebugMode && derivedHidden) {
          final fromDb = f.isHidden;
          final fromRepMeta =
              repMeta.detail != null ||
              repMeta.location != null ||
              repMeta.category != null;
          _calendarDebugPrint(
            '[loadFromDisk] hidden flow id=${f.id} name="${f.name}" fromDb=$fromDb fromRepMeta=$fromRepMeta',
          );
        }
        final flow = _Flow(
          id: f.id,
          calendarId: f.calendarId,
          name: f.name,
          color: Color(rgbToArgb(f.color)),
          active: f.active,
          isSaved: f.isSaved,
          savedAt: f.savedAt,
          rules: _parseRules(f.rules),
          start: f.startDate,
          end: f.endDate,
          notes: f.notes,
          shareId: f.shareId, // NEW: Load share_id
          isHidden: derivedHidden,
          isReminder: f.isReminder,
          reminderUuid: f.reminderUuid,
        );
        newFlows.add(flow);
        // 🔍 DEBUG: Log what color came from database for ALL custom flows
        // Log flows with ID greater than 156 to catch all user-created flows
        if (kDebugMode && f.id > 156) {
          _calendarDebugPrint(
            '[loadFlows] Flow ${f.id} "${f.name}" loaded with color=${f.color} (0x${f.color.toRadixString(16)})',
          );
        }
        if (flow.id >= nextFlowId) nextFlowId = flow.id + 1;
      }

      // Ensure reminder rules are present from loaded reminder flows if they didn't load earlier.
      // (Run after commit to use new flow state.)
      if (kDebugMode) {
        final hiddenCount = newFlows.where((f) => f.isHidden).length;
        final activeCount = newFlows.where((f) => f.active).length;
        final expiredCount = newFlows
            .where(
              (f) =>
                  f.active &&
                  !isFlowScheduleOpenLocally(active: f.active, endDate: f.end),
            )
            .length;
        _calendarDebugPrint(
          '[loadFromDisk] newFlows: total=${newFlows.length} hidden=$hiddenCount active=$activeCount expired=$expiredCount',
        );
      }

      // Reuse the just-loaded flow rows for reminder bootstrapping so startup
      // does not pay for a second full flow fetch before note hydration.
      await _primeReminderRulesFromFlows(newFlows);

      // Build index/maps for later use
      final Map<int, _Flow> flowIndex = {for (final f in newFlows) f.id: f};
      final flowOwnersById = <int, FlowRecordSnapshot>{
        for (final f in newFlows)
          f.id: FlowRecordSnapshot(
            id: f.id,
            active: f.active,
            isHidden: f.isHidden,
            isReminder: f.isReminder,
            isSaved: f.isSaved,
            notes: f.notes,
          ),
      };

      // Materialized history is wider than live schedule hydration: ended
      // non-saved flows keep their past `user_events`, while saved inactive
      // templates and backend deleted rows stay out of the calendar.
      final hydrationFlowIds = newFlows
          .where((f) {
            return shouldHydrateMaterializedUserEvents(flowOwnersById[f.id]!);
          })
          .map((f) => f.id)
          .toSet(); // 👈 Set for O(1) contains() lookups
      if (kDebugMode) {
        _calendarDebugPrint(
          '[loadFromDisk] hydrationFlowIds count: ${hydrationFlowIds.length}',
        );
        if (hydrationFlowIds.isNotEmpty) {
          for (final fid in hydrationFlowIds) {
            final flow = flowIndex[fid];
            if (flow == null) continue;
            final rn = _decodeRepeatingNoteMetadata(flow.notes);
            final looksLikeRepeatingNote =
                rn.detail != null || rn.location != null || rn.category != null;
            _calendarDebugPrint(
              '[loadFromDisk] flow id=$fid name="${flow.name}" '
              'isReminder=${flow.isReminder} hidden=${flow.isHidden} '
              'notesLikeRepeatingNote=$looksLikeRepeatingNote',
            );
          }
        }
      }

      ({DateTime startUtc, DateTime endUtc})? flowWindow;
      if (hydrationFlowIds.isNotEmpty) {
        flowWindow = _computeFlowHydrationWindow(hydrationFlowIds, flowIndex);
        if (focusWindow != null) {
          flowWindow = _clampHydrationWindowToFocus(flowWindow, focusWindow);
        }
        if (kDebugMode) {
          _calendarDebugPrint(
            '[loadFromDisk] flow hydration window '
            '${flowWindow.startUtc.toIso8601String()} → ${flowWindow.endUtc.toIso8601String()}',
          );
        }
      }

      Future<Map<int, List<FlowEventRow>>> loadFlowEvents() async {
        final eventsByFlowId = <int, List<FlowEventRow>>{};
        if (hydrationFlowIds.isEmpty) {
          return eventsByFlowId;
        }

        try {
          final batchedEvents = await repo.getEventsForFlowIds(
            hydrationFlowIds,
            startUtc: flowWindow?.startUtc,
            endUtc: flowWindow?.endUtc,
          );
          for (final evt in batchedEvents) {
            final fid = evt.flowLocalId;
            if (fid == null || !hydrationFlowIds.contains(fid)) continue;
            eventsByFlowId.putIfAbsent(fid, () => <FlowEventRow>[]).add(evt);
          }
          if (kDebugMode) {
            _calendarDebugPrint(
              '[loadFromDisk] getEventsForFlowIds count=${batchedEvents.length} flows=${eventsByFlowId.length}',
            );
          }
        } catch (err, st) {
          if (kDebugMode) {
            _calendarDebugPrint(
              '[loadFromDisk] batched flow event fetch failed: $err',
            );
            _calendarDebugPrint('$st');
          }
        }

        if (eventsByFlowId.isNotEmpty) {
          if (kDebugMode) {
            eventsByFlowId.forEach((fid, events) {
              _calendarDebugPrint(
                '[loadFromDisk] flow $fid events (batched) count: ${events.length}',
              );
            });
          }
          return eventsByFlowId;
        }

        for (final flowId in hydrationFlowIds) {
          try {
            final flowEvents = await repo.getEventsForFlow(
              flowId,
              startUtc: flowWindow?.startUtc,
              endUtc: flowWindow?.endUtc,
              flowEventsOnly: true,
            );
            eventsByFlowId[flowId] = flowEvents;
            if (kDebugMode) {
              _calendarDebugPrint(
                '[loadFromDisk] getEventsForFlow($flowId) count: ${flowEvents.length} (fallback)',
              );
            }
          } catch (err, st) {
            if (kDebugMode) {
              _calendarDebugPrint(
                '[loadFromDisk] failed to hydrate events for flow $flowId: $err',
              );
              _calendarDebugPrint('$st');
            }
          }
        }

        return eventsByFlowId;
      }

      var standaloneWindow = _computeStandaloneHydrationWindow(newFlows);
      if (focusWindow != null) {
        standaloneWindow = _clampHydrationWindowToFocus(
          standaloneWindow,
          focusWindow,
        );
      }
      final flowEventsFuture = loadFlowEvents();
      final standaloneFuture = repo.getStandaloneEventsForDateRangeAll(
        startUtc: standaloneWindow.startUtc,
        endUtc: standaloneWindow.endUtc,
        pageSize: 1000,
        flowOwnersById: flowOwnersById,
      );
      final flowEventCountsFuture = _flowsRepo.loadMyFlowEventCounts(
        flowIds: newFlows.map((flow) => flow.id),
      );
      final eventsByFlowId = await flowEventsFuture;

      int flowAddedCount = 0;

      for (final flowId in hydrationFlowIds) {
        try {
          final flowEvents = eventsByFlowId[flowId] ?? const <FlowEventRow>[];
          final owningFlow = flowIndex[flowId];
          final isTrackSkyFlow = _isTrackSkyFlowName(owningFlow?.name);

          for (final evt in flowEvents) {
            // Convert DB UTC timestamps -> device local -> Kemetic date
            var localStart = evt.startsAtUtc.toLocal();
            var localEnd = evt.endsAtUtc?.toLocal();
            var allDay = evt.allDay;

            if (isTrackSkyFlow) {
              final normalized = normalizeTrackSkyLocalWindow(
                title: evt.title,
                category: evt.category,
                startLocal: localStart,
                endLocal: localEnd,
                allDay: allDay,
              );
              localStart = normalized.startLocal;
              localEnd = normalized.endLocal;
              allDay = normalized.allDay;
            }

            final kDate = KemeticMath.fromGregorian(localStart);

            // Build _Note, same shape the rest of the app expects
            // 👈 SAFETY NET: Skip events for flows that don't exist or are inactive.
            final ownerSnapshot = flowOwnersById[flowId];
            final flowEligible =
                owningFlow != null &&
                ownerSnapshot != null &&
                shouldHydrateMaterializedUserEvents(ownerSnapshot);
            if (!flowEligible) {
              // Skip backend deleted rows and saved inactive templates.
              continue;
            }

            final startTime = allDay
                ? null
                : TimeOfDay.fromDateTime(localStart);
            final endTime = localEnd == null
                ? null
                : TimeOfDay.fromDateTime(localEnd);
            if ((evt.category ?? '') == 'tombstone') {
              continue;
            }

            final meta = _decodeDetailMetadata(evt.detail);
            final storedCleanDetail = _cleanDetail(meta.detail);
            final canonicalDawnDetail =
                _canonicalDawnHouseRiteDetailForLoadedEvent(
                  flow: owningFlow,
                  event: evt,
                );
            final canonicalTheWeighingDetail =
                _canonicalTheWeighingDetailForLoadedEvent(
                  flow: owningFlow,
                  event: evt,
                );
            final canonicalOfferingTableDetail =
                _canonicalOfferingTableDetailForLoadedEvent(
                  flow: owningFlow,
                  event: evt,
                );
            final canonicalTheTendingDetail =
                _canonicalTheTendingDetailForLoadedEvent(
                  flow: owningFlow,
                  event: evt,
                );
            final canonicalKeptWordDetail =
                _canonicalKeptWordDetailForLoadedEvent(
                  flow: owningFlow,
                  event: evt,
                );
            final canonicalCourseDetail = _canonicalCourseDetailForLoadedEvent(
              flow: owningFlow,
              event: evt,
              localStart: localStart,
            );
            final canonicalWagDetail = _canonicalWagDetailForLoadedEvent(
              flow: owningFlow,
              event: evt,
            );
            final canonicalOpenHandDetail =
                _canonicalOpenHandDetailForLoadedEvent(
                  flow: owningFlow,
                  event: evt,
                );
            final canonicalDjedDetail = _canonicalDjedDetailForLoadedEvent(
              flow: owningFlow,
              event: evt,
            );
            final canonicalDetail =
                canonicalDawnDetail ??
                canonicalTheWeighingDetail ??
                canonicalOfferingTableDetail ??
                canonicalTheTendingDetail ??
                canonicalKeptWordDetail ??
                canonicalCourseDetail ??
                canonicalWagDetail ??
                canonicalOpenHandDetail ??
                canonicalDjedDetail;
            final cleanedDetail = canonicalDetail ?? storedCleanDetail;
            if (canonicalDetail != null &&
                canonicalDetail != storedCleanDetail) {
              _repairDawnHouseRiteLoadedDetail(
                repo: repo,
                event: evt,
                canonicalDetail: canonicalDetail,
                color: meta.color,
                alertMinutes: meta.alertMinutes,
              );
            }

            if (_isTombstoned(evt.clientEventId)) {
              continue;
            }
            if (_isPendingDelete(
              id: evt.id,
              clientEventId: evt.clientEventId,
              kYear: kDate.kYear,
              kMonth: kDate.kMonth,
              kDay: kDate.kDay,
              title: evt.title,
              allDay: allDay,
              start: startTime,
              end: endTime,
              flowId: flowId,
            )) {
              continue;
            }

            final note = _Note(
              id: evt.id,
              clientEventId: evt.clientEventId,
              calendarId: evt.calendarId,
              calendarName: evt.calendarName,
              title: _cleanTitle(evt.title),
              detail: cleanedDetail, // Clean the flowLocalId prefix
              location: evt.location,
              allDay: allDay,
              start: startTime,
              end: endTime,
              flowId: flowId,
              category: evt.category,
              isReminder: owningFlow.isReminder,
              reminderId: owningFlow.isReminder
                  ? owningFlow.reminderUuid
                  : null,
              manualColor: meta.color,
              alertOffsetMinutes: meta.alertMinutes,
              actionId: evt.actionId,
              behaviorPayload: evt.behaviorPayload,
            );

            final key = _kKey(kDate.kYear, kDate.kMonth, kDate.kDay);
            final bucket = newNotes.putIfAbsent(key, () => <_Note>[]);

            final noteStartMinute = note.allDay
                ? null
                : note.start == null
                ? null
                : note.start!.hour * 60 + note.start!.minute;
            final noteEndMinute = note.allDay
                ? null
                : note.end == null
                ? null
                : note.end!.hour * 60 + note.end!.minute;
            final incomingDedupeKey = buildMaterializedFlowEventDedupeKey(
              flowId: flowId,
              allDay: note.allDay,
              eventId: evt.id,
              clientEventId: note.clientEventId,
              title: note.title,
              startMinute: noteStartMinute,
              endMinute: noteEndMinute,
            );
            final already = bucket.any((existing) {
              if ((existing.flowId ?? -1) != flowId) return false;
              final existingStartMinute = existing.allDay
                  ? null
                  : existing.start == null
                  ? null
                  : existing.start!.hour * 60 + existing.start!.minute;
              final existingEndMinute = existing.allDay
                  ? null
                  : existing.end == null
                  ? null
                  : existing.end!.hour * 60 + existing.end!.minute;
              final existingDedupeKey = buildMaterializedFlowEventDedupeKey(
                flowId: flowId,
                allDay: existing.allDay,
                eventId: existing.id,
                clientEventId: existing.clientEventId,
                title: existing.title,
                startMinute: existingStartMinute,
                endMinute: existingEndMinute,
              );
              return existingDedupeKey == incomingDedupeKey;
            });

            if (!already) {
              bucket.add(note);
              flowAddedCount++;
            }
          }
        } catch (err, st) {
          if (kDebugMode) {
            _calendarDebugPrint(
              '[loadFromDisk] failed to hydrate events for flow $flowId: $err',
            );
            _calendarDebugPrint('$st');
          }
        }
      }

      if (kDebugMode) {
        _calendarDebugPrint(
          '[loadFromDisk] flow notes added to newNotes: $flowAddedCount',
        );
      }

      // Load filing-backed standalone calendar events: notes, reminders, and
      // nutrition rows. Flow rows stay in the flow hydration path above.
      try {
        final standaloneResult = await standaloneFuture;
        final standaloneEvents = standaloneResult.events;
        final ghostStandaloneIds = standaloneResult.ghostEventIds;

        if (ghostStandaloneIds.isNotEmpty) {
          unawaited(() async {
            try {
              await repo.deleteByIds(
                ghostStandaloneIds,
                semantic: 'calendar_hydration_ghost_cleanup',
                suppressesClient: false,
                sourceFeature: 'CalendarPage._loadFromDisk',
                deleteScope: 'standalone_ghost_cleanup',
              );
            } catch (e, st) {
              if (kDebugMode) {
                _calendarDebugPrint(
                  '[_loadFromDisk] standalone ghost cleanup failed: $e',
                );
                _calendarDebugPrint('$st');
              }
            }
          }());
        }

        int standaloneAddedCount = 0;

        for (final evt in standaloneEvents) {
          try {
            final cid = evt.clientEventId ?? '';
            final rawDetail = evt.detail ?? '';
            final flowDecision = classifyFlowEvent(
              event: FlowEventSnapshot(
                flowLocalId: evt.flowLocalId,
                clientEventId: evt.clientEventId,
                detail: evt.detail,
                category: evt.category,
              ),
              flowOwnersById: flowOwnersById,
            );

            final isReminderBackboneEvent =
                cid.startsWith('reminder:') || cid.startsWith('nutrition:');

            // Filing-backed reminder rows may carry their canonical reminder
            // flow id for color/identity. Keep them in the standalone calendar
            // lane while still rejecting non-reminder flow ghosts.
            if (!flowDecision.isStandaloneVisible && !isReminderBackboneEvent) {
              continue;
            }

            // 🚫 HARD GUARD 4b: Reminder instances whose rule no longer exists (or was ended/deleted).
            if (cid.startsWith('reminder:')) {
              final rid = _reminderRuleIdFromCid(cid);
              final exists =
                  rid != null && _reminderRules.any((r) => r.id == rid);
              final ended = rid != null && _endedReminderIds.contains(rid);
              if (!exists || ended) {
                continue;
              }
            }

            // ✅ Nutrition: treat as reminder if a matching rule exists
            bool isReminderEvent = cid.startsWith('reminder:');
            String? reminderRuleId = _reminderRuleIdFromCid(cid);
            if (cid.startsWith('nutrition:')) {
              final parts = cid.split(':');
              if (parts.length >= 3) {
                final itemId = parts.sublist(1, parts.length - 1).join(':');
                final rid = 'nutrition:$itemId';
                final exists =
                    _reminderRules.any((r) => r.id == rid) &&
                    !_endedReminderIds.contains(rid);
                if (exists) {
                  isReminderEvent = true;
                  reminderRuleId = rid;
                }
              }
            }

            final positiveFiledFlowId =
                evt.flowLocalId != null && evt.flowLocalId! > 0
                ? evt.flowLocalId
                : null;
            final noteFlowId = isReminderEvent ? positiveFiledFlowId ?? -1 : -1;
            final reminderFlow = isReminderEvent && positiveFiledFlowId != null
                ? flowIndex[positiveFiledFlowId]
                : null;
            final reminderFlowColor = reminderFlow == null
                ? null
                : _displayFlowColor(reminderFlow.name, reminderFlow.color);

            // ✅ If it passed all guards → this is a true standalone note
            final localStart = evt.startsAtUtc.toLocal();
            final kDate = KemeticMath.fromGregorian(localStart);
            final decoded = _decodeDetailMetadata(rawDetail);
            final cleanedDetail = _cleanDetail(decoded.detail);

            final startTime = evt.allDay
                ? null
                : TimeOfDay.fromDateTime(localStart);
            final endTime = evt.endsAtUtc == null
                ? null
                : TimeOfDay.fromDateTime(evt.endsAtUtc!.toLocal());
            if ((evt.category ?? '') == 'tombstone') {
              continue;
            }

            if (_isTombstoned(evt.clientEventId)) {
              continue;
            }
            if (_isPendingDelete(
              id: evt.id,
              clientEventId: evt.clientEventId,
              kYear: kDate.kYear,
              kMonth: kDate.kMonth,
              kDay: kDate.kDay,
              title: evt.title,
              allDay: evt.allDay,
              start: startTime,
              end: endTime,
              flowId: noteFlowId,
            )) {
              continue;
            }

            final note = _Note(
              id: evt.id,
              clientEventId: evt.clientEventId,
              calendarId: evt.calendarId,
              calendarName: evt.calendarName,
              title: _cleanTitle(evt.title),
              detail: cleanedDetail,
              location: evt.location,
              allDay: evt.allDay,
              start: startTime,
              end: endTime,
              flowId: noteFlowId,
              manualColor:
                  decoded.color ??
                  reminderFlowColor ??
                  (evt.calendarIsPersonal
                      ? null
                      : (evt.calendarColor != null
                            ? Color(evt.calendarColor!)
                            : null)),
              category: evt.category,
              isReminder: isReminderEvent,
              reminderId: reminderRuleId,
              alertOffsetMinutes: decoded.alertMinutes,
            );

            final key = _kKey(kDate.kYear, kDate.kMonth, kDate.kDay);
            final bucket = newNotes.putIfAbsent(key, () => <_Note>[]);

            bool skip = false;
            int? replaceIndex;
            final incomingKey = _standaloneDedupeKey(note);
            final incomingPriority = _standalonePriority(note.clientEventId);

            for (int i = 0; i < bucket.length; i++) {
              final existing = bucket[i];
              if ((existing.flowId ?? -1) != -1 &&
                  !existing.isReminder &&
                  !note.isReminder) {
                continue; // skip flow-driven non-reminder rows
              }

              if (existing.clientEventId != null &&
                  note.clientEventId != null &&
                  existing.clientEventId == note.clientEventId) {
                skip = true;
                break;
              }

              if (existing.isReminder || note.isReminder) {
                if (existing.isReminder &&
                    note.isReminder &&
                    existing.reminderId == note.reminderId &&
                    existing.start?.hour == note.start?.hour &&
                    existing.start?.minute == note.start?.minute) {
                  skip = true;
                  break;
                }
                continue;
              }

              final existingKey = _standaloneDedupeKey(existing);
              if (existingKey == incomingKey) {
                final existingPriority = _standalonePriority(
                  existing.clientEventId,
                );
                if (incomingPriority > existingPriority) {
                  replaceIndex = i;
                } else {
                  skip = true;
                }
                break;
              }
            }

            if (skip) {
              continue;
            }

            if (replaceIndex != null) {
              bucket[replaceIndex] = note;
            } else {
              bucket.add(note);
              standaloneAddedCount++; // ✅ important: track how many actually added
            }
          } catch (rowErr) {
            _calendarDebugPrint(
              '[_loadFromDisk] ⚠️ standalone row skipped: $rowErr (id=${evt.id} cid=${evt.clientEventId})',
            );
            continue;
          }
        }

        if (kDebugMode) {
          _calendarDebugPrint(
            '[_loadFromDisk] loaded $standaloneAddedCount standalone events after filtering '
            '(${standaloneWindow.startUtc.toIso8601String()} → ${standaloneWindow.endUtc.toIso8601String()})',
          );
        }
      } catch (err, st) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[loadFromDisk] failed to load standalone events: $err',
          );
          _calendarDebugPrint('$st');
        }
      }

      final hydratedTrackSkyFlowIds = newFlows
          .where((flow) => _isTrackSkyFlowName(flow.name))
          .map((flow) => flow.id)
          .where((flowId) => flowId > 0)
          .toSet();
      final dedupedNotes = <String, List<_Note>>{};
      newNotes.forEach((key, notes) {
        final cleaned = _dedupeVisibleDayNotes(
          notes,
          trackSkyFlowIds: hydratedTrackSkyFlowIds,
        );
        if (cleaned.isNotEmpty) {
          dedupedNotes[key] = cleaned;
        }
      });

      // Force rebuild as soon as visible event data is ready. Flow counts and
      // reminder regeneration are secondary and can land afterward.
      _flows
        ..clear()
        ..addAll(newFlows);
      _notes
        ..clear()
        ..addAll(dedupedNotes);
      _nextFlowId = nextFlowId;

      if (kDebugMode) {
        _calendarDebugPrint(
          '[loadFromDisk] committed _flows.length=${_flows.length} _notes keys=${_notes.length}',
        );
      }

      _rebuildReminderRulesFromFlowsIfMissing();
      _bumpDataVersion();
      _lastSuccessfulHydrationAt = DateTime.now();
      _warmStartCacheRestoredForUserId = _activeWarmStartUserId();
      _warmStartSnapshotVisible = false;
      if (preserveViewport && preservedScrollOffset != null) {
        _lastKnownCalendarScrollOffset = preservedScrollOffset;
        WidgetsBinding.instance.addPostFrameCallback((_) {
          if (!mounted ||
              !_scrollCtrl.hasClients ||
              !_scrollCtrl.position.hasContentDimensions) {
            return;
          }
          final position = _scrollCtrl.position;
          final clamped = preservedScrollOffset.clamp(
            position.minScrollExtent,
            position.maxScrollExtent,
          );
          _scrollCtrl.jumpTo(clamped);
          _lastKnownCalendarScrollOffset = clamped.toDouble();
        });
      }

      Future<void> finishNonCriticalPostProcessing() async {
        try {
          final flowEventCounts = await flowEventCountsFuture;
          if (mounted) {
            setState(() {
              _flowTotalEventCounts
                ..clear()
                ..addAll(flowEventCounts.total);
              _flowRemainingEventCounts
                ..clear()
                ..addAll(flowEventCounts.remaining);
            });
          } else {
            _flowTotalEventCounts
              ..clear()
              ..addAll(flowEventCounts.total);
            _flowRemainingEventCounts
              ..clear()
              ..addAll(flowEventCounts.remaining);
          }
          _scheduleWarmStartCacheSave();
        } catch (err, st) {
          if (kDebugMode) {
            _calendarDebugPrint(
              '[loadFromDisk] failed to load flow activity counts: $err',
            );
            _calendarDebugPrint('$st');
          }
        }

        try {
          if (keepWarmStartSnapshotVisible) {
            if (kDebugMode) {
              _calendarDebugPrint(
                '[loadFromDisk] skipped reminder regen after warm-start backfill',
              );
            }
          } else {
            final changed = await _regenReminderNotes(notify: false);
            if (changed) {
              _refreshNoteCacheUi();
            }
          }
        } catch (err, st) {
          if (kDebugMode) {
            _calendarDebugPrint('[loadFromDisk] reminder regen failed: $err');
            _calendarDebugPrint('$st');
          }
        }
      }

      if (fastStartupMode) {
        unawaited(finishNonCriticalPostProcessing());
      } else {
        await finishNonCriticalPostProcessing();
      }
    } catch (e, stackTrace) {
      if (kDebugMode) {
        _calendarDebugPrint('Supabase sync FAILED: $e');
        _calendarDebugPrint('Stack: $stackTrace');
      }
    } finally {
      _isLoadingFromDisk = false;
    }

    if (kDebugMode) {
      _calendarDebugPrint('=== _loadFromDisk END ($source) ===');
      if (source.startsWith('shared_calendar_event_tap')) {
        _calendarDebugPrint(
          '[SharedCalendarEventTap] hydration complete source=$source',
        );
      }
    }
  }

  /// Allows other screens (e.g., Settings) to trigger a fresh sync of flows/notes.
  Future<void> reloadFromOutside() =>
      _refreshAfterReturn(reason: 'external_request', force: true);

  static Map<String, dynamic> ruleToJson(FlowRule r) {
    if (r is _RuleWeek) {
      return {
        'type': 'week',
        'weekdays': r.weekdays.toList(),
        'allDay': r.allDay,
        if (r.start != null) 'startHour': r.start!.hour,
        if (r.start != null) 'startMinute': r.start!.minute,
        if (r.end != null) 'endHour': r.end!.hour,
        if (r.end != null) 'endMinute': r.end!.minute,
      };
    }
    if (r is _RuleDecan) {
      return {
        'type': 'decan',
        'months': r.months.toList(),
        'decans': r.decans.toList(),
        'daysInDecan': r.daysInDecan.toList(),
        'allDay': r.allDay,
        if (r.start != null) 'startHour': r.start!.hour,
        if (r.start != null) 'startMinute': r.start!.minute,
        if (r.end != null) 'endHour': r.end!.hour,
        if (r.end != null) 'endMinute': r.end!.minute,
      };
    }
    if (r is _RuleDates) {
      return {
        'type': 'dates',
        'dates': r.dates.map((d) => d.millisecondsSinceEpoch).toList(),
        'allDay': r.allDay,
        if (r.start != null) 'startHour': r.start!.hour,
        if (r.start != null) 'startMinute': r.start!.minute,
        if (r.end != null) 'endHour': r.end!.hour,
        if (r.end != null) 'endMinute': r.end!.minute,
      };
    }
    throw ArgumentError('Unknown rule type');
  }

  List<FlowRule> _parseRules(String rulesJson) {
    if (rulesJson.isEmpty) return [];
    try {
      final parsed = jsonDecode(rulesJson) as List;
      return parsed
          .map((j) => CalendarPage.ruleFromJson(j as Map<String, dynamic>))
          .toList();
    } catch (_) {
      return [];
    }
  }

  List<FlowRule> _parseFlowRowRules(List<dynamic> rules) {
    if (rules.isEmpty) return const [];
    final parsed = <FlowRule>[];
    for (final raw in rules) {
      if (raw is! Map) continue;
      try {
        parsed.add(CalendarPage.ruleFromJson(Map<String, dynamic>.from(raw)));
      } catch (_) {
        // Skip malformed rows from older records without dropping the flow.
      }
    }
    return parsed;
  }

  _Flow _flowFromFiledRow(FlowRow row) {
    return _Flow(
      id: row.id,
      calendarId: row.calendarId,
      name: row.name,
      color: Color(rgbToArgb(row.color)),
      active: row.active,
      isSaved: row.isSaved,
      savedAt: row.savedAt,
      rules: _parseFlowRowRules(row.rules),
      start: row.startDate?.toLocal(),
      end: row.endDate?.toLocal(),
      notes: row.notes,
      shareId: row.shareId,
      isHidden: row.isHidden,
      isReminder: row.isReminder,
      reminderUuid: row.reminderUuid,
    );
  }

  _MyFlowsFilingSnapshot _myFlowsFilingSnapshotFromRows(List<FlowRow> rows) {
    final flows = <_Flow>[];
    final activeIds = <int>{};
    final savedIds = <int>{};
    final totalCounts = <int, int>{};
    final remainingCounts = <int, int>{};

    for (final row in rows) {
      flows.add(_flowFromFiledRow(row));
      if (row.visibleInActiveList) activeIds.add(row.id);
      if (row.visibleInSavedList) savedIds.add(row.id);
      totalCounts[row.id] = row.totalEventCount;
      remainingCounts[row.id] = row.remainingLiveEventCount;
    }

    if (kDebugMode) {
      _calendarDebugPrint(
        '[MyFlowsFiling] rows=${rows.length} active=${activeIds.length} saved=${savedIds.length}',
      );
    }

    return _MyFlowsFilingSnapshot(
      flows: List<_Flow>.unmodifiable(flows),
      activeFlowIds: Set<int>.unmodifiable(activeIds),
      savedFlowIds: Set<int>.unmodifiable(savedIds),
      totalEventCounts: Map<int, int>.unmodifiable(totalCounts),
      remainingEventCounts: Map<int, int>.unmodifiable(remainingCounts),
    );
  }

  _MyFlowsFilingSnapshot? _cachedMyFlowsFilingSnapshot() {
    final cached = _myFlowsFilingSnapshotCache;
    if (cached != null) return cached;
    final cachedRows = _flowsRepo.cachedMyFiledFlowsSync();
    if (cachedRows == null) return null;
    final snapshot = _myFlowsFilingSnapshotFromRows(cachedRows);
    _myFlowsFilingSnapshotCache = snapshot;
    return snapshot;
  }

  Future<void> _restoreMyFlowsFilingSnapshotCache({
    String reason = 'restore',
  }) async {
    if (_myFlowsFilingSnapshotCache != null) return;
    final rows = await _flowsRepo.restoreCachedFiledFlows();
    if (rows == null || !mounted) return;
    _myFlowsFilingSnapshotCache = _myFlowsFilingSnapshotFromRows(rows);
    if (kDebugMode) {
      _calendarDebugPrint(
        '[MyFlowsFiling] restored cache reason=$reason rows=${rows.length}',
      );
    }
  }

  Future<_MyFlowsFilingSnapshot> _loadMyFlowsFilingSnapshot() async {
    final rows = await _flowsRepo.refreshMyFiledFlows();
    final snapshot = _myFlowsFilingSnapshotFromRows(rows);
    _myFlowsFilingSnapshotCache = snapshot;
    return snapshot;
  }

  void _primeMyFlowsFilingSnapshotCache({String reason = 'prime'}) {
    unawaited(() async {
      try {
        await _restoreMyFlowsFilingSnapshotCache(reason: reason);
        await _loadMyFlowsFilingSnapshot();
      } catch (e, st) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[MyFlowsFiling] prime failed reason=$reason error=$e',
          );
          _calendarDebugPrint('$st');
        }
      }
    }());
  }

  Future<int?> _findFlowIdByReminderUuid(String reminderUuid) async {
    final dbUuid = _dbReminderUuidFromRuleId(reminderUuid);
    if (dbUuid == null) return null;
    try {
      final repo = FlowsRepo(Supabase.instance.client);
      return await repo.getFlowIdByReminderUuid(dbUuid);
    } catch (_) {
      return null;
    }
  }

  bool _rulesEqual(List<dynamic> oldRulesJson, List<FlowRule> newRules) {
    if (oldRulesJson.length != newRules.length) return false;
    List<Map<String, dynamic>> normalize(List<Map<String, dynamic>> list) {
      list.sort(
        (a, b) =>
            (a['type'] as String? ?? '').compareTo(b['type'] as String? ?? ''),
      );
      return list;
    }

    final oldNormalized = normalize(
      oldRulesJson.map((r) => Map<String, dynamic>.from(r as Map)).toList(),
    );
    final newNormalized = normalize(
      newRules
          .map(ruleToJson)
          .map((r) => Map<String, dynamic>.from(r))
          .toList(),
    );
    return jsonEncode(oldNormalized) == jsonEncode(newNormalized);
  }

  bool _isColorOnlyChange(FlowRow oldFlow, _Flow newFlow) {
    if (oldFlow.name != newFlow.name) return false;
    if (oldFlow.notes != newFlow.notes) return false;
    if (oldFlow.startDate != newFlow.start) return false;
    if (oldFlow.endDate != newFlow.end) return false;
    if (!_rulesEqual(oldFlow.rules, newFlow.rules)) return false;
    return oldFlow.color != newFlow.color.toARGB32();
  }

  Future<NotificationScheduleResult?> _scheduleAlertForEvent({
    required _Note note,
    required int ky,
    required int km,
    required int kd,
    required String clientEventId,
    String? eventId,
  }) async {
    if (note.alertOffsetMinutes == _alertNoneMinutes) {
      try {
        await Notify.cancelNotificationForEvent(clientEventId);
      } catch (_) {
        // Ignore cancellation failures; nothing else to do.
      }
      return null;
    }

    final alertAtLocal = _alertDateTimeLocal(
      note: note,
      kYear: ky,
      kMonth: km,
      kDay: kd,
    );
    final effectiveMinutes = _effectiveAlertMinutes(note.alertOffsetMinutes);
    if (alertAtLocal == null || effectiveMinutes == null) return null;

    final cleanedDetail = _cleanDetail(note.detail);
    final bodyLines = <String>[
      if ((note.location ?? '').trim().isNotEmpty) note.location!.trim(),
      if (cleanedDetail.isNotEmpty) cleanedDetail,
    ];
    final body = bodyLines.isEmpty ? null : bodyLines.join('\n');
    final itemType = note.isReminder
        ? calendarPushItemTypeReminder
        : ((note.flowId != null && note.flowId! > 0)
              ? calendarPushItemTypeFlowEvent
              : calendarPushItemTypeNote);

    final result = await Notify.scheduleAlertWithPersistenceResult(
      clientEventId: clientEventId,
      scheduledAt: alertAtLocal,
      title: note.title,
      body: body,
      payload: CalendarPage._calendarNotificationPayloadJson(
        itemType: itemType,
        kYear: ky,
        kMonth: km,
        kDay: kd,
        eventId: eventId ?? note.id,
        clientEventId: clientEventId,
        reminderId: note.reminderId,
        flowId: note.flowId,
      ),
    );

    final reminderId = _reminderIdForNote(note, alertAtLocal.toUtc());
    await _reminderService.addOrUpdate(
      Reminder(
        id: reminderId,
        eventId: eventId,
        title: note.title,
        detail: cleanedDetail.isEmpty ? null : cleanedDetail,
        alertAtUtc: alertAtLocal.toUtc(),
        flowId: note.flowId?.toString(),
        createdAt: DateTime.now().toUtc(),
        updatedAt: DateTime.now().toUtc(),
      ),
    );
    return result;
  }

  void _showNotificationScheduleWarning(String? message) {
    final text = message?.trim();
    if (!mounted || text == null || text.isEmpty) return;
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(content: Text(text), backgroundColor: Colors.orange.shade800),
    );
  }

  // Persist flows + planned notes coming back from Flow Studio
  // AFTER
  Future<int?> _persistFlowStudioResult(_FlowStudioResult r) async {
    final repo = UserEventsRepo(Supabase.instance.client);
    final isNewFlowSave = r.savedFlow != null && r.savedFlow!.id <= 0;

    // 1) Deletes take precedence
    final deleteId = r.deleteFlowId;
    if (deleteId != null) {
      if (kDebugMode) {
        _calendarDebugPrint('[persistFlowStudio] Deleting flowId=$deleteId');
      }
      // 🔧 KEY FIX: Delete ALL notes for this flow (not just future ones)
      try {
        await repo.deleteByFlowId(deleteId);
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudio] ✓ Deleted ALL notes for flow',
          );
        }
      } catch (e) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudio] ⚠️ Failed to delete notes: $e',
          );
        }
        rethrow; // bubble up so we don't silently keep the flow
      }
      try {
        await repo.deleteFlow(deleteId);
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudio] ✓ Deleted flow from database',
          );
        }
      } catch (e) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudio] ⚠️ Failed to delete flow: $e',
          );
        }
        rethrow; // bubble up and avoid thinking it was removed
      }
      // Remove the flow from memory
      _flows.removeWhere((f) => f.id == deleteId);
      setState(() {});
      _notifyDayViewDataChanged();
      if (kDebugMode) {
        _calendarDebugPrint('[persistFlowStudio] ✓ Flow deletion complete');
      }
      return deleteId;
    }

    // 2) Save/create flow if provided
    _Flow? saved;
    FlowRow? oldFlowRow;
    if (r.savedFlow != null) {
      // Capture previous state for change detection (best-effort)
      if (r.savedFlow!.id > 0) {
        try {
          oldFlowRow = await _flowsRepo.getFlowById(r.savedFlow!.id);
        } catch (_) {
          oldFlowRow = null;
        }
      }

      // ✅ For imported flows (with plannedNotes), clear rules to prevent rule-based rescheduling
      // The rules are already cleared in _save() when widget.importData != null,
      // but we also check here as a safety measure
      final bool hasSnapshotEvents = r.plannedNotes.isNotEmpty;
      final bool isAiLocal = r.savedFlow?.shareId == 'ai-local';
      final rulesJson = (hasSnapshotEvents && !isAiLocal)
          ? jsonEncode([])
          : jsonEncode(r.savedFlow!.rules.map(ruleToJson).toList());

      final savedId = await repo.upsertFlow(
        id: r.savedFlow!.id > 0 ? r.savedFlow!.id : null,
        name: r.savedFlow!.name,
        color: r.savedFlow!.color.toARGB32(),
        active: r.savedFlow!.active,
        calendarId: r.savedFlow!.calendarId,
        startDate: r.savedFlow!.start,
        endDate: r.savedFlow!.end,
        notes: r.savedFlow!.notes,
        rules: rulesJson,
        isHidden: r.savedFlow!.isHidden,
        originType: r.originType,
        originFlowId: r.originFlowId,
        originShareId: r.originShareId ?? r.savedFlow!.shareId,
        originGenerationId: r.originGenerationId,
        rootFlowId: r.rootFlowId,
        aiMetadata: r.aiMetadata,
      );

      saved = _Flow(
        id: savedId,
        calendarId: r.savedFlow!.calendarId,
        name: r.savedFlow!.name,
        color: r.savedFlow!.color,
        active: r.savedFlow!.active,
        isSaved: r.savedFlow!.isSaved,
        savedAt: r.savedFlow!.savedAt,
        rules: r.savedFlow!.rules,
        start: r.savedFlow!.start,
        end: r.savedFlow!.end,
        notes: r.savedFlow!.notes,
        shareId: r.savedFlow!.shareId,
        isHidden: r.savedFlow!.isHidden, // Preserve hidden status
      );

      if (r.originGenerationId != null) {
        try {
          await repo.flowCommit(
            generationId: r.originGenerationId!,
            flowId: savedId,
          );
        } catch (e) {
          if (kDebugMode) {
            _calendarDebugPrint(
              '[persistFlowStudio] flow_commit failed for generation ${r.originGenerationId}: $e',
            );
          }
        }
      }

      final idx = _flows.indexWhere((f) => f.id == savedId);
      if (idx >= 0) {
        _flows[idx] = saved;
      } else {
        _flows.add(saved);
        if (savedId >= _nextFlowId) _nextFlowId = savedId + 1;
      }

      // Add verification logging
      if (kDebugMode) {
        _calendarDebugPrint(
          '[persistFlowStudio] Saved flow $savedId "${saved.name}" with color=${saved.color.toARGB32().toRadixString(16)} to database',
        );
      }
    }

    // 3) Apply planned notes locally
    final flowId = saved?.id ?? r.savedFlow?.id ?? -1;
    final flowCalendarId = saved?.calendarId ?? r.savedFlow?.calendarId;
    final flowCalendarName = _calendarSummary(flowCalendarId)?.name;
    final aiGenerated = oldFlowRow?.aiMetadata == null
        ? null
        : oldFlowRow!.aiMetadata?['generated'];
    final isAIFlow = aiGenerated is bool && aiGenerated;
    String? firstClientEventId;
    String? notificationWarning;
    bool flowAdditionNotified = false;

    Future<void> notifyFlowAdditionIfNeeded() async {
      if (flowAdditionNotified || !isNewFlowSave || saved == null) return;
      flowAdditionNotified = true;
      await _notifySharedCalendarItemAdded(
        calendarId: saved.calendarId,
        itemType: 'flow',
        itemId: saved.id.toString(),
        itemTitle: saved.name,
        clientEventId: firstClientEventId,
        flowId: saved.id,
        startDate: saved.start,
        endDate: saved.end,
      );
    }

    if (r.plannedNotes.isNotEmpty) {
      final repo2 = UserEventsRepo(Supabase.instance.client);

      // Concrete planned-note edits replace the occurrence set. The CIDs include
      // event time, so stale rows must be retired before new times are written.
      if (flowId > 0) {
        try {
          await repo2.deleteByFlowId(
            flowId,
            semantic: 'flow_replace',
            suppressesClient: false,
            sourceFeature: 'CalendarPage._persistFlowStudioResult',
            deleteScope: isAIFlow ? 'ai_flow_replace' : 'planned_flow_replace',
          );
          final removedLocal = _removeLocalNotesForFlowReplacement(flowId);
          if (kDebugMode) {
            _calendarDebugPrint(
              '[persistFlowStudio] Cleared existing events for planned-note flow $flowId before replacement (localRemoved=$removedLocal)',
            );
          }
        } catch (e) {
          if (kDebugMode) {
            _calendarDebugPrint(
              '[persistFlowStudio] Failed to clear events for AI flow $flowId: $e',
            );
          }
        }
      }

      for (final p in r.plannedNotes) {
        final n = p.note;
        final noteFlowId = n.flowId ?? flowId;

        // Add to in-memory notes
        _addNote(
          p.ky,
          p.km,
          p.kd,
          n.title,
          n.detail,
          calendarId: flowCalendarId,
          calendarName: flowCalendarName,
          location: n.location,
          allDay: n.allDay,
          start: n.start,
          end: n.end,
          flowId: noteFlowId >= 0 ? noteFlowId : null,
          category: n.category,
          alertOffsetMinutes: n.alertOffsetMinutes,
        );

        // Persist to database
        final cid = EventCidUtil.buildClientEventId(
          ky: p.ky,
          km: p.km,
          kd: p.kd,
          title: n.title,
          startHour: n.start?.hour ?? 9,
          startMinute: n.start?.minute ?? 0,
          allDay: n.allDay,
          flowId: noteFlowId,
        );

        final gDay = KemeticMath.toGregorian(p.ky, p.km, p.kd);
        final startsAt = DateTime(
          gDay.year,
          gDay.month,
          gDay.day,
          n.start?.hour ?? 9,
          n.start?.minute ?? 0,
        );

        DateTime? endsAt;
        if (!n.allDay && n.end != null) {
          endsAt = DateTime(
            gDay.year,
            gDay.month,
            gDay.day,
            n.end!.hour,
            n.end!.minute,
          );
        } else if (!n.allDay) {
          endsAt = startsAt.add(const Duration(hours: 1));
        }

        final trimmedDetail = (n.detail ?? '').trim();
        final baseDetail = trimmedDetail.isEmpty ? null : trimmedDetail;
        final detailWithMeta = _encodeDetailWithMeta(
          baseDetail,
          alertMinutes: n.alertOffsetMinutes,
        );
        final detailToSave = detailWithMeta ?? baseDetail;

        final savedEvent = await repo2.upsertByClientId(
          clientEventId: cid,
          title: n.title,
          startsAtUtc: startsAt.toUtc(),
          detail: detailToSave,
          location: (n.location ?? '').trim().isEmpty ? null : n.location,
          allDay: n.allDay,
          endsAtUtc: endsAt?.toUtc(),
          calendarId: flowCalendarId,
          flowLocalId: noteFlowId >= 0 ? noteFlowId : null,
          category: n.category,
          actionId: n.actionId,
          behaviorPayload: n.behaviorPayload,
          caller: 'persist_flow_studio',
        );
        firstClientEventId ??= savedEvent.clientEventId ?? cid;

        final scheduleResult = await _scheduleAlertForEvent(
          note: n.copyWith(
            calendarId: flowCalendarId,
            calendarName: flowCalendarName,
          ),
          ky: p.ky,
          km: p.km,
          kd: p.kd,
          clientEventId: savedEvent.clientEventId ?? cid,
          eventId: savedEvent.id,
        );
        if (scheduleResult?.needsUserVisibleWarning == true) {
          notificationWarning ??= scheduleResult?.message;
        }
      }
    }

    // Use shared scheduler for flow notes if we have a saved flow
    if (saved != null && saved.active && saved.rules.isNotEmpty) {
      // If we have planned notes, skip rule-based scheduling to preserve titles/times.
      if (r.plannedNotes.isNotEmpty) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudio] ✅ Skipping scheduleFlowNotes - using plannedNotes with individual titles',
          );
        }
        await notifyFlowAdditionIfNeeded();
        setState(() {});
        _notifyDayViewDataChanged();
        _showNotificationScheduleWarning(notificationWarning);
        return saved.id;
      }
      // If rules list was cleared (e.g., snapshot-only imports), skip scheduling.
      if (saved.rules.isEmpty) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudio] ✅ Skipping scheduleFlowNotes - flow has no rules (snapshot-only)',
          );
        }
        setState(() {});
        _notifyDayViewDataChanged();
        return saved.id;
      }
      try {
        // Check if this is an AI-generated flow before scheduling
        // (AI flows already have individually-titled events that shouldn't be regenerated)
        final flowRow = await _flowsRepo.getFlowById(saved.id);

        // Defensive type checking for ai_metadata.generated field
        final aiGenerated = flowRow?.aiMetadata?['generated'];
        final isAIFlow = aiGenerated is bool && aiGenerated == true;

        if (isAIFlow) {
          if (kDebugMode) {
            _calendarDebugPrint(
              '[persistFlowStudio] ✅ Skipping scheduleFlowNotes for AI-generated flow ${saved.id} (preserving individual note titles)',
            );
          }

          // TODO: Add analytics once analytics service is integrated
          // Example: _analyticsService.logEvent('ai_flow_schedule_skipped', {'flowId': saved.id});
        } else {
          // Imported flow with only color change? Skip reschedule.
          if (saved.shareId != null &&
              oldFlowRow != null &&
              _isColorOnlyChange(oldFlowRow, saved)) {
            if (kDebugMode) {
              _calendarDebugPrint(
                '[persistFlowStudio] ⚠️ Skipping reschedule for color-only change on imported flow ${saved.id}',
              );
            }
          } else {
            // Only regenerate notes for manually-created flows with recurring rules
            await scheduleFlowNotes(
              flowId: saved.id,
              rules: saved.rules,
              flowNotes: saved.notes,
              startDate: saved.start,
              endDate: saved.end,
            );

            if (kDebugMode) {
              _calendarDebugPrint(
                '[persistFlowStudio] ✅ Scheduled recurring notes for flow ${saved.id}',
              );
            }
            if (firstClientEventId == null) {
              try {
                final events = await repo.getEventsForFlow(saved.id);
                if (events.isNotEmpty) {
                  firstClientEventId = events.first.clientEventId;
                }
              } catch (_) {}
            }
          }

          // TODO: Add analytics once analytics service is integrated
          // Example: _analyticsService.logEvent('flow_notes_scheduled', {
          //   'flowId': saved.id,
          //   'ruleCount': saved.rules.length,
          //   'dateRange': '${saved.start} to ${saved.end}',
          // });
        }
      } catch (e, stackTrace) {
        // Log error but don't crash - flow is already saved
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudio] ⚠️ Failed to check/schedule flow notes: $e',
          );
          _calendarDebugPrint('Stack trace: $stackTrace');
        }

        // TODO: Add error tracking once analytics service is integrated
        // Example: _analyticsService.logError('flow_schedule_error', e, stackTrace);
      }
    }

    if (saved != null && isNewFlowSave) {
      await notifyFlowAdditionIfNeeded();
    } else if (saved != null) {
      await _notifySharedCalendarMembers(
        calendarId: saved.calendarId,
        title: _calendarDisplayName(saved.calendarId),
        body: 'Flow updated: ${saved.name}',
        clientEventId: firstClientEventId,
        data: <String, dynamic>{'flow_id': saved.id},
      );
    }

    setState(() {});
    _notifyDayViewDataChanged();
    _showNotificationScheduleWarning(notificationWarning);
    return saved?.id;
  }

  /// Schedules all note occurrences for a flow to the calendar
  /// This is the shared logic used by both Flow Studio and Inbox imports
  // Save a single (non-repeating) note only
  Future<({String clientEventId, String eventId})> _saveSingleNoteOnly({
    required int selYear,
    required int selMonth,
    required int selDay,
    required String title,
    String? detail,
    String? location,
    String? calendarId,
    String? calendarName,
    required bool allDay,
    TimeOfDay? startTime,
    TimeOfDay? endTime,
    Color? color,
    String? category,
    int alertMinutesBefore = _alertNoneMinutes,
  }) async {
    // Compute event start + alert time
    final gDay = KemeticMath.toGregorian(selYear, selMonth, selDay);
    final startLocal = allDay
        ? DateTime(gDay.year, gDay.month, gDay.day, 9, 0) // default 9:00 AM
        : DateTime(
            gDay.year,
            gDay.month,
            gDay.day,
            startTime!.hour,
            startTime.minute,
          );
    final note = _Note(
      calendarId: calendarId,
      calendarName: calendarName,
      title: title,
      detail: detail,
      location: location,
      allDay: allDay,
      start: startTime,
      end: endTime,
      flowId: -1,
      manualColor: color,
      category: category,
      alertOffsetMinutes: alertMinutesBefore,
    );

    // Build canonical clientEventId for this manual note
    final String unifiedCid = _buildCid(
      ky: selYear,
      km: selMonth,
      kd: selDay,
      title: title,
      startHour: (allDay || startTime == null) ? null : startTime.hour,
      startMinute: (allDay || startTime == null) ? null : startTime.minute,
      allDay: allDay,
      flowId: -1,
      calendarScopeToken: _calendarScopeToken(calendarId),
    );

    await _ensureManualDeleteTombstonesLoaded();
    await _clearManualTombstone(unifiedCid);

    final encodedDetail = _encodeDetailWithMeta(
      detail,
      color: color,
      alertMinutes: alertMinutesBefore,
    );

    // Sync to Supabase and persist id/clientEventId
    final repo = UserEventsRepo(Supabase.instance.client);
    try {
      final endsAtUtc = (allDay || endTime == null)
          ? null
          : DateTime(
              gDay.year,
              gDay.month,
              gDay.day,
              endTime.hour,
              endTime.minute,
            ).toUtc();

      final updated = await repo.upsertByClientId(
        clientEventId: unifiedCid,
        title: title,
        startsAtUtc: startLocal.toUtc(),
        detail: encodedDetail,
        location: location,
        allDay: allDay,
        endsAtUtc: endsAtUtc,
        category: category,
        calendarId: calendarId,
        caller: 'save_single',
      );

      if (updated.id.isEmpty) {
        throw StateError('Supabase upsert returned empty id for $unifiedCid');
      }

      final savedClientEventId = updated.clientEventId ?? unifiedCid;

      _addNote(
        selYear,
        selMonth,
        selDay,
        title,
        detail,
        id: updated.id,
        clientEventId: savedClientEventId,
        calendarId: calendarId,
        calendarName: calendarName,
        location: location,
        allDay: allDay,
        start: startTime,
        end: endTime,
        manualColor: color,
        category: category,
        alertOffsetMinutes: alertMinutesBefore,
      );

      final scheduleResult = await _scheduleAlertForEvent(
        note: note.copyWith(
          id: updated.id,
          clientEventId: updated.clientEventId,
          calendarId: calendarId,
          calendarName: calendarName,
        ),
        ky: selYear,
        km: selMonth,
        kd: selDay,
        clientEventId: updated.clientEventId ?? unifiedCid,
        eventId: updated.id,
      );
      if (scheduleResult?.needsUserVisibleWarning == true) {
        _showNotificationScheduleWarning(scheduleResult?.message);
      }

      await _notifySharedCalendarItemAdded(
        calendarId: updated.calendarId ?? calendarId,
        itemType: 'event',
        itemId: updated.id,
        itemTitle: title,
        clientEventId: savedClientEventId,
        eventId: updated.id,
        startDate: gDay,
        endDate: endsAtUtc?.toLocal(),
        kYear: selYear,
        kMonth: selMonth,
        kDay: selDay,
      );

      // Also log to app_events for analytics
      try {
        await repo.track(
          event: 'note_created',
          properties: {
            'title': title,
            if (detail != null && detail.isNotEmpty) 'body': detail,
            if (location != null && location.isNotEmpty) 'location': location,
            'all_day': allDay,
          },
          source: 'client',
        );
      } catch (e) {
        if (kDebugMode) {
          _calendarDebugPrint('[SaveSingleNote] failed to log app_events: $e');
        }
      }
      return (clientEventId: savedClientEventId, eventId: updated.id);
    } catch (e, st) {
      try {
        await Notify.cancelNotificationForEvent(unifiedCid);
      } catch (cancelErr) {
        _calendarDebugPrint(
          '[SaveSingleNote] failed to cancel notification for $unifiedCid after error: $cancelErr',
        );
      }
      _calendarDebugPrint(
        '[SaveSingleNote] failed to save standalone note (cid=$unifiedCid): $e',
      );
      if (kDebugMode) {
        _calendarDebugPrint('$st');
      }
      rethrow;
    }
  }

  Future<({String clientEventId, String eventId})> _updateSingleNoteOnly({
    required String existingEventId,
    required String? previousClientEventId,
    required int selYear,
    required int selMonth,
    required int selDay,
    required String title,
    String? detail,
    String? location,
    String? calendarId,
    String? calendarName,
    required bool allDay,
    TimeOfDay? startTime,
    TimeOfDay? endTime,
    Color? color,
    String? category,
    int alertMinutesBefore = _alertNoneMinutes,
  }) async {
    final gDay = KemeticMath.toGregorian(selYear, selMonth, selDay);
    final startLocal = allDay
        ? DateTime(gDay.year, gDay.month, gDay.day, 9, 0)
        : DateTime(
            gDay.year,
            gDay.month,
            gDay.day,
            startTime!.hour,
            startTime.minute,
          );
    final note = _Note(
      id: existingEventId,
      clientEventId: previousClientEventId,
      calendarId: calendarId,
      calendarName: calendarName,
      title: title,
      detail: detail,
      location: location,
      allDay: allDay,
      start: startTime,
      end: endTime,
      flowId: -1,
      manualColor: color,
      category: category,
      alertOffsetMinutes: alertMinutesBefore,
    );
    final bodyLines = <String>[
      if (location != null && location.isNotEmpty) location,
      if (detail != null && detail.isNotEmpty) detail,
    ];

    final unifiedCid = _buildCid(
      ky: selYear,
      km: selMonth,
      kd: selDay,
      title: title,
      startHour: (allDay || startTime == null) ? null : startTime.hour,
      startMinute: (allDay || startTime == null) ? null : startTime.minute,
      allDay: allDay,
      flowId: -1,
      calendarScopeToken: _calendarScopeToken(calendarId),
    );

    await _ensureManualDeleteTombstonesLoaded();
    await _clearManualTombstone(unifiedCid);

    final encodedDetail = _encodeDetailWithMeta(
      detail,
      color: color,
      alertMinutes: alertMinutesBefore,
    );

    final repo = UserEventsRepo(Supabase.instance.client);
    final importedDeviceEvent = isImportedDeviceCalendarEvent(
      clientEventId: previousClientEventId,
      category: category,
    );
    final effectiveCategory = _editableStandaloneCategory(
      detachImportedDeviceEvent: importedDeviceEvent,
      category: category,
    );
    final endsAtUtc = (allDay || endTime == null)
        ? null
        : DateTime(
            gDay.year,
            gDay.month,
            gDay.day,
            endTime.hour,
            endTime.minute,
          ).toUtc();

    final updated = await repo.replace(
      id: existingEventId,
      clientEventId: unifiedCid,
      calendarId: calendarId,
      title: title,
      detail: encodedDetail,
      location: location,
      allDay: allDay,
      startsAt: startLocal,
      endsAt: endsAtUtc,
      category: effectiveCategory,
    );

    final savedClientEventId = updated.clientEventId ?? unifiedCid;
    if (previousClientEventId != null &&
        previousClientEventId != savedClientEventId) {
      try {
        await Notify.cancelNotificationForEvent(previousClientEventId);
      } catch (_) {}
    }
    if (importedDeviceEvent) {
      await _suppressImportedDeviceEventSource(previousClientEventId);
    }

    _addNote(
      selYear,
      selMonth,
      selDay,
      title,
      detail,
      id: updated.id,
      clientEventId: savedClientEventId,
      calendarId: calendarId,
      calendarName: calendarName,
      location: location,
      allDay: allDay,
      start: startTime,
      end: endTime,
      manualColor: color,
      category: effectiveCategory,
      alertOffsetMinutes: alertMinutesBefore,
    );

    final scheduleResult = await _scheduleAlertForEvent(
      note: note.copyWith(id: updated.id, clientEventId: savedClientEventId),
      ky: selYear,
      km: selMonth,
      kd: selDay,
      clientEventId: savedClientEventId,
      eventId: updated.id,
    );
    if (scheduleResult?.needsUserVisibleWarning == true) {
      _showNotificationScheduleWarning(scheduleResult?.message);
    }

    await _notifySharedCalendarMembers(
      calendarId: calendarId,
      title: _calendarDisplayName(calendarId),
      body: 'Updated event: $title',
      clientEventId: savedClientEventId,
      data: <String, dynamic>{
        'event_id': updated.id,
        if (bodyLines.isNotEmpty) 'preview': bodyLines.join('\n'),
      },
    );

    return (clientEventId: savedClientEventId, eventId: updated.id);
  }

  // Save a repeating note as a hidden micro-flow
  Future<void> _saveRepeatingNoteAsHiddenFlow({
    required int selYear,
    required int selMonth,
    required int selDay,
    required String title,
    String? detail,
    String? location,
    String? calendarId,
    String? calendarName,
    required bool allDay,
    required TimeOfDay? startTime,
    required TimeOfDay? endTime,
    required NoteRepeatOption repeatOption,
    required SimpleRecurrenceFrequency customFrequency,
    required int customInterval,
    required NoteRepeatEndType endType,
    required DateTime? endDate,
    required int endCount,
    required Color color,
    String? category,
    int alertMinutesBefore = _alertNoneMinutes,
  }) async {
    // 1. First occurrence = selected Kemetic day -> Gregorian
    final DateTime firstOccurrence = KemeticMath.toGregorian(
      selYear,
      selMonth,
      selDay,
    );

    // 2. Determine horizon for recurrence generation and flow.end.
    late final DateTime horizonEnd;
    if (endType == NoteRepeatEndType.onDate && endDate != null) {
      horizonEnd = DateUtils.dateOnly(endDate);
    } else if (endType == NoteRepeatEndType.afterCount) {
      // Rough upper bound: assume worst-case yearly interval * count.
      horizonEnd = firstOccurrence.add(Duration(days: 365 * endCount));
    } else {
      // Never ends: use a sane horizon (e.g. 1 year out).
      horizonEnd = firstOccurrence.add(const Duration(days: 365));
    }

    // 3. Generate `_RuleDates` with Kemetic-aware recurrence logic.
    final _RuleDates rule = _buildNoteRuleDates(
      firstOccurrenceDate: firstOccurrence,
      repeatOption: repeatOption,
      customFrequency: customFrequency,
      customInterval: customInterval,
      endType: endType,
      endDate: endDate,
      endCount: endCount,
      allDay: allDay,
      startTime: startTime,
      endTime: endTime,
      horizonEnd: horizonEnd,
    );

    // 4. Guard: if we somehow got no dates, fall back to single note.
    if (rule.dates.isEmpty) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[RepeatNote] Empty date set for repeating note "$title"; falling back to single note.',
        );
      }
      await _saveSingleNoteOnly(
        selYear: selYear,
        selMonth: selMonth,
        selDay: selDay,
        title: title,
        detail: detail,
        location: location,
        calendarId: calendarId,
        calendarName: calendarName,
        allDay: allDay,
        startTime: startTime,
        endTime: endTime,
        color: color,
        category: category,
        alertMinutesBefore: alertMinutesBefore,
      );
      return;
    }

    // 5. Create a hidden flow object in memory (micro-flow just for this note pattern).
    final flow = _Flow(
      id: -1, // Will be replaced by DB id
      calendarId: calendarId,
      name: title,
      color: color, // Use selected color
      active: true,
      rules: [rule],
      start: firstOccurrence,
      end: horizonEnd,
      notes: _encodeRepeatingNoteMetadata(
        detail: detail,
        location: location,
        category: category,
        alertMinutes: alertMinutesBefore,
      ),
      shareId: null,
      isHidden: true, // Critical: these never show in Flow Studio lists
    );

    final repo = UserEventsRepo(Supabase.instance.client);

    // 6. Persist the flow row to Supabase, storing rules as JSON.
    final rulesJson = jsonEncode([CalendarPageState.ruleToJson(rule)]);

    final int flowId = await repo.upsertFlow(
      id: null,
      name: flow.name,
      color: flow.color.toARGB32(),
      active: flow.active,
      calendarId: flow.calendarId,
      startDate: flow.start,
      endDate: flow.end,
      notes: flow.notes,
      rules: rulesJson,
      isHidden: flow.isHidden,
    );

    // 7. Insert into in-memory _flows list with correct ID.
    final savedFlow = _Flow(
      id: flowId,
      calendarId: flow.calendarId,
      name: flow.name,
      color: flow.color,
      active: flow.active,
      rules: flow.rules,
      start: flow.start,
      end: flow.end,
      notes: flow.notes,
      shareId: flow.shareId,
      isHidden: flow.isHidden,
    );

    _flows.add(savedFlow);
    if (flowId >= _nextFlowId) {
      _nextFlowId = flowId + 1;
    }

    // 8. Trigger materialization of events into user_events via the shared engine.
    await _triggerFlowSchedule(flowId);

    String? firstClientEventId;
    String? firstEventId;
    try {
      final events = await repo.getEventsForFlow(flowId);
      if (events.isNotEmpty) {
        firstClientEventId = events.first.clientEventId;
        firstEventId = events.first.id;
      }
    } catch (_) {}

    if (firstEventId != null) {
      await _notifySharedCalendarItemAdded(
        calendarId: flow.calendarId,
        itemType: 'note',
        itemId: firstEventId,
        itemTitle: title,
        clientEventId: firstClientEventId,
        flowId: flowId,
        noteId: firstEventId,
        startDate: firstOccurrence,
      );
    } else {
      await _notifySharedCalendarItemAdded(
        calendarId: flow.calendarId,
        itemType: 'flow',
        itemId: flowId.toString(),
        itemTitle: title,
        flowId: flowId,
        startDate: firstOccurrence,
      );
    }

    // 9. Refresh local caches so the new repeating note series shows up immediately.
    unawaited(_loadFromDisk(source: 'repeat_note_save'));
  }

  /// Universal date picker supporting Kemetic/Gregorian toggle
  Future<DateTime?> pickDateUniversal({
    required BuildContext context,
    required DateTime initialDate,
    bool allowPast = false,
    DateTime? firstDate,
    DateTime? lastDate,
  }) async {
    // Default to Gregorian mode for repeat-end selection
    bool localKemetic = false;

    // ---- Gregorian seed ----
    final now = DateUtils.dateOnly(DateTime.now());
    DateTime gSeed = initialDate;
    int gy = gSeed.year, gm = gSeed.month, gd = gSeed.day;

    // ---- Kemetic seed ----
    var kSeed = KemeticMath.fromGregorian(initialDate);
    int ky = kSeed.kYear, km = kSeed.kMonth, kd = kSeed.kDay;

    int gregDayMax(int y, int m) => DateUtils.getDaysInMonth(y, m);
    int kemDayMax(int year, int month) =>
        (month == 13) ? (KemeticMath.isLeapKemeticYear(year) ? 6 : 5) : 30;

    // ---- Controllers ----
    final gYearStart = now.year;
    final gYearCtrl = FixedExtentScrollController(
      initialItem: (gy - gYearStart).clamp(0, 399),
    );
    final gMonthCtrl = FixedExtentScrollController(
      initialItem: (gm - 1).clamp(0, 11),
    );
    final gDayCtrl = FixedExtentScrollController(
      initialItem: (gd - 1).clamp(0, 30),
    );

    final kYearStart = ky;
    final kYearCtrl = FixedExtentScrollController(
      initialItem: (ky - kYearStart).clamp(0, 400),
    );
    final kMonthCtrl = FixedExtentScrollController(
      initialItem: (km - 1).clamp(0, 12),
    );
    final kDayCtrl = FixedExtentScrollController(
      initialItem: (kd - 1).clamp(0, 29),
    );

    // ---------------------------------------------------------------------------
    // SHOW THE BOTTOM SHEET
    // ---------------------------------------------------------------------------
    final result = await showModalBottomSheet<DateTime>(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.black,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(16)),
      ),
      builder: (sheetCtx) {
        return StatefulBuilder(
          builder: (sheetCtx, setSheetState) {
            // Clamp wheels against month/day changes
            final gMax = gregDayMax(gy, gm);
            if (gd > gMax) gd = gMax;
            final kMax = kemDayMax(ky, km);
            if (kd > kMax) kd = kMax;

            // -------------------------------------------------------------------
            // Gregorian wheel
            // -------------------------------------------------------------------
            Widget gregWheel() => SizedBox(
              height: 160,
              child: Row(
                children: [
                  // MONTH
                  Expanded(
                    flex: 4,
                    child: CupertinoPicker(
                      scrollController: gMonthCtrl,
                      itemExtent: 32,
                      looping: true,
                      backgroundColor: const Color(0x00121214),
                      onSelectedItemChanged: (i) {
                        setSheetState(() {
                          gm = (i % 12) + 1;
                          final mx = gregDayMax(gy, gm);
                          if (gd > mx && gDayCtrl.hasClients) {
                            gd = mx;
                            WidgetsBinding.instance.addPostFrameCallback(
                              (_) => gDayCtrl.jumpToItem(gd - 1),
                            );
                          }
                        });
                      },
                      children: List.generate(
                        12,
                        (i) => Center(
                          child: GlossyText(
                            text: _gregMonthNames[i + 1],
                            style: const TextStyle(fontSize: 14),
                            gradient: silverGloss,
                          ),
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(width: 6),

                  // DAY
                  Expanded(
                    flex: 3,
                    child: CupertinoPicker(
                      scrollController: gDayCtrl,
                      itemExtent: 32,
                      looping: true,
                      backgroundColor: const Color(0x00121214),
                      onSelectedItemChanged: (i) {
                        setSheetState(() {
                          final mx = gregDayMax(gy, gm);
                          gd = (i % mx) + 1;
                        });
                      },
                      children: List.generate(
                        gregDayMax(gy, gm),
                        (i) => Center(
                          child: GlossyText(
                            text: '${i + 1}',
                            style: const TextStyle(fontSize: 14),
                            gradient: silverGloss,
                          ),
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(width: 6),

                  // YEAR
                  Expanded(
                    flex: 4,
                    child: CupertinoPicker(
                      scrollController: gYearCtrl,
                      itemExtent: 32,
                      looping: true,
                      backgroundColor: const Color(0x00121214),
                      onSelectedItemChanged: (i) {
                        setSheetState(() {
                          gy = gYearStart + i;
                          final mx = gregDayMax(gy, gm);
                          if (gd > mx && gDayCtrl.hasClients) {
                            gd = mx;
                            WidgetsBinding.instance.addPostFrameCallback(
                              (_) => gDayCtrl.jumpToItem(gd - 1),
                            );
                          }
                        });
                      },
                      children: List.generate(40, (i) {
                        final yy = gYearStart + i;
                        return Center(
                          child: GlossyText(
                            text: '$yy',
                            style: const TextStyle(fontSize: 14),
                            gradient: silverGloss,
                          ),
                        );
                      }),
                    ),
                  ),
                ],
              ),
            );

            // -------------------------------------------------------------------
            // Kemetic wheel
            // -------------------------------------------------------------------
            Widget kemWheel() => SizedBox(
              height: 160,
              child: Row(
                children: [
                  // MONTH
                  Expanded(
                    flex: 4,
                    child: CupertinoPicker(
                      scrollController: kMonthCtrl,
                      itemExtent: 32,
                      looping: true,
                      backgroundColor: const Color(0x00121214),
                      onSelectedItemChanged: (i) {
                        setSheetState(() {
                          km = (i % 13) + 1;
                          final mx = kemDayMax(ky, km);
                          if (kd > mx && kDayCtrl.hasClients) {
                            kd = mx;
                            WidgetsBinding.instance.addPostFrameCallback(
                              (_) => kDayCtrl.jumpToItem(kd - 1),
                            );
                          }
                        });
                      },
                      children: List.generate(
                        13,
                        (i) => Center(
                          child: MonthNameText(
                            getMonthById(i + 1).displayFull,
                            style: const TextStyle(fontSize: 14),
                          ),
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(width: 6),

                  // DAY
                  Expanded(
                    flex: 3,
                    child: CupertinoPicker(
                      scrollController: kDayCtrl,
                      itemExtent: 32,
                      looping: true,
                      backgroundColor: const Color(0x00121214),
                      onSelectedItemChanged: (i) {
                        setSheetState(() {
                          final mx = kemDayMax(ky, km);
                          kd = (i % mx) + 1;
                        });
                      },
                      children: List.generate(
                        kemDayMax(ky, km),
                        (i) => Center(
                          child: GlossyText(
                            text: '${i + 1}',
                            style: const TextStyle(fontSize: 14),
                            gradient: silverGloss,
                          ),
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(width: 6),

                  // YEAR
                  Expanded(
                    flex: 4,
                    child: CupertinoPicker(
                      scrollController: kYearCtrl,
                      itemExtent: 32,
                      looping: true,
                      backgroundColor: const Color(0x00121214),
                      onSelectedItemChanged: (i) {
                        setSheetState(() {
                          ky = kYearStart + i;
                          final mx = kemDayMax(ky, km);
                          if (kd > mx && kDayCtrl.hasClients) {
                            kd = mx;
                            WidgetsBinding.instance.addPostFrameCallback(
                              (_) => kDayCtrl.jumpToItem(kd - 1),
                            );
                          }
                        });
                      },
                      children: List.generate(401, (i) {
                        final y = kYearStart + i;
                        final last = (km == 13)
                            ? (KemeticMath.isLeapKemeticYear(y) ? 6 : 5)
                            : 30;
                        final yStart = KemeticMath.toGregorian(y, km, 1).year;
                        final yEnd = KemeticMath.toGregorian(y, km, last).year;
                        final label = (yStart == yEnd)
                            ? '$yStart'
                            : '$yStart/$yEnd';
                        return Center(
                          child: GlossyText(
                            text: label,
                            style: const TextStyle(fontSize: 14),
                            gradient: silverGloss,
                          ),
                        );
                      }),
                    ),
                  ),
                ],
              ),
            );

            // -------------------------------------------------------------------
            // UI SHEET CONTENT
            // -------------------------------------------------------------------
            return Padding(
              padding: EdgeInsets.only(
                left: 16,
                right: 16,
                top: 12,
                bottom: MediaQuery.of(sheetCtx).viewInsets.bottom + 12,
              ),
              child: Column(
                mainAxisSize: MainAxisSize.min,
                children: [
                  // drag handle
                  Container(
                    width: 36,
                    height: 4,
                    margin: const EdgeInsets.only(bottom: 12),
                    decoration: BoxDecoration(
                      color: Colors.white24,
                      borderRadius: BorderRadius.circular(2),
                    ),
                  ),

                  // mode toggle
                  CupertinoSegmentedControl<bool>(
                    groupValue: localKemetic,
                    padding: const EdgeInsets.all(2),
                    children: const {
                      true: Padding(
                        padding: EdgeInsets.symmetric(
                          horizontal: 10,
                          vertical: 6,
                        ),
                        child: Text('Kemetic'),
                      ),
                      false: Padding(
                        padding: EdgeInsets.symmetric(
                          horizontal: 10,
                          vertical: 6,
                        ),
                        child: Text('Gregorian'),
                      ),
                    },
                    onValueChanged: (v) {
                      setSheetState(() {
                        if (v) {
                          // Switch to Kemetic
                          final gNow = DateTime(gy, gm, gd);
                          final k = KemeticMath.fromGregorian(gNow);
                          ky = k.kYear;
                          km = k.kMonth;
                          kd = k.kDay;
                          final kMax = kemDayMax(ky, km);
                          if (kd > kMax) kd = kMax;
                          localKemetic = true;

                          WidgetsBinding.instance.addPostFrameCallback((_) {
                            kYearCtrl.jumpToItem(
                              (ky - kYearStart).clamp(0, 400),
                            );
                            kMonthCtrl.jumpToItem((km - 1).clamp(0, 12));
                            kDayCtrl.jumpToItem((kd - 1).clamp(0, 29));
                          });
                        } else {
                          // Switch to Gregorian
                          final g = KemeticMath.toGregorian(ky, km, kd);
                          gy = g.year;
                          gm = g.month;
                          gd = g.day;
                          final gMax = gregDayMax(gy, gm);
                          if (gd > gMax) gd = gMax;
                          localKemetic = false;

                          WidgetsBinding.instance.addPostFrameCallback((_) {
                            gYearCtrl.jumpToItem(
                              (gy - gYearStart).clamp(0, 39),
                            );
                            gMonthCtrl.jumpToItem((gm - 1).clamp(0, 11));
                            gDayCtrl.jumpToItem((gd - 1).clamp(0, 30));
                          });
                        }
                      });
                    },
                  ),

                  const SizedBox(height: 10),

                  GlossyText(
                    text: localKemetic
                        ? 'Pick date (Kemetic)'
                        : 'Pick date (Gregorian)',
                    style: const TextStyle(
                      fontSize: 16,
                      fontWeight: FontWeight.w600,
                    ),
                    gradient: localKemetic ? goldGloss : blueGloss,
                  ),

                  const SizedBox(height: 8),

                  localKemetic ? kemWheel() : gregWheel(),

                  const SizedBox(height: 12),

                  Row(
                    children: [
                      // CANCEL
                      Expanded(
                        child: OutlinedButton(
                          style: OutlinedButton.styleFrom(
                            foregroundColor: Colors.white,
                            side: const BorderSide(color: silver, width: 1.25),
                          ),
                          onPressed: () => Navigator.pop(sheetCtx),
                          child: const Text('Cancel'),
                        ),
                      ),
                      const SizedBox(width: 8),

                      // USE THIS DATE
                      Expanded(
                        child: ElevatedButton(
                          style: ElevatedButton.styleFrom(
                            backgroundColor: localKemetic ? _gold : _blue,
                            foregroundColor: Colors.black,
                          ),
                          onPressed: () {
                            final DateTime chosen = localKemetic
                                ? KemeticMath.toGregorian(ky, km, kd)
                                : DateUtils.dateOnly(DateTime(gy, gm, gd));

                            // Apply constraints
                            DateTime finalResult = chosen;
                            if (!allowPast &&
                                firstDate != null &&
                                finalResult.isBefore(firstDate)) {
                              finalResult = firstDate;
                            }
                            if (lastDate != null &&
                                finalResult.isAfter(lastDate)) {
                              finalResult = lastDate;
                            }

                            Navigator.pop(sheetCtx, finalResult);
                          },
                          child: const Text('Use this date'),
                        ),
                      ),
                    ],
                  ),
                ],
              ),
            );
          },
        );
      },
    );

    return result;
  }

  /// Trigger function: central place to (re)schedule events for a flow.
  ///
  /// This is the only method that should call `scheduleFlowNotes` directly.
  /// It is used by:
  ///  - Flow Studio saves/updates
  ///  - Repeating notes (hidden micro-flows)
  Future<void> _triggerFlowSchedule(int flowId) async {
    _Flow flow;

    try {
      flow = _flows.firstWhere((f) => f.id == flowId);
    } catch (_) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[triggerFlowSchedule] Flow $flowId not found in _flows; skipping schedule.',
        );
      }
      return;
    }

    // If flow is inactive or has no rules, just clear its events.
    if (!flow.active || flow.rules.isEmpty) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[triggerFlowSchedule] Flow $flowId inactive or has no rules; deleting events.',
        );
      }
      final repo = UserEventsRepo(Supabase.instance.client);
      await repo.deleteByFlowId(flowId);
      return;
    }

    if (kDebugMode) {
      _calendarDebugPrint(
        '[triggerFlowSchedule] Scheduling flow $flowId with ${flow.rules.length} rules',
      );
    }

    await scheduleFlowNotes(
      flowId: flow.id,
      rules: flow.rules,
      flowNotes: flow.notes,
      startDate: flow.start,
      endDate: flow.end,
    );
  }

  Future<void> scheduleFlowNotes({
    required int flowId,
    required List<FlowRule> rules,
    required String? flowNotes,
    DateTime? startDate,
    DateTime? endDate,
  }) async {
    final repo = UserEventsRepo(Supabase.instance.client);
    final scheduleStart = startDate ?? DateTime.now();
    final scheduleEnd =
        endDate ??
        scheduleStart.add(const Duration(days: 90)); // Default 90 days

    if (kDebugMode) {
      _calendarDebugPrint(
        '[scheduleFlowNotes] Starting for flowId=$flowId from $scheduleStart to $scheduleEnd',
      );
    }

    // Look up flow object for name and metadata
    _Flow? flow;
    try {
      flow = _flows.firstWhere((f) => f.id == flowId);
    } catch (_) {
      flow = null;
    }

    final flowStart = flow?.start ?? DateTime(1970);
    final flowEnd = flow?.end ?? DateTime(2100);
    final hasOverlap =
        !flowEnd.isBefore(scheduleStart) && !flowStart.isAfter(scheduleEnd);
    if (!hasOverlap) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[scheduleFlowNotes] ⚠️ No overlap: flow ($flowStart-$flowEnd) vs schedule ($scheduleStart-$scheduleEnd)',
        );
      }
      return;
    }

    String noteTitle = flow?.name ?? 'Flow Event';
    final flowCalendarId = flow?.calendarId;
    final flowCalendarName = _calendarSummary(flowCalendarId)?.name;
    String? noteDetail;
    String? noteLocation;
    String? noteCategory;
    int? noteAlertMinutes;

    // Decode flow.notes to extract detail and location for repeating notes
    if (flowNotes != null && flowNotes.isNotEmpty) {
      try {
        // Try JSON first (for repeating notes)
        final meta = jsonDecode(flowNotes) as Map<String, dynamic>;
        if (meta['kind'] == 'repeating_note') {
          noteDetail = (meta['detail'] as String?)?.trim();
          noteLocation = (meta['location'] as String?)?.trim();
          noteCategory = (meta['category'] as String?)?.trim();
          noteAlertMinutes = (meta['alertMinutes'] as num?)?.toInt();
        } else {
          // Legacy flowNotes format - try notesDecode
          try {
            final decoded = notesDecode(flowNotes);
            if (decoded.overview.isNotEmpty) noteDetail = decoded.overview;
          } catch (_) {
            // Ignore if decode fails
          }
        }
      } catch (_) {
        // Not JSON, try legacy format
        try {
          final decoded = notesDecode(flowNotes);
          if (decoded.overview.isNotEmpty) noteDetail = decoded.overview;
        } catch (_) {
          // Ignore if both fail
        }
      }
    }

    // Build candidate events first; only delete/insert if we have any.
    final candidateEvents = <_CandidateEvent>[];
    try {
      var date = scheduleStart;
      while (!date.isAfter(scheduleEnd)) {
        final kDate = KemeticMath.fromGregorian(date);

        for (final rule in rules) {
          if (rule.matches(
            ky: kDate.kYear,
            km: kDate.kMonth,
            kd: kDate.kDay,
            g: date,
          )) {
            final startHour = rule.allDay ? 9 : (rule.start?.hour ?? 9);
            final startMinute = rule.allDay ? 0 : (rule.start?.minute ?? 0);

            final detailWithMeta = _encodeDetailWithMeta(
              noteDetail,
              alertMinutes: noteAlertMinutes,
            );

            final cid = _buildCid(
              ky: kDate.kYear,
              km: kDate.kMonth,
              kd: kDate.kDay,
              title: noteTitle,
              startHour: startHour,
              startMinute: startMinute,
              allDay: rule.allDay,
              flowId: flowId,
            );

            final startsAt = DateTime(
              date.year,
              date.month,
              date.day,
              startHour,
              startMinute,
            );

            DateTime? endsAt;
            if (!rule.allDay) {
              if (rule.end != null) {
                endsAt = DateTime(
                  date.year,
                  date.month,
                  date.day,
                  rule.end!.hour,
                  rule.end!.minute,
                );
              } else {
                // Default to 1 hour if end is missing
                endsAt = DateTime(
                  date.year,
                  date.month,
                  date.day,
                  startHour,
                  startMinute,
                ).add(const Duration(hours: 1));
              }
            }

            candidateEvents.add(
              _CandidateEvent(
                clientEventId: cid,
                title: noteTitle,
                startsAtUtc: startsAt.toUtc(),
                endsAtUtc: endsAt?.toUtc(),
                calendarId: flowCalendarId,
                detail: detailWithMeta ?? noteDetail,
                location: noteLocation,
                allDay: rule.allDay,
                flowLocalId: flowId,
                category: noteCategory,
              ),
            );
          }
        }

        date = date.add(const Duration(days: 1));
      }
    } catch (e, stack) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[scheduleFlowNotes] ⚠️ Generation failed for flowId=$flowId: $e',
        );
        _calendarDebugPrint(stack.toString());
      }
      return;
    }

    if (candidateEvents.isEmpty) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[scheduleFlowNotes] ⚠️ No events generated for flowId=$flowId; skipping delete.',
        );
      }
      return;
    }

    try {
      // Clear existing scheduled notes for this flow after successful generation
      await repo.deleteByFlowId(
        flowId,
        fromDate: scheduleStart.toUtc(),
        semantic: 'flow_reschedule',
        suppressesClient: false,
        sourceFeature: 'CalendarPage.scheduleFlowNotes',
        deleteScope: 'flow_reschedule',
      );
      await repo.track(
        event: 'flow_rescheduled',
        properties: {'flow_id': flowId, 'v': kAppEventsSchemaVersion},
      );

      for (final ev in candidateEvents) {
        final savedEvent = await repo.upsertByClientId(
          clientEventId: ev.clientEventId,
          title: ev.title,
          startsAtUtc: ev.startsAtUtc,
          detail: ev.detail,
          location: ev.location,
          allDay: ev.allDay,
          endsAtUtc: ev.endsAtUtc,
          calendarId: ev.calendarId,
          flowLocalId: ev.flowLocalId,
          category: ev.category,
          caller: 'schedule_flow_notes',
        );

        final decodedMeta = _decodeDetailMetadata(ev.detail);
        final localStart = ev.startsAtUtc.toLocal();
        final kDate = KemeticMath.fromGregorian(localStart);
        final note = _Note(
          calendarId: flowCalendarId,
          calendarName: flowCalendarName,
          title: ev.title,
          detail: decodedMeta.detail ?? ev.detail,
          location: ev.location,
          allDay: ev.allDay,
          start: ev.allDay ? null : TimeOfDay.fromDateTime(localStart),
          end: ev.endsAtUtc == null
              ? null
              : TimeOfDay.fromDateTime(ev.endsAtUtc!.toLocal()),
          flowId: ev.flowLocalId,
          category: ev.category,
          alertOffsetMinutes: decodedMeta.alertMinutes ?? _alertNoneMinutes,
        );

        await _scheduleAlertForEvent(
          note: note,
          ky: kDate.kYear,
          km: kDate.kMonth,
          kd: kDate.kDay,
          clientEventId: savedEvent.clientEventId ?? ev.clientEventId,
          eventId: savedEvent.id,
        );
      }

      if (kDebugMode) {
        _calendarDebugPrint(
          '[scheduleFlowNotes] Scheduled ${candidateEvents.length} notes for flowId=$flowId',
        );
      }
    } catch (e, stack) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[scheduleFlowNotes] ⚠️ CRITICAL: delete/insert failed for flowId=$flowId: $e',
        );
        _calendarDebugPrint(stack.toString());
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    // ✅ HARDENING 2: Gate build until state is restored to prevent race condition
    if (!_restored) {
      return const SizedBox.shrink();
    }

    final kToday = _today;
    final size = MediaQuery.sizeOf(context);
    final orientation = MediaQuery.orientationOf(context);
    final isLandscape = orientation == Orientation.landscape;
    // Landscape grid only on phone-sized screens; tablets/desktop stay on portrait layout.
    final useGrid = isLandscape && size.shortestSide < 600;
    if (!useGrid) {
      _landscapeTodayAction = null;
    }

    // ========================================
    // DEBUG: Log orientation changes
    // ========================================
    final previousOrientation = _lastOrientation;
    if (previousOrientation != null && previousOrientation != orientation) {
      if (kDebugMode) {
        _calendarDebugPrint('\n${'🔄' * 30}');
        _calendarDebugPrint('ORIENTATION CHANGED!');
        _calendarDebugPrint('From: $previousOrientation → To: $orientation');
        _calendarDebugPrint('Navigator canPop: ${Navigator.canPop(context)}');
        _calendarDebugPrint(
          'Modal route active: ${ModalRoute.of(context)?.isCurrent ?? false}',
        );
        _calendarDebugPrint('${'🔄' * 30}\n');
      }

      if (previousOrientation == Orientation.portrait &&
          orientation == Orientation.landscape) {
        _commitVisiblePortraitMonthForRotation();
      }

      if (orientation == Orientation.portrait) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '📜 [CALENDAR] Preserving month for portrait: $_lastViewKy-$_lastViewKm',
          );
        }
        _portraitRecenterPending = true;
      }
    }
    _lastOrientation = orientation;

    if (useGrid) {
      // ✅ FIX 5: Only call if state is missing (optimization)
      // The method already has a guard, but this prevents unnecessary function calls
      // ✅ FIX 6: Also prevent during landscape updates to avoid side effects
      if (!_isUpdatingFromLandscape &&
          (_lastViewKy == null || _lastViewKm == null)) {
        _updateCenteredMonthWide();
      }

      final ky = _lastViewKy ?? kToday.kYear;
      final km = _lastViewKm ?? kToday.kMonth;

      if (kDebugMode) {
        _calendarDebugPrint('\n📱 [CALENDAR] Building LandscapeMonthView');
        _calendarDebugPrint('   initialKy: $ky');
        _calendarDebugPrint('   initialKm: $km');
        _calendarDebugPrint('   initialKd: null');
        _calendarDebugPrint('   onAddNote callback: PROVIDED');
      }

      return Scaffold(
        backgroundColor: _bg,
        appBar: _buildCalendarAppBar(
          useLandscapeGrid: true,
          titleOverride: _buildLandscapeCalendarTitle(ky, km),
        ),
        body: LandscapeMonthView(
          embeddedInCalendarScaffold: true,
          initialKy: ky,
          initialKm: km,
          initialKd: _lastViewKd ?? _today.kDay, // ✅ Highlight current day
          showGregorian: _showGregorian,
          dataVersion: _dayViewDataVersion,
          notesForDay: (ky, km, kd) {
            final notes = _getNotes(ky, km, kd);
            return notes
                .map(
                  (n) => NoteData(
                    id: n.id?.toString(),
                    clientEventId: n.clientEventId,
                    calendarId: n.calendarId,
                    calendarName: n.calendarName,
                    title: n.title,
                    detail: n.detail,
                    location: n.location,
                    allDay: n.allDay,
                    start: n.start,
                    end: n.end,
                    flowId: n.flowId,
                    manualColor: n.manualColor,
                    category: n.category,
                    isReminder: n.isReminder,
                    reminderId: n.reminderId,
                    behaviorPayload: n.behaviorPayload,
                  ),
                )
                .toList();
          },
          flowIndex: _buildCalendarFlowChromeIndex(),
          activeLedgerFlowIds: _buildActiveLedgerFlowIds(),
          getMonthName: (km) => getMonthById(km).displayFull,
          onManageFlows: _getMyFlowsCallback(),
          onAddNote: (ky, km, kd) {
            if (kDebugMode) {
              _calendarDebugPrint(
                '\n🎯 [CALLBACK] onAddNote received from landscape',
              );
              _calendarDebugPrint('   Date: $ky-$km-$kd');
            }
            _openDaySheet(ky, km, kd, allowDateChange: true);
          },
          onMonthChanged: _handleLandscapeMonthChanged, // ✅ ADD CALLBACK
          onVisibleMonthCommitted: _commitLandscapeVisibleMonthForRotation,
          onTodayActionChanged: (action) {
            _landscapeTodayAction = action;
          },
          onDeleteNote: (ky, km, kd, evt) async =>
              _deleteNoteByEvent(ky, km, kd, evt),
          onEditNote: (ky, km, kd, evt) async {
            await _editNoteByEvent(ky, km, kd, evt);
          },
          onEditReminder: (id) async => _editReminderById(id),
          onEndReminder: (id) async => _endReminderRule(id),
          onShareReminder: (evt) async => _shareNoteSimple(evt),
          onShareNote: (evt) async {
            await _shareNoteSimple(evt);
          },
          onAppendToJournal: _journalInitialized
              ? (text) => _journalController.appendToToday(text)
              : null,
          onEndFlow: (id) => _endFlow(id),
          onSaveFlow: _saveFlowById,
          onEventDetailRestorationChanged:
              _handleCalendarEventDetailRestorationChanged,
          shouldPreserveEventDetailRestorationOnClose: () =>
              RestorationCoordinator
                  .instance
                  .shouldPreserveOverlayForLifecycleClose,
        ),
      );
    }

    final scaffold = Scaffold(
      backgroundColor: _bg,
      appBar: _buildCalendarAppBar(useLandscapeGrid: false),
      body: _buildBodyWithJournal(),
    );

    Widget content = scaffold;

    final calendarMonthCoachmarkTargetKey = _calendarMonthCoachmarkTargetKey;
    if (_showCalendarMonthCoachmark &&
        calendarMonthCoachmarkTargetKey != null) {
      content = Stack(
        children: [
          content,
          Positioned.fill(
            child: CalendarMonthCoachmark(
              targetKey: calendarMonthCoachmarkTargetKey,
              onTargetTap: _handleCalendarMonthCoachmarkTargetTap,
            ),
          ),
        ],
      );
    }

    if (_showCalendarToggleCoachmark) {
      content = Stack(
        children: [
          content,
          Positioned.fill(
            child: CalendarToggleCoachmark(
              targetKey: _calendarToggleKey,
              onTargetTap: _handleCalendarToggleTapped,
            ),
          ),
        ],
      );
    }

    if (_showOnboarding) {
      content = Stack(
        children: [
          content,
          Positioned.fill(
            child: OnboardingOverlay(
              slides: _buildOnboardingSlides(),
              onSkip: _handleOnboardingSkip,
              onComplete: _handleOnboardingComplete,
            ),
          ),
        ],
      );
    }

    return content;
  }

  Widget _buildBodyWithJournal() {
    final isPortrait =
        MediaQuery.of(context).orientation == Orientation.portrait;
    final allowTouchPinchGestures = useExpandedTouchTargets(context);
    final allowGlobalScaleGestures = useGlobalScaleGestures(context);
    if (_portraitRecenterPending && isPortrait) {
      _ensurePortraitCentered();
    }

    final scrollView = Offstage(
      offstage: _portraitRecenterPending && isPortrait,
      child: _buildCalendarScrollView(),
    );

    final content = PinchGestureSurface(
      enableTouchPinch: allowTouchPinchGestures,
      enableGlobalScaleGestures: allowGlobalScaleGestures,
      onScaleStart: _onScaleStart,
      onScaleUpdate: _onScaleUpdate,
      onScaleEnd: _onScaleEnd,
      child: scrollView,
    );

    return Stack(
      children: [
        content,
        _buildPlannerSwipeGate(),
        _buildProfileSwipeGate(),
        const PendingEventInviteOverlay(),
        if (_reflectionPrompt != null) _buildReflectionBadge(),
      ],
    );
  }

  Widget _buildPlannerSwipeGate() {
    return PageNavigationEdgeSwipe(
      direction: PageNavigationSwipeDirection.leftToRight,
      enabled: !_plannerNavigationInFlight,
      onCommit: () {
        unawaited(_openPlannerPage(edgeSwipeTransition: true));
      },
    );
  }

  Widget _buildProfileSwipeGate() {
    return PageNavigationEdgeSwipe(
      direction: PageNavigationSwipeDirection.rightToLeft,
      enabled: !_profileNavigationInFlight,
      onCommit: () {
        unawaited(_openProfile(context, openedFromCalendarSwipe: true));
      },
    );
  }

  /* ───────────── Decan Reflection Badge & Archive ───────────── */

  Widget _buildReflectionBadge() {
    final prompt = _reflectionPrompt;
