    final media = MediaQuery.of(context);
    final maxWidth = media.size.width * 0.72;
    final preview = prompt.reflectionText.trim().isEmpty
        ? 'Decan reflection ready'
        : prompt.reflectionText.trim();

    return Positioned(
      right: 12,
      bottom: 16 + media.padding.bottom,
      child: Material(
        color: Colors.black.withValues(alpha: 0.9),
        borderRadius: BorderRadius.circular(14),
        elevation: 8,
        child: InkWell(
          borderRadius: BorderRadius.circular(14),
          onTap: _showReflectionSheet,
          child: Padding(
            padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 12),
            child: ConstrainedBox(
              constraints: BoxConstraints(maxWidth: maxWidth),
              child: Row(
                mainAxisSize: MainAxisSize.min,
                children: [
                  const Icon(Icons.menu_book_rounded, color: _gold, size: 18),
                  const SizedBox(width: 8),
                  Flexible(
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        const Text(
                          'Decan reflection',
                          style: TextStyle(
                            color: _gold,
                            fontSize: 12,
                            fontWeight: FontWeight.w700,
                          ),
                        ),
                        const SizedBox(height: 2),
                        Text(
                          preview,
                          maxLines: 2,
                          overflow: TextOverflow.ellipsis,
                          style: const TextStyle(
                            color: Colors.white,
                            fontSize: 12.5,
                            height: 1.25,
                          ),
                        ),
                      ],
                    ),
                  ),
                ],
              ),
            ),
          ),
        ),
      ),
    );
  }

  void _showReflectionSheet() {
    final prompt = _reflectionPrompt;
    if (prompt == null) return;
    final dateRange =
        '${_formatDateOnlyLocal(prompt.decanStart)} → ${_formatDateOnlyLocal(prompt.decanEnd)}';

    showModalBottomSheet(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.black,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(18)),
      ),
      builder: (sheetCtx) {
        final inset = MediaQuery.of(sheetCtx).viewInsets.bottom;
        return SafeArea(
          child: Padding(
            padding: EdgeInsets.fromLTRB(16, 12, 16, 12 + inset),
            child: SizedBox(
              height: MediaQuery.of(sheetCtx).size.height * 0.65,
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Center(
                    child: Container(
                      width: 48,
                      height: 4,
                      decoration: BoxDecoration(
                        color: Colors.white12,
                        borderRadius: BorderRadius.circular(99),
                      ),
                    ),
                  ),
                  const SizedBox(height: 12),
                  Text(
                    prompt.decanName,
                    style: const TextStyle(
                      color: _gold,
                      fontSize: 16,
                      fontWeight: FontWeight.w700,
                    ),
                  ),
                  const SizedBox(height: 4),
                  Text(
                    dateRange,
                    style: const TextStyle(
                      color: Colors.white70,
                      fontSize: 12.5,
                    ),
                  ),
                  if (prompt.badgeCount > 0) ...[
                    const SizedBox(height: 4),
                    Text(
                      '${prompt.badgeCount} badge${prompt.badgeCount == 1 ? '' : 's'} captured',
                      style: const TextStyle(
                        color: Colors.white60,
                        fontSize: 12,
                      ),
                    ),
                  ],
                  const SizedBox(height: 14),
                  Expanded(
                    child: SingleChildScrollView(
                      child: Text(
                        prompt.reflectionText,
                        style: const TextStyle(
                          color: Colors.white,
                          fontSize: 14.5,
                          height: 1.5,
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(height: 12),
                  Row(
                    children: [
                      ElevatedButton.icon(
                        onPressed: _archivingReflection
                            ? null
                            : () => _archiveReflectionPrompt(sheetCtx),
                        style: ElevatedButton.styleFrom(
                          backgroundColor: _gold,
                          foregroundColor: Colors.black,
                          padding: const EdgeInsets.symmetric(
                            horizontal: 16,
                            vertical: 12,
                          ),
                        ),
                        icon: _archivingReflection
                            ? const SizedBox(
                                width: 16,
                                height: 16,
                                child: CircularProgressIndicator(
                                  strokeWidth: 2,
                                  color: Colors.black,
                                ),
                              )
                            : const Icon(Icons.archive_outlined, size: 18),
                        label: const Text('Archive to profile'),
                      ),
                      const SizedBox(width: 12),
                      TextButton(
                        onPressed: () => Navigator.of(sheetCtx).pop(),
                        child: const Text(
                          'Close',
                          style: TextStyle(color: _gold),
                        ),
                      ),
                    ],
                  ),
                ],
              ),
            ),
          ),
        );
      },
    ).whenComplete(() {
      if (!mounted) return;
      final current = _reflectionPrompt;
      if (current == null) return;
      if (!DateUtils.isSameDay(current.decanStart, prompt.decanStart)) return;
      unawaited(_dismissReflectionPrompt());
    });
  }

  String _formatDateOnlyLocal(DateTime date) {
    final d = date.toLocal();
    final yyyy = d.year.toString().padLeft(4, '0');
    final mm = d.month.toString().padLeft(2, '0');
    final dd = d.day.toString().padLeft(2, '0');
    return '$yyyy-$mm-$dd';
  }

  DateTime _dateOnlyLocal(DateTime date) {
    final d = date.toLocal();
    return DateTime(d.year, d.month, d.day);
  }

  Future<void> _dismissReflectionPrompt() async {
    final prompt = _reflectionPrompt;
    if (prompt == null) return;
    if (mounted) {
      setState(() => _reflectionPrompt = null);
    }
    await _markReflectionPromptInteracted(prompt, interactionKind: 'dismissed');
    if (!mounted) return;
    final current = _reflectionPrompt;
    if (current != null &&
        DateUtils.isSameDay(current.decanStart, prompt.decanStart)) {
      setState(() => _reflectionPrompt = null);
    }
  }

  ({
    DateTime start,
    DateTime end,
    String decanName,
    String? decanTheme,
    String decanContextKey,
    int kMonth,
    int kYear,
  })?
  _latestCompletedDecanWindow() {
    final now = DateTime.now();
    final kem = KemeticMath.fromGregorian(now);

    // Skip epagomenal days (month 13) for reflection generation; fall back to month 12.
    int kMonth = kem.kMonth;
    int kYear = kem.kYear;
    int completedDecan = kem.kDay ~/ 10; // 1-based decan completion count

    if (kMonth == 13) {
      kMonth = 12;
      completedDecan = 3;
    }

    if (completedDecan == 0) {
      if (kMonth <= 1) {
        kYear -= 1;
        kMonth = 12;
      } else {
        kMonth -= 1;
      }
      completedDecan = 3;
    }

    completedDecan = completedDecan.clamp(1, 3);
    if (kMonth == 13) return null; // guard epagomenal month fallback

    final decanStartDay = ((completedDecan - 1) * 10) + 1;
    final decanEndDay = completedDecan * 10;

    final start = KemeticMath.toGregorian(kYear, kMonth, decanStartDay);
    final end = KemeticMath.toGregorian(kYear, kMonth, decanEndDay);
    final todayLocal = _dateOnlyLocal(DateTime.now());
    if (_dateOnlyLocal(end).isAfter(todayLocal)) {
      return null; // only after completion
    }

    final decanLabel = DecanMetadata.decanNameFor(
      kMonth: kMonth,
      kDay: decanEndDay,
      expanded: true,
    );
    final monthLabel = getMonthById(kMonth).displayShort;

    return (
      start: start,
      end: end,
      decanName: '$monthLabel — $decanLabel',
      decanTheme: decanLabel,
      decanContextKey: '$kMonth-$completedDecan',
      kMonth: kMonth,
      kYear: kYear,
    );
  }

  JournalDocument? _documentFromJournalEntry(JournalEntry entry) {
    final body = entry.body.trim();
    if (body.isEmpty) return JournalDocument.fromPlainText('');

    if (body.startsWith('{') && body.contains('"version"')) {
      try {
        final map = jsonDecode(body) as Map<String, dynamic>;
        return JournalDocument.fromJson(map);
      } catch (e) {
        if (kDebugMode) {
          _calendarDebugPrint(
            'Failed to parse journal document for ${entry.gregDate}: $e',
          );
        }
      }
    }

    return JournalDocument.fromPlainText(body);
  }

  Future<
    List<
      ({
        EventBadgeToken token,
        DateTime occurredOn,
        DateTime? occurredAt,
        List<String> tags,
      })
    >
  >
  _collectDecanBadges(DateTime decanStart, DateTime decanEnd) async {
    final entries = await _journalRepo.listRange(
      start: decanStart,
      end: decanEnd,
    );
    final badges =
        <
          ({
            EventBadgeToken token,
            DateTime occurredOn,
            DateTime? occurredAt,
            List<String> tags,
          })
        >[];
    final seen = <String>{};

    void addBadges(
      List<EventBadgeToken> tokens,
      DateTime fallbackDay, {
      List<String> tags = const <String>[],
    }) {
      final day = _dateOnlyLocal(fallbackDay);
      for (final token in tokens) {
        if (!seen.add(token.id)) continue;
        final occurred = token.start != null
            ? _dateOnlyLocal(token.start!)
            : day;
        badges.add((
          token: token,
          occurredOn: occurred,
          occurredAt: token.start,
          tags: tags,
        ));
      }
    }

    for (final entry in entries) {
      final doc = _documentFromJournalEntry(entry);
      if (doc == null) continue;
      addBadges(JournalBadgeUtils.tokensFromDocument(doc), entry.gregDate);
    }

    final currentDoc = _journalController.currentDocument;
    final currentDate = _journalController.currentDate;
    final withinWindow =
        currentDate != null &&
        !currentDate.isBefore(_dateOnlyLocal(decanStart)) &&
        !currentDate.isAfter(_dateOnlyLocal(decanEnd));
    if (currentDoc != null && currentDate != null && withinWindow) {
      addBadges(JournalBadgeUtils.tokensFromDocument(currentDoc), currentDate);
    }

    final plannerBadges = await _plannerBadgeRepo.fetchPlannerBadges(
      start: decanStart,
      end: decanEnd,
    );
    for (final badge in plannerBadges) {
      final token = badge.toEventBadgeToken();
      if (!seen.add(token.id)) continue;
      badges.add((
        token: token,
        occurredOn: _dateOnlyLocal(badge.occurredOn),
        occurredAt: null,
        tags: badge.tags,
      ));
    }

    badges.sort((a, b) {
      final cmp = a.occurredOn.compareTo(b.occurredOn);
      if (cmp != 0) return cmp;
      if (a.occurredAt == null && b.occurredAt == null) return 0;
      if (a.occurredAt == null) return 1;
      if (b.occurredAt == null) return -1;
      return a.occurredAt!.compareTo(b.occurredAt!);
    });

    return badges;
  }

  String _buildReflectionFromBadges(List<EventBadgeToken> badges) {
    if (badges.isEmpty) {
      return 'Time moved quietly this decan. Silence is still a shape—space held open for whatever wants to speak next.';
    }

    final titleCounts = <String, int>{};
    int morningCount = 0;
    int eveningCount = 0;

    for (final b in badges) {
      final t = b.title.trim().toLowerCase();
      if (t.isNotEmpty) {
        titleCounts[t] = (titleCounts[t] ?? 0) + 1;
      }
      final start = b.start;
      if (start != null) {
        final h = start.toLocal().hour;
        if (h < 12) morningCount++;
        if (h >= 18) eveningCount++;
      }
    }

    final sorted = titleCounts.entries.toList()
      ..sort((a, b) => b.value.compareTo(a.value));
    final dominant = sorted.isNotEmpty ? sorted.first.value : 0;
    final total = badges.length;
    final dominantRatio = total == 0 ? 0.0 : dominant / total;

    final focused = dominantRatio >= 0.5;
    final exploratory = sorted.length >= 3 && dominantRatio < 0.5;
    final morningLean = morningCount > total / 2;
    final eveningLean = eveningCount > total / 2;

    final opening = focused
        ? 'This decan moved in close circles—choosing depth over breadth.'
        : exploratory
        ? 'Your days touched many currents, yet an inner note stayed steady.'
        : 'You moved with measured steps, neither rushing nor drifting.';

    final pattern = focused
        ? 'Returning to similar moments suggests you were seeking alignment more than variety—choosing what felt true over what was simply available.'
        : exploratory
        ? 'You let yourself explore without fixing on one shape. That kind of wandering is listening for what rings honest.'
        : 'Your marks carried a quiet negotiation between stability and change, steadying yourself while testing new edges.';

    final rhythm = morningLean
        ? 'Mornings held more of your presence—as if first light gave the clearest signal.'
        : eveningLean
        ? 'Evenings gathered your energy—closing light became a place to settle what mattered.'
        : 'Your hours spread across the day, a gentle pulse rather than a single surge.';

    const silence =
        'Some spaces stayed quiet—not as neglect, but as rest points waiting to receive you when you are ready.';

    const invitation =
        'As the next decan opens, carry forward the feeling that felt most like you, and let one quiet space be touched—only if it calls.';

    const closing =
        'Archive what mattered so you do not have to relearn it later. Endings are easier when you can see the shape you already made.';

    final dominantTitle = sorted.isNotEmpty
        ? 'Most frequent: “${sorted.first.key}”. '
        : '';
    final badgesLine = 'Badges logged: $total. ${dominantTitle.trim()}';

    return [
      opening,
      pattern,
      rhythm,
      silence,
      badgesLine,
      invitation,
      closing,
    ].join('\n\n');
  }

  Future<bool> _hasInteractedWithReflectionPrompt(DateTime decanStart) async {
    if (await _decanReflectionPromptState.hasInteracted(decanStart)) {
      return true;
    }
    final cloudInteracted = await _decanReflectionRepo.hasPromptInteracted(
      decanStart,
    );
    if (cloudInteracted) {
      await _decanReflectionPromptState.markInteracted(decanStart);
    }
    return cloudInteracted;
  }

  Future<void> _markReflectionPromptInteracted(
    ({
      String? id,
      String decanName,
      String? decanTheme,
      DateTime decanStart,
      DateTime decanEnd,
      int badgeCount,
      String reflectionText,
      bool persisted,
    })
    prompt, {
    required String interactionKind,
  }) async {
    await _decanReflectionPromptState.markInteracted(prompt.decanStart);
    await _decanReflectionRepo.markPromptInteracted(
      decanStart: prompt.decanStart,
      decanEnd: prompt.decanEnd,
      interactionKind: interactionKind,
    );
  }

  Future<void> _maybeLoadDecanReflectionPrompt({bool force = false}) async {
    if (!mounted || _reflectionInFlight) return;
    final user = Supabase.instance.client.auth.currentUser;
    if (user == null) return;

    final today = DateUtils.dateOnly(DateTime.now());
    if (_lastReflectionCheckDay != null &&
        DateUtils.isSameDay(today, _lastReflectionCheckDay) &&
        !force &&
        _reflectionPrompt != null) {
      return;
    }
    _lastReflectionCheckDay = today;

    final window = _latestCompletedDecanWindow();
    if (window == null) {
      if (_reflectionPrompt != null) {
        setState(() => _reflectionPrompt = null);
      }
      return;
    }

    // Gate visibility until 8pm local on the 10th day of the decan
    final decanStartLocal = window.start.toLocal();
    final gateLocal = DateTime(
      decanStartLocal.year,
      decanStartLocal.month,
      decanStartLocal.day,
    ).add(const Duration(days: 9, hours: 20)); // day 10 at 8pm
    if (DateTime.now().isBefore(gateLocal)) {
      if (_reflectionPrompt != null) setState(() => _reflectionPrompt = null);
      return;
    }

    _reflectionInFlight = true;
    try {
      if (await _hasInteractedWithReflectionPrompt(window.start)) {
        if (!mounted) return;
        if (_reflectionPrompt != null) {
          setState(() => _reflectionPrompt = null);
        }
        return;
      }

      final existing = await _decanReflectionRepo.findByWindow(
        window.start,
        window.end,
      );
      if (existing != null) {
        if (!mounted) return;
        setState(() {
          _reflectionPrompt = (
            id: existing.id,
            decanName: existing.decanName,
            decanTheme: existing.decanTheme,
            decanStart: existing.decanStart,
            decanEnd: existing.decanEnd,
            badgeCount: existing.badgeCount,
            reflectionText: existing.reflectionText,
            persisted: true,
          );
        });
        return;
      }

      final decanBadges = await _collectDecanBadges(window.start, window.end);
      final payloadBadges = decanBadges
          .map(
            (b) => {
              'title': b.token.title,
              'details': b.token.description ?? b.token.title,
              'tags': b.tags,
              'event_id': b.token.eventId,
              'occurred_on': _formatDateOnlyLocal(b.occurredOn),
              if (b.occurredAt != null)
                'occurred_at': b.occurredAt!.toUtc().toIso8601String(),
            },
          )
          .toList();

      String reflectionText = '';
      int badgeCount = decanBadges.length;
      String? reflectionId;

      try {
        final response = await _aiReflectionService.generateReflection(
          decanName: window.decanName,
          decanTheme: window.decanTheme,
          decanContextKey: window.decanContextKey,
          decanStart: window.start,
          decanEnd: window.end,
          includeHistory: false, // prioritize current decan’s badges
          persist: true,
          useKnowledgeGraph: true,
          useDecisionMatrix: true,
          badges: payloadBadges,
        );
        if (response.success &&
            (response.reflection?.trim().isNotEmpty ?? false)) {
          reflectionText = response.reflection!.trim();
          badgeCount = response.badgeCount ?? badgeCount;
          reflectionId = response.reflectionId;
          Events.trackIfAuthed('decan_reflection_generated', {
            'kg': true,
            'decision_matrix': true,
            'badge_count': badgeCount,
            'persisted': response.reflectionId != null,
            'branch': response.branch ?? 'unknown',
          });
        }
      } catch (_) {
        // Ignore and fall back to local generation
      }

      if (reflectionText.trim().isEmpty) {
        reflectionText = _buildReflectionFromBadges(
          decanBadges.map((b) => b.token).toList(),
        );
      }

      if (reflectionText.trim().isEmpty) {
        return;
      }

      if (!mounted) return;
      setState(() {
        _reflectionPrompt = (
          id: reflectionId,
          decanName: window.decanName,
          decanTheme: window.decanTheme,
          decanStart: window.start,
          decanEnd: window.end,
          badgeCount: badgeCount,
          reflectionText: reflectionText.trim(),
          persisted: reflectionId != null,
        );
      });
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint('[DecanReflection] prompt load failed: $e');
      }
    } finally {
      _reflectionInFlight = false;
    }
  }

  Future<void> _archiveReflectionPrompt([BuildContext? ctx]) async {
    final prompt = _reflectionPrompt;
    if (prompt == null || _archivingReflection) return;

    if (mounted) {
      setState(() => _archivingReflection = true);
    }

    try {
      DecanReflection? saved = prompt.persisted && prompt.id != null
          ? await _decanReflectionRepo.getById(prompt.id!)
          : null;

      saved ??= await _decanReflectionRepo.saveReflection(
        decanName: prompt.decanName,
        decanTheme: prompt.decanTheme,
        decanStart: prompt.decanStart,
        decanEnd: prompt.decanEnd,
        badgeCount: prompt.badgeCount,
        reflectionText: prompt.reflectionText,
      );
      if (saved == null) {
        throw Exception('Unable to save reflection');
      }

      await _markReflectionPromptInteracted(
        prompt,
        interactionKind: 'archived',
      );

      if (!mounted) return;
      setState(() => _reflectionPrompt = null);
      if (ctx != null && ctx.mounted && Navigator.of(ctx).canPop()) {
        Navigator.of(ctx).pop();
      }
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Reflection archived to your profile'),
          duration: Duration(seconds: 2),
        ),
      );
    } catch (e) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Could not archive reflection: $e')),
      );
    } finally {
      if (mounted) {
        setState(() => _archivingReflection = false);
      } else {
        _archivingReflection = false;
      }
    }
  }

  Widget _buildCalendarScrollView() {
    final kToday = _today;

    // ✅ FIX 4: Wrap with NotificationListener to capture scroll-end events
    return NotificationListener<ScrollEndNotification>(
      onNotification: (notification) {
        if (!_initialViewportSettled) return false;
        if (_scrollCtrl.hasClients) {
          _lastKnownCalendarScrollOffset = _scrollCtrl.position.pixels;
        }
        // ✅ Only update centered month when scrolling STOPS
        WidgetsBinding.instance.addPostFrameCallback((_) {
          if (!mounted || !_initialViewportSettled) return;

          final centered = _computeCenteredMonthPrecisely();
          if (centered.$1 != _lastViewKy || centered.$2 != _lastViewKm) {
            _handlePortraitMonthChanged(centered.$1, centered.$2);
          }
          _scheduleCalendarRestorationSave(reason: 'calendar_scroll_end');
        });
        return false;
      },
      child: CustomScrollView(
        key: const PageStorageKey('calendar_portrait_scroll'),
        controller: _scrollCtrl,
        anchor: 0.0, // start the center sliver at the top on cold open
        center: _centerKey, // current Kemetic year is the center
        slivers: [
          // PAST years
          SliverList(
            delegate: SliverChildBuilderDelegate(
              (ctx, i) {
                final kYear = kToday.kYear - (i + 1);
                return _YearSection(
                  kYear: kYear,
                  todayMonth: null,
                  todayDay: null,
                  todayDayKey: null, // no anchor in past/future lists
                  monthAnchorKeyProvider: (m) => keyForMonth(kYear, m),
                  monthHeaderKeyProvider: (m) => keyForMonthHeader(kYear, m),
                  dayAnchorKeyProvider: (m, d) =>
                      _calendarDayAnchorKeyFor(kYear, m, d),
                  onMonthHeaderTap: (context, kMonth) =>
                      _handleMonthHeaderTapped(context, kYear, kMonth),
                  onDecanTap: (context, kMonth, decanIndex) =>
                      _handleDecanHeaderTapped(
                        context,
                        kYear,
                        kMonth,
                        decanIndex,
                      ),
                  onDayTap: (c, m, d) => _openDayView(c, kYear, m, d),
                  notesGetter: (m, d) => _getNotes(kYear, m, d),
                  flowColorsGetter: (ky, km, kd) =>
