  Map<int, FlowData> _buildCalendarFlowChromeIndex() {
    final allFlowsById = _allFlowsById();
    final activeLedgerFlowIds = _buildActiveLedgerFlowIds();
    final referencedFlowIds = _calendarReferencedFlowIds();
    final chromeIds = {...activeLedgerFlowIds, ...referencedFlowIds}.toList()
      ..sort();
    final index = <int, FlowData>{};

    for (final flowId in chromeIds) {
      final flow = allFlowsById[flowId];
      if (flow == null) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[calendarFlowChrome] MISSING_FLOW_OWNER_ROW flowId=$flowId',
          );
        }
        continue;
      }

      final snapshot = _flowRecordSnapshotFromFlow(flow);
      if (!shouldExposeFlowChromeForCalendar(
        snapshot,
        isReferencedByCalendar: referencedFlowIds.contains(flowId),
        isActiveLedgerFlow: activeLedgerFlowIds.contains(flowId),
      )) {
        continue;
      }

      index[flowId] = _flowDataFromFlow(flow);
    }

    return index;
  }

  FlowLedger<_Flow> _buildFlowLedger(Iterable<_Flow> flows) {
    return buildFlowLedger<_Flow>(
      flows: flows,
      idOf: (flow) => flow.id,
      activeOf: (flow) => flow.active,
      isSavedOf: (flow) => flow.isSaved,
      isHiddenOf: (flow) => flow.isHidden,
      isReminderOf: (flow) => flow.isReminder,
      endDateOf: (flow) => flow.end,
      notesOf: (flow) => flow.notes,
      useRemainingEventCount: true,
      totalEventCounts: _flowTotalEventCounts,
      remainingEventCounts: _flowRemainingEventCounts,
    );
  }

  FlowData? _calendarChromeFlowDataForId(int? flowId) {
    if (flowId == null || flowId <= 0) return null;
    final flow = _allFlowsById()[flowId];
    if (flow == null) return null;
    final activeLedgerFlowIds = _buildActiveLedgerFlowIds();
    final snapshot = _flowRecordSnapshotFromFlow(flow);
    if (!shouldExposeFlowChromeForCalendar(
      snapshot,
      isReferencedByCalendar: true,
      isActiveLedgerFlow: activeLedgerFlowIds.contains(flowId),
    )) {
      return null;
    }
    return _flowDataFromFlow(flow);
  }

  EventItem _calendarSheetEventItemFromNote(_Note note) {
    final startMin = note.allDay
        ? 9 * 60
        : (note.start?.hour ?? 9) * 60 + (note.start?.minute ?? 0);
    final endMin = note.allDay
        ? 17 * 60
        : (note.end?.hour ?? 17) * 60 + (note.end?.minute ?? 0);

    return EventItem(
      id: note.id,
      clientEventId: note.clientEventId,
      calendarId: note.calendarId,
      calendarName: note.calendarName,
      title: note.title,
      detail: note.detail,
      location: note.location,
      startMin: startMin,
      endMin: endMin,
      flowId: note.flowId,
      color: _noteColor(note),
      manualColor: note.manualColor,
      allDay: note.allDay,
      category: note.category,
      isReminder: note.isReminder,
      reminderId: note.reminderId,
      behaviorPayload: note.behaviorPayload,
    );
  }

  bool _noteHasStableIdentity(_Note note) =>
      (note.id?.trim().isNotEmpty ?? false) ||
      (note.clientEventId?.trim().isNotEmpty ?? false);

  int _visibleDayNotePriority(_Note note, {bool preferTimed = false}) {
    var score = 0;
    if (_noteHasStableIdentity(note)) score += 8;
    if (note.id?.trim().isNotEmpty ?? false) score += 3;
    if (note.clientEventId?.trim().isNotEmpty ?? false) score += 2;
    if (note.start != null) score += 1;
    if (note.end != null) score += 1;
    if (note.detail?.trim().isNotEmpty ?? false) score += 1;
    if (preferTimed && !note.allDay) score += 12;
    return score;
  }

  String _visibleDayNoteBaseKey(_Note note) {
    final flowKey = note.flowId?.toString() ?? 'NO_FLOW';

    String startKey;
    String endKey;

    if (note.allDay) {
      startKey = 'ALLDAY';
      endKey = 'ALLDAY';
    } else if (note.start != null && note.end != null) {
      startKey = '${note.start!.hour * 60 + note.start!.minute}';
      endKey = '${note.end!.hour * 60 + note.end!.minute}';
    } else {
      startKey = 'NO_START';
      endKey = 'NO_END';
    }

    final titleKey = note.title.trim().toLowerCase();
    return '$flowKey|$startKey|$endKey|$titleKey';
  }

  String? _visibleDayFlowLogicalKey(_Note note) {
    final flowId = note.flowId;
    if (flowId == null || flowId <= 0 || note.isReminder) return null;
    final titleKey = note.title.trim().toLowerCase();
    if (titleKey.isEmpty) return null;
    return 'flow-logical|$flowId|$titleKey';
  }

  String? _trackSkyVisibleDayNoteKey(_Note note, {Set<int>? trackSkyFlowIds}) {
    final flowId = note.flowId;
    final isTrackSkyNote =
        flowId != null &&
        flowId > 0 &&
        ((trackSkyFlowIds != null && trackSkyFlowIds.contains(flowId)) ||
            _isTrackSkyFlowName(_flowName(note)));
    if (!isTrackSkyNote) return null;
    final flowKey = note.flowId?.toString() ?? 'NO_FLOW';
    final titleKey = note.title.trim().toLowerCase();
    final categoryKey = (note.category ?? '').trim().toLowerCase();
    return 'track-sky|$flowKey|$categoryKey|$titleKey';
  }

  void _mergeVisibleDayDuplicate({
    required List<_Note> deduped,
    required Map<String, int> indexByKey,
    required String key,
    required _Note note,
    bool preferTimed = false,
  }) {
    final existingIndex = indexByKey[key];
    if (existingIndex == null) {
      indexByKey[key] = deduped.length;
      deduped.add(note);
      return;
    }

    final existing = deduped[existingIndex];
    final existingScore = _visibleDayNotePriority(
      existing,
      preferTimed: preferTimed,
    );
    final incomingScore = _visibleDayNotePriority(
      note,
      preferTimed: preferTimed,
    );
    if (incomingScore > existingScore) {
      deduped[existingIndex] = note;
    }
  }

  void _mergeVisibleDayFlowLogicalDuplicate({
    required List<_Note> deduped,
    required Map<String, int> indexByKey,
    required String key,
    required _Note note,
  }) {
    final existingIndex = indexByKey[key];
    if (existingIndex == null) {
      indexByKey[key] = deduped.length;
      deduped.add(note);
      return;
    }

    final existing = deduped[existingIndex];
    final existingScore = _visibleDayNotePriority(existing, preferTimed: true);
    final incomingScore = _visibleDayNotePriority(note, preferTimed: true);
    if (incomingScore >= existingScore || !_noteHasStableIdentity(note)) {
      deduped[existingIndex] = note;
    }
  }

  List<_Note> _dedupeVisibleDayNotes(
    List<_Note> notes, {
    Set<int>? trackSkyFlowIds,
  }) {
    if (notes.length < 2) return notes;

    final exactDeduped = <_Note>[];
    final exactIndexByKey = <String, int>{};
    for (final note in notes) {
      _mergeVisibleDayDuplicate(
        deduped: exactDeduped,
        indexByKey: exactIndexByKey,
        key: _visibleDayNoteBaseKey(note),
        note: note,
      );
    }

    final trackSkyDeduped = <_Note>[];
    final trackSkyIndexByKey = <String, int>{};
    for (final note in exactDeduped) {
      final trackSkyKey = _trackSkyVisibleDayNoteKey(
        note,
        trackSkyFlowIds: trackSkyFlowIds,
      );
      if (trackSkyKey == null) {
        trackSkyDeduped.add(note);
        continue;
      }

      _mergeVisibleDayDuplicate(
        deduped: trackSkyDeduped,
        indexByKey: trackSkyIndexByKey,
        key: trackSkyKey,
        note: note,
        preferTimed: true,
      );
    }

    final flowLogicalDeduped = <_Note>[];
    final flowLogicalIndexByKey = <String, int>{};
    for (final note in trackSkyDeduped) {
      final flowLogicalKey = _visibleDayFlowLogicalKey(note);
      if (flowLogicalKey == null) {
        flowLogicalDeduped.add(note);
        continue;
      }

      _mergeVisibleDayFlowLogicalDuplicate(
        deduped: flowLogicalDeduped,
        indexByKey: flowLogicalIndexByKey,
        key: flowLogicalKey,
        note: note,
      );
    }

    return flowLogicalDeduped;
  }

  String _calendarSheetEventIdentityKey(EventItem event) {
    final id = event.id?.trim();
    if (id != null && id.isNotEmpty) return 'id:$id';

    final clientEventId = event.clientEventId?.trim();
    if (clientEventId != null && clientEventId.isNotEmpty) {
      return 'cid:$clientEventId';
    }

    final reminderId = event.reminderId?.trim();
    if (reminderId != null && reminderId.isNotEmpty) {
      return 'rid:$reminderId';
    }

    return [
      event.title.trim().toLowerCase(),
      event.startMin,
      event.endMin,
      event.flowId ?? '',
      event.location?.trim().toLowerCase() ?? '',
      event.detail?.trim().toLowerCase() ?? '',
      event.allDay,
      event.isReminder,
    ].join('|');
  }

  bool _calendarSheetEventsShareStableIdentity(EventItem a, EventItem b) {
    final aId = a.id?.trim();
    final bId = b.id?.trim();
    if (aId != null && aId.isNotEmpty && bId != null && bId.isNotEmpty) {
      return aId == bId;
    }

    final aClientId = a.clientEventId?.trim();
    final bClientId = b.clientEventId?.trim();
    if (aClientId != null &&
        aClientId.isNotEmpty &&
        bClientId != null &&
        bClientId.isNotEmpty) {
      return aClientId == bClientId;
    }

    final aReminderId = a.reminderId?.trim();
    final bReminderId = b.reminderId?.trim();
    if (aReminderId != null &&
        aReminderId.isNotEmpty &&
        bReminderId != null &&
        bReminderId.isNotEmpty) {
      return aReminderId == bReminderId;
    }

    return _calendarSheetEventIdentityKey(a) ==
        _calendarSheetEventIdentityKey(b);
  }

  int _compareCalendarSheetEventItems(EventItem a, EventItem b) {
    final startCmp = a.startMin.compareTo(b.startMin);
    if (startCmp != 0) return startCmp;

    final endCmp = a.endMin.compareTo(b.endMin);
    if (endCmp != 0) return endCmp;

    return _calendarSheetEventIdentityKey(
      a,
    ).compareTo(_calendarSheetEventIdentityKey(b));
  }

  List<EventItem> _calendarSheetEventsForDay(int ky, int km, int kd) {
    final notes = _getNotes(ky, km, kd);
    final events = [
      for (final note in notes) _calendarSheetEventItemFromNote(note),
    ];
    events.sort(_compareCalendarSheetEventItems);
    return events;
  }

  DayViewSheetEventTarget? _resolveCalendarAdjacentEventTarget({
    required int ky,
    required int km,
    required int kd,
    required EventItem event,
    required bool forward,
  }) {
    final currentEvents = _calendarSheetEventsForDay(ky, km, kd);
    final currentIndex = currentEvents.indexWhere(
      (candidate) => _calendarSheetEventsShareStableIdentity(candidate, event),
    );

    if (currentIndex >= 0) {
      final sameDayIndex = forward ? currentIndex + 1 : currentIndex - 1;
      if (sameDayIndex >= 0 && sameDayIndex < currentEvents.length) {
        return DayViewSheetEventTarget(
          ky: ky,
          km: km,
          kd: kd,
          event: currentEvents[sameDayIndex],
        );
      }
    }

    final currentGregorian = KemeticMath.toGregorian(ky, km, kd);
    final direction = forward ? 1 : -1;
    for (int offset = 1; offset <= 366; offset++) {
      final nextGregorian = currentGregorian.add(
        Duration(days: direction * offset),
      );
      final nextKemetic = KemeticMath.fromGregorian(nextGregorian);
      final nextDayEvents = _calendarSheetEventsForDay(
        nextKemetic.kYear,
        nextKemetic.kMonth,
        nextKemetic.kDay,
      );
      if (nextDayEvents.isEmpty) continue;
      return DayViewSheetEventTarget(
        ky: nextKemetic.kYear,
        km: nextKemetic.kMonth,
        kd: nextKemetic.kDay,
        event: forward ? nextDayEvents.first : nextDayEvents.last,
      );
    }

    return null;
  }

  DayViewSheetEventTarget _resolveCalendarCurrentEventTarget(
    DayViewSheetEventTarget target,
  ) {
    final currentEvents = _calendarSheetEventsForDay(
      target.ky,
      target.km,
      target.kd,
    );
    if (currentEvents.isEmpty) return target;

    for (final candidate in currentEvents) {
      if (!_calendarSheetEventsShareStableIdentity(candidate, target.event)) {
        continue;
      }
      return DayViewSheetEventTarget(
        ky: target.ky,
        km: target.km,
        kd: target.kd,
        event: candidate,
      );
    }

    return target;
  }

  @visibleForTesting
  int filteredNoteCountForDay(int kYear, int kMonth, int kDay) {
    // Unified logic: all views read from _notes (which is the canonical source).
    // Zombie filters are already applied during _loadFromDisk, so we just count.
    final key = _kKey(kYear, kMonth, kDay);
    return (_notes[key] ?? const []).length;
  }
}

